// Default tint per type (mirrors the client PC map; extra joinery/furniture keys added).
const ADS_ICON_COLORS: Record<string, string> = {
  sink: "#2563eb", sink2: "#2563eb", plumbing: "#0891b2", water: "#0891b2", drain: "#0e7490",
  ro: "#14b8a6", chimney: "#6366f1", hob: "#ea580c", gas: "#dc2626", fridge: "#8b5cf6",
  microwave: "#f59e0b", oven: "#d97706", dishwasher: "#0ea5e9", washing: "#64748b",
  switchboard: "#eab308", socket: "#22c55e", light: "#f59e0b", fan: "#0ea5e9",
  hanging: "#7c3aed", drawer: "#9333ea", trouser: "#7c3aed", tie: "#a855f7", shoe: "#8b5cf6",
  jewellery: "#c026d3", safe: "#475569", laundry: "#0d9488",
  tv: "#334155", sofa: "#b45309", bed: "#be123c", dining: "#a16207", study: "#0f766e", dressing: "#db2777",
  generic: "#334155",
};
// Server-side icon → <g> wrapper (translate+scale a 24-box to pixel size at cx,cy).
function svgIcon(type: string, cx: number, cy: number, size: number, color?: string): string {
  const inner = ADS_ICON_PATHS[type] || ADS_ICON_PATHS.generic;
  const s = size / 24, col = color || ADS_ICON_COLORS[type] || "#334155";
  return `<g transform="translate(${(cx - size / 2).toFixed(2)},${(cy - size / 2).toFixed(2)}) scale(${s.toFixed(4)})" style="color:${col}" fill="none" stroke="currentColor" stroke-width="1.6" stroke-linecap="round" stroke-linejoin="round">${inner}</g>`;
}
function sinkEllipse(cx: number, cy: number, size = 26): string {
  return svgIcon("sink", cx, cy, size);
}

// §7 AutoCAD presentation: draw doors (swing arc + leaf), windows (double line),
// columns and ventilators on a HORIZONTAL wall at y=top. `into` = +1 → the room is
// below the wall (cabinets hang down), so a door swings into +y. Reads GEN_WINDOWS +
// GEN_STRUCTURES so the §3 opening-awareness is actually VISIBLE on the drawing.
function planOpeningsH(xOf: (mm: number) => number, top: number, La: number, into = 1, wallKey?: string): string[] {
  const S = PLAN_S, els: string[] = [], at = (mm: number) => xOf(mm);
  // wallKey (e.g. "back"/"left") restricts to openings on that wall; items with no
  // wall set are treated as being on the primary wall (drawn only when wallKey is unset or "back").
  const onWall = (wl?: string) => !wallKey ? true : (wl ? wl.toLowerCase().includes(wallKey) : wallKey === "back");
  for (const w of GEN_WINDOWS) {
    if (!onWall(w.wall)) continue;
    const a = w.along, b = a + w.width; if (a == null || a > La) continue;
    els.push(`<rect x="${at(a)}" y="${top - 2}" width="${(b - a) * S}" height="4" fill="#f4f7fb"/>`);
    els.push(`<line x1="${at(a)}" y1="${top - 1.6}" x2="${at(b)}" y2="${top - 1.6}" stroke="#0891b2" stroke-width="0.9"/>`);
    els.push(`<line x1="${at(a)}" y1="${top + 1.6}" x2="${at(b)}" y2="${top + 1.6}" stroke="#0891b2" stroke-width="0.9"/>`);
    els.push(`<text x="${at((a + b) / 2)}" y="${top - 4}" fill="#0891b2" font-size="6" text-anchor="middle">window</text>`);
  }
  for (const s of GEN_STRUCTURES) {
    if (!onWall(s.wall)) continue;
    const w = s.width && s.width > 0 ? s.width : (s.kind === "column" ? 300 : 800);
    const a = s.pos; if (a == null || a > La) continue; const b = a + w;
    if (s.kind === "door") {
      const wp = (b - a) * S, hinge = at(a), yLeaf = top + into * wp;
      els.push(`<rect x="${hinge}" y="${top - 2}" width="${wp}" height="4" fill="#f4f7fb"/>`);
      els.push(`<line x1="${hinge}" y1="${top}" x2="${hinge}" y2="${yLeaf}" stroke="#8b5a2b" stroke-width="1.4"/>`);
      els.push(`<path d="M${at(b)} ${top} A${wp} ${wp} 0 0 ${into > 0 ? 1 : 0} ${hinge} ${yLeaf}" fill="none" stroke="#8b5a2b" stroke-width="0.8" stroke-dasharray="3 2"/>`);
      els.push(`<text x="${at((a + b) / 2)}" y="${top - 4}" fill="#8b5a2b" font-size="6" text-anchor="middle">door</text>`);
    } else if (s.kind === "column") {
      els.push(`<rect x="${at(a)}" y="${top - 4}" width="${w * S}" height="8" fill="#94a3b8" stroke="#475569" stroke-width="0.6"/>`);
      els.push(`<text x="${at(a + w / 2)}" y="${top - 6}" fill="#475569" font-size="6" text-anchor="middle">col</text>`);
    } else if (s.kind === "ventilator" || s.kind === "balcony" || s.kind === "stair") {
      els.push(`<rect x="${at(a)}" y="${top - 2}" width="${w * S}" height="4" fill="#f4f7fb" stroke="#0891b2" stroke-width="0.7" stroke-dasharray="2 2"/>`);
      els.push(`<text x="${at(a + w / 2)}" y="${top - 4}" fill="#0891b2" font-size="5.5" text-anchor="middle">${s.kind}</text>`);
    }
  }
  return els;
}
// §7: small numbered badge at a cabinet's corner (cabinet schedule cross-reference).
function cabNumberBadge(cx: number, cy: number, n: number): string {
  return `<circle cx="${cx.toFixed(1)}" cy="${cy.toFixed(1)}" r="5.5" fill="#1e3a5f"/><text x="${cx.toFixed(1)}" y="${(cy + 2.5).toFixed(1)}" fill="#fff" font-size="7" text-anchor="middle">${n}</text>`;
}
function renderPlanStraight(type: string, run: RunLayout): string {
  const S = PLAN_S, d = STD.baseDepth, pad = 26, header = 20;
  const La = run.length, W = La * S + pad * 2, H = d * S + pad * 2 + header, top = pad + header;
  const xOf = (mm: number) => pad + mm * S;
  const p = [svgHead(W, H)];
  p.push(`<text x="${W / 2}" y="16" fill="#1e3a5f" font-size="11" text-anchor="middle">${type} — Plan (${Math.round(La)} mm)</text>`);
  p.push(`<line x1="${pad}" y1="${top}" x2="${xOf(La)}" y2="${top}" stroke="#64748b" stroke-width="3"/>`);
  let cabNo = 0;
  for (const c of run.base) {
    p.push(`<rect x="${xOf(c.x)}" y="${top}" width="${c.w * S}" height="${d * S}" fill="${planFill(c.kind)}" stroke="#2f74d0" stroke-width="1"/>`);
    if (c.kind === "sink") p.push(sinkEllipse(xOf(c.x) + c.w * S / 2, top + d * S / 2));
    if (c.kind === "hob" || c.kind === "drawer3") p.push(svgIcon("hob", xOf(c.x) + c.w * S / 2, top + d * S / 2, Math.min(c.w * S, d * S) * 0.62));
    if (c.kind !== "filler" && c.w * S > 14) p.push(cabNumberBadge(xOf(c.x) + 8, top + d * S - 8, ++cabNo));
  }
  p.push(`<rect x="${xOf(La / 2 - GEN.chimneyWidth / 2)}" y="${top - 5}" width="${GEN.chimneyWidth * S}" height="3.5" fill="#c7d2fe"/>`);
  p.push(svgIcon("chimney", xOf(La / 2), top - 11, 20));
  p.push(...planOpeningsH(xOf, top, La, 1));   // §7/§3: doors/windows/columns drawn on the wall
  p.push(`</svg>`);
  return p.join("");
}

function renderPlanL(runA: RunLayout, runB: RunLayout, La: number, Lb: number, opts: { label?: string; openLeg?: boolean } = {}): string {
  const S = PLAN_S, d = STD.baseDepth, pad = 34, header = 20;
  const W = La * S + pad * 2, H = Lb * S + pad * 2 + header;
  const ox = pad, oy = pad + header;
  const xOf = (mm: number) => ox + mm * S, yOf = (mm: number) => oy + mm * S;
  const name = opts.label ?? "L-Shape";
  const p = [svgHead(W, H)];
  p.push(`<text x="${W / 2}" y="16" fill="#1e3a5f" font-size="11" text-anchor="middle">${name} — Plan (back ${Math.round(La)} × ${opts.openLeg ? "peninsula" : "side"} ${Math.round(Lb)} mm)</text>`);
  // Walls (the peninsula's second leg is open — no wall along it)
  p.push(`<line x1="${ox}" y1="${oy}" x2="${xOf(La)}" y2="${oy}" stroke="#64748b" stroke-width="3"/>`);
  if (!opts.openLeg) p.push(`<line x1="${ox}" y1="${oy}" x2="${ox}" y2="${yOf(Lb)}" stroke="#64748b" stroke-width="3"/>`);
  else p.push(`<text x="${ox + d * S / 2}" y="${yOf(Lb) + 8}" fill="#94a3b8" font-size="6" text-anchor="middle">seating</text>`);
  // Run A — back wall (cabinets hang down)
  let cabNo = 0;
  for (const c of runA.base) {
    p.push(`<rect x="${xOf(c.x)}" y="${oy}" width="${c.w * S}" height="${d * S}" fill="${planFill(c.kind)}" stroke="#2f74d0" stroke-width="1"/>`);
    if (c.kind === "sink") p.push(sinkEllipse(xOf(c.x) + c.w * S / 2, oy + d * S / 2));
    if (c.kind === "hob" || c.kind === "drawer3") p.push(svgIcon("hob", xOf(c.x) + c.w * S / 2, oy + d * S / 2, Math.min(c.w * S, d * S) * 0.62));
    if (c.kind !== "filler" && c.w * S > 14) p.push(cabNumberBadge(xOf(c.x) + 8, oy + d * S - 8, ++cabNo));
  }
  p.push(...planOpeningsH(xOf, oy, La, 1, "back"));   // §7: doors/windows/columns on the back wall
  // Run B — left wall (cabinets extend right), drawn vertically
  for (const c of runB.base) {
    p.push(`<rect x="${ox}" y="${yOf(c.x)}" width="${d * S}" height="${c.w * S}" fill="${planFill(c.kind)}" stroke="#2f74d0" stroke-width="1"/>`);
    if (c.kind === "sink") p.push(sinkEllipse(ox + d * S / 2, yOf(c.x) + c.w * S / 2));
  }
  // chimney mark on Run A centre + corner label
  p.push(`<rect x="${xOf(La / 2 - GEN.chimneyWidth / 2)}" y="${oy - 5}" width="${GEN.chimneyWidth * S}" height="3.5" fill="#c7d2fe"/>`);
  p.push(svgIcon("chimney", xOf(La / 2), oy - 11, 20));
  p.push(`<text x="${ox + d * S / 2}" y="${oy + d * S / 2}" fill="#475569" font-size="6" text-anchor="middle">corner</text>`);
  p.push(`</svg>`);
  return p.join("");
}

function renderPlanU(left: RunLayout, back: RunLayout, right: RunLayout, Lb: number, Ll: number, Lr: number): string {
  const S = PLAN_S, d = STD.baseDepth, pad = 34, header = 20;
  const W = Lb * S + pad * 2, H = Math.max(Ll, Lr) * S + pad * 2 + header;
  const ox = pad, oy = pad + header;
  const xOf = (mm: number) => ox + mm * S, yOf = (mm: number) => oy + mm * S;
  const rightX = ox + Lb * S - d * S;
  const p = [svgHead(W, H)];
  p.push(`<text x="${W / 2}" y="16" fill="#1e3a5f" font-size="11" text-anchor="middle">U-Shape — Plan (back ${Math.round(Lb)} · left ${Math.round(Ll)} · right ${Math.round(Lr)} mm)</text>`);
  // Walls: back (top), left, right
  p.push(`<line x1="${ox}" y1="${oy}" x2="${xOf(Lb)}" y2="${oy}" stroke="#64748b" stroke-width="3"/>`);
  p.push(`<line x1="${ox}" y1="${oy}" x2="${ox}" y2="${yOf(Ll)}" stroke="#64748b" stroke-width="3"/>`);
  p.push(`<line x1="${xOf(Lb)}" y1="${oy}" x2="${xOf(Lb)}" y2="${yOf(Lr)}" stroke="#64748b" stroke-width="3"/>`);
  // Back wall cabinets (hang down)
  for (const c of back.base) p.push(`<rect x="${xOf(c.x)}" y="${oy}" width="${c.w * S}" height="${d * S}" fill="${planFill(c.kind)}" stroke="#2f74d0" stroke-width="1"/>`);
  // Left wall cabinets (extend right)
  for (const c of left.base) {
    p.push(`<rect x="${ox}" y="${yOf(c.x)}" width="${d * S}" height="${c.w * S}" fill="${planFill(c.kind)}" stroke="#2f74d0" stroke-width="1"/>`);
    if (c.kind === "sink") p.push(sinkEllipse(ox + d * S / 2, yOf(c.x) + c.w * S / 2));
  }
  // Right wall cabinets (extend left)
  for (const c of right.base) p.push(`<rect x="${rightX}" y="${yOf(c.x)}" width="${d * S}" height="${c.w * S}" fill="${planFill(c.kind)}" stroke="#2f74d0" stroke-width="1"/>`);
  // chimney mark on back centre + corner labels
  p.push(`<rect x="${xOf(Lb / 2 - GEN.chimneyWidth / 2)}" y="${oy - 6}" width="${GEN.chimneyWidth * S}" height="5" fill="#a5b4fc"/>`);
  p.push(`<text x="${xOf(Lb / 2)}" y="${oy - 8}" fill="#3730a3" font-size="7" text-anchor="middle">chimney</text>`);
  p.push(`<text x="${ox + d * S / 2}" y="${oy + d * S / 2}" fill="#475569" font-size="6" text-anchor="middle">corner</text>`);
  p.push(`<text x="${rightX + d * S / 2}" y="${oy + d * S / 2}" fill="#475569" font-size="6" text-anchor="middle">corner</text>`);
  p.push(`</svg>`);
  return p.join("");
}

// G-Shape — a U-shape plus a peninsula return projecting left from the right wall's far end.
function renderPlanG(left: RunLayout, back: RunLayout, right: RunLayout, peninsula: RunLayout, Lb: number, Ll: number, Lr: number, Lp: number): string {
  const S = PLAN_S, d = STD.baseDepth, pad = 34, header = 20;
  const maxSide = Math.max(Ll, Lr);
  const W = Lb * S + pad * 2, H = maxSide * S + pad * 2 + header;
  const ox = pad, oy = pad + header;
  const xOf = (mm: number) => ox + mm * S, yOf = (mm: number) => oy + mm * S;
  const rightX = ox + Lb * S - d * S;
  const p = [svgHead(W, H)];
  p.push(`<text x="${W / 2}" y="16" fill="#1e3a5f" font-size="11" text-anchor="middle">G-Shape — Plan (back ${Math.round(Lb)} · left ${Math.round(Ll)} · right ${Math.round(Lr)} · peninsula ${Math.round(Lp)} mm)</text>`);
  // Walls: back (top), left, right
  p.push(`<line x1="${ox}" y1="${oy}" x2="${xOf(Lb)}" y2="${oy}" stroke="#64748b" stroke-width="3"/>`);
  p.push(`<line x1="${ox}" y1="${oy}" x2="${ox}" y2="${yOf(Ll)}" stroke="#64748b" stroke-width="3"/>`);
  p.push(`<line x1="${xOf(Lb)}" y1="${oy}" x2="${xOf(Lb)}" y2="${yOf(Lr)}" stroke="#64748b" stroke-width="3"/>`);
  // Back wall cabinets (hang down)
  for (const c of back.base) p.push(`<rect x="${xOf(c.x)}" y="${oy}" width="${c.w * S}" height="${d * S}" fill="${planFill(c.kind)}" stroke="#2f74d0" stroke-width="1"/>`);
  // Left wall cabinets (extend right)
  for (const c of left.base) { p.push(`<rect x="${ox}" y="${yOf(c.x)}" width="${d * S}" height="${c.w * S}" fill="${planFill(c.kind)}" stroke="#2f74d0" stroke-width="1"/>`); if (c.kind === "sink") p.push(sinkEllipse(ox + d * S / 2, yOf(c.x) + c.w * S / 2)); }
  // Right wall cabinets (extend left)
  for (const c of right.base) p.push(`<rect x="${rightX}" y="${yOf(c.x)}" width="${d * S}" height="${c.w * S}" fill="${planFill(c.kind)}" stroke="#2f74d0" stroke-width="1"/>`);
  // Peninsula bar (bottom, projecting LEFT from the right wall's far end)
  const penTop = yOf(Lr) - d * S;
  for (const c of (peninsula && peninsula.base) || []) {
    const xr = xOf(Lb) - c.x * S;                 // right edge of this cab
    const xl = xOf(Lb) - (c.x + c.w) * S;          // left edge
    p.push(`<rect x="${Math.min(xl, xr)}" y="${penTop}" width="${Math.abs(xr - xl)}" height="${d * S}" fill="${planFill(c.kind)}" stroke="#2f74d0" stroke-width="1"/>`);
    if (c.kind === "sink") p.push(sinkEllipse((xl + xr) / 2, penTop + d * S / 2));
  }
  // chimney mark + corner + peninsula labels
  p.push(`<rect x="${xOf(Lb / 2 - GEN.chimneyWidth / 2)}" y="${oy - 6}" width="${GEN.chimneyWidth * S}" height="5" fill="#a5b4fc"/>`);
  p.push(`<text x="${xOf(Lb / 2)}" y="${oy - 8}" fill="#3730a3" font-size="7" text-anchor="middle">chimney</text>`);
  p.push(`<text x="${ox + d * S / 2}" y="${oy + d * S / 2}" fill="#475569" font-size="6" text-anchor="middle">corner</text>`);
  p.push(`<text x="${rightX + d * S / 2}" y="${oy + d * S / 2}" fill="#475569" font-size="6" text-anchor="middle">corner</text>`);
  p.push(`<text x="${xOf(Lb) - Lp * S / 2}" y="${penTop + d * S / 2}" fill="#475569" font-size="6" text-anchor="middle">peninsula</text>`);
  p.push(`</svg>`);
  return p.join("");
}

// Parallel / galley — two facing runs with a working aisle between them.
function renderPlanParallel(runA: RunLayout, runB: RunLayout, La: number, Lb: number): string {
  const S = PLAN_S, d = STD.baseDepth, aisle = 1000, pad = 30, header = 20;
  const W = Math.max(La, Lb) * S + pad * 2;
  const H = (d * 2 + aisle) * S + pad * 2 + header;
  const ox = pad, oyTop = pad + header;
  const oyBot = oyTop + (d + aisle) * S;          // top of Run B band
  const xOf = (mm: number) => ox + mm * S;
  const p = [svgHead(W, H)];
  p.push(`<text x="${W / 2}" y="16" fill="#1e3a5f" font-size="11" text-anchor="middle">Parallel — Plan (Run A ${Math.round(La)} · Run B ${Math.round(Lb)} mm · ${aisle} aisle)</text>`);
  // Top + bottom walls
  p.push(`<line x1="${ox}" y1="${oyTop}" x2="${xOf(La)}" y2="${oyTop}" stroke="#64748b" stroke-width="3"/>`);
  p.push(`<line x1="${ox}" y1="${oyBot + d * S}" x2="${xOf(Lb)}" y2="${oyBot + d * S}" stroke="#64748b" stroke-width="3"/>`);
  // Run A (top, hangs down)
  for (const c of runA.base) p.push(`<rect x="${xOf(c.x)}" y="${oyTop}" width="${c.w * S}" height="${d * S}" fill="${planFill(c.kind)}" stroke="#2f74d0" stroke-width="1"/>`);
  // Run B (bottom, extends up from bottom wall)
  for (const c of runB.base) {
    p.push(`<rect x="${xOf(c.x)}" y="${oyBot}" width="${c.w * S}" height="${d * S}" fill="${planFill(c.kind)}" stroke="#2f74d0" stroke-width="1"/>`);
    if (c.kind === "sink") p.push(sinkEllipse(xOf(c.x) + c.w * S / 2, oyBot + d * S / 2));
  }
  p.push(`<rect x="${xOf(La / 2 - GEN.chimneyWidth / 2)}" y="${oyTop - 6}" width="${GEN.chimneyWidth * S}" height="5" fill="#a5b4fc"/>`);
  p.push(`<text x="${xOf(La / 2)}" y="${oyTop - 8}" fill="#3730a3" font-size="7" text-anchor="middle">chimney</text>`);
  p.push(`<text x="${W / 2}" y="${oyTop + (d + aisle / 2) * S}" fill="#475569" font-size="8" text-anchor="middle">aisle</text>`);
  p.push(`</svg>`);
  return p.join("");
}

// Island — a main wall run plus a freestanding centred island block.
function renderPlanIsland(main: RunLayout, island: RunLayout, La: number, Li: number): string {
  const S = PLAN_S, d = STD.baseDepth, islD = 1000, aisle = 1000, pad = 30, header = 20;
  const W = La * S + pad * 2;
  const H = (d + aisle + islD) * S + pad * 2 + header;
  const ox = pad, oyTop = pad + header;
  const islY = oyTop + (d + aisle) * S;
  const islX = ox + (La - Li) / 2 * S;            // centre the island on the run
  const xOf = (mm: number) => ox + mm * S;
  const p = [svgHead(W, H)];
  p.push(`<text x="${W / 2}" y="16" fill="#1e3a5f" font-size="11" text-anchor="middle">Island — Plan (main ${Math.round(La)} · island ${Math.round(Li)} mm)</text>`);
  p.push(`<line x1="${ox}" y1="${oyTop}" x2="${xOf(La)}" y2="${oyTop}" stroke="#64748b" stroke-width="3"/>`);
  // Main wall cabinets (hang down)
  for (const c of main.base) p.push(`<rect x="${xOf(c.x)}" y="${oyTop}" width="${c.w * S}" height="${d * S}" fill="${planFill(c.kind)}" stroke="#2f74d0" stroke-width="1"/>`);
  p.push(`<rect x="${xOf(La / 2 - GEN.chimneyWidth / 2)}" y="${oyTop - 6}" width="${GEN.chimneyWidth * S}" height="5" fill="#a5b4fc"/>`);
  p.push(`<text x="${xOf(La / 2)}" y="${oyTop - 8}" fill="#3730a3" font-size="7" text-anchor="middle">chimney</text>`);
  // Island block (freestanding)
  for (const c of island.base) {
    p.push(`<rect x="${islX + c.x * S}" y="${islY}" width="${c.w * S}" height="${islD * S}" fill="${planFill(c.kind)}" stroke="#2f74d0" stroke-width="1"/>`);
    if (c.kind === "sink") p.push(sinkEllipse(islX + c.x * S + c.w * S / 2, islY + islD * S / 2));
  }
  p.push(`<text x="${islX + Li * S / 2}" y="${islY - 4}" fill="#475569" font-size="8" text-anchor="middle">island</text>`);
  p.push(`</svg>`);
  return p.join("");
}

// =============================================================================
// 4c. EXPORT — combined SVG + real-mm DXF, derived from the rendered SVGs.
// Each SVG root carries data-mmscale (px per mm) so millimetres are recoverable.
// PRODUCTION UPGRADE: emit discipline layers (CABINETS/ELECTRICAL/DIMENSIONS)
//   and a full DXF writer (arcs/splines/blocks, e.g. the `dxf` npm package).
// =============================================================================

interface SvgPrim {
  width: number; height: number; scale: number;
  rects: Array<{ x: number; y: number; w: number; h: number; layer: string }>;
  lines: Array<{ x1: number; y1: number; x2: number; y2: number; layer: string }>;
  polys: Array<{ pts: Array<{ x: number; y: number }>; layer: string }>;
  ellipses: Array<{ cx: number; cy: number; rx: number; ry: number; layer: string }>;
  texts: Array<{ x: number; y: number; s: string; layer: string }>;
}

// Discipline layers + AutoCAD colour indices (ACI). Used so the DXF opens with
// cabinets / electrical / dimensions / etc. on separate, toggleable layers.
const SOCKET_COLORS = ["#f59e0b", "#ef4444", "#22c55e", "#a855f7"];
const WALL_STROKES = ["#475569", "#334155", "#64748b"];
const LAYER_COLOR: Record<string, number> = {
  CABINETS: 7, WALLS: 8, ELECTRICAL: 2, DIMENSIONS: 4, APPLIANCES: 5, HARDWARE: 3, ANNOTATION: 6,
};
// Infer the discipline from the primitive's fill/stroke (the renderers already
// colour-code by meaning, so no SVG changes are needed).
function classifyLayer(type: string, fill: string, stroke: string): string {
  fill = (fill || "").toLowerCase(); stroke = (stroke || "").toLowerCase();
  if (type === "rect") {
    if (SOCKET_COLORS.includes(fill)) return "ELECTRICAL";
    if (fill === "#020617" || fill === "#a5b4fc") return "APPLIANCES"; // tv screen / chimney mark
    return "CABINETS";
  }
  if (type === "polygon" || type === "ellipse") return "APPLIANCES";   // chimney / sink / basin
  if (type === "line") {
    if (SOCKET_COLORS.includes(stroke)) return "DIMENSIONS";           // socket dimension lines
    if (WALL_STROKES.includes(stroke)) return "WALLS";
    if (stroke === "#0891b2" || stroke === "#94a3b8") return "HARDWARE"; // handles / hanging rods
    if (stroke === "#14b8a6") return "APPLIANCES";                      // mirror reflection
    return "CABINETS";                                                  // drawer/shelf dividers
  }
  if (type === "text") return SOCKET_COLORS.includes(fill) ? "DIMENSIONS" : "ANNOTATION";
  return "CABINETS";
}

function parseSvgPrimitives(svgRaw: string): SvgPrim {
  const svg = svgRaw.replace(/<defs>[\s\S]*?<\/defs>/g, ""); // drop hatch patterns
  const num = (s: string, re: RegExp) => { const m = s.match(re); return m ? parseFloat(m[1]) : 0; };
  const str = (s: string, re: RegExp) => { const m = s.match(re); return m ? m[1] : ""; };
  const width = num(svg, /(?<![\w-])width="([\d.]+)"/);
  const height = num(svg, /(?<![\w-])height="([\d.]+)"/);
  const scale = num(svg, /data-mmscale="([\d.]+)"/) || 1;

  const rects: SvgPrim["rects"] = [];
  for (const m of svg.matchAll(/<rect\b([^>]*)>/g)) {
    const a = m[1];
    const w = num(a, /(?<![\w-])width="(-?[\d.]+)"/), h = num(a, /(?<![\w-])height="(-?[\d.]+)"/);
    if (w <= 0 || h <= 0) continue;
    if (w >= width * 0.98 && h >= height * 0.98) continue; // skip full-canvas background
    rects.push({ x: num(a, /(?<![\w-])x="(-?[\d.]+)"/), y: num(a, /(?<![\w-])y="(-?[\d.]+)"/), w, h, layer: classifyLayer("rect", str(a, /fill="([^"]+)"/), str(a, /stroke="([^"]+)"/)) });
  }
  const lines: SvgPrim["lines"] = [];
  for (const m of svg.matchAll(/<line\b([^>]*)>/g)) {
    const a = m[1];
    lines.push({ x1: num(a, /x1="(-?[\d.]+)"/), y1: num(a, /y1="(-?[\d.]+)"/), x2: num(a, /x2="(-?[\d.]+)"/), y2: num(a, /y2="(-?[\d.]+)"/), layer: classifyLayer("line", "", str(a, /stroke="([^"]+)"/)) });
  }
  const polys: SvgPrim["polys"] = [];
  for (const m of svg.matchAll(/<polygon\b([^>]*)>/g)) {
    const a = m[1];
    const pts = (str(a, /points="([^"]+)"/)).trim().split(/\s+/).map((pt) => { const [px, py] = pt.split(",").map(parseFloat); return { x: px, y: py }; }).filter((q) => !isNaN(q.x) && !isNaN(q.y));
    if (pts.length >= 2) polys.push({ pts, layer: classifyLayer("polygon", str(a, /fill="([^"]+)"/), "") });
  }
  const ellipses: SvgPrim["ellipses"] = [];
  for (const m of svg.matchAll(/<ellipse\b([^>]*)>/g)) {
    const a = m[1];
    ellipses.push({ cx: num(a, /cx="(-?[\d.]+)"/), cy: num(a, /cy="(-?[\d.]+)"/), rx: num(a, /rx="(-?[\d.]+)"/), ry: num(a, /ry="(-?[\d.]+)"/), layer: "APPLIANCES" });
  }
  const texts: SvgPrim["texts"] = [];
  for (const m of svg.matchAll(/<text\b([^>]*)>([\s\S]*?)<\/text>/g)) {
    const s = m[2].replace(/<[^>]*>/g, "").replace(/&amp;/g, "&").replace(/[^\x20-\x7E]/g, "").trim();
    if (s) texts.push({ x: num(m[1], /(?<![\w-])x="(-?[\d.]+)"/), y: num(m[1], /(?<![\w-])y="(-?[\d.]+)"/), s, layer: classifyLayer("text", str(m[1], /fill="([^"]+)"/), "") });
  }
  return { width, height, scale, rects, lines, polys, ellipses, texts };
}

// Stack the plan + every elevation into one downloadable SVG (nested <svg>s).
function combinedSvg(layout: any, meta: { type?: string; id?: string } = {}): string {
  const svgs: string[] = [layout.planSvg, ...layout.elevations.map((e: any) => e.svg), ...((layout.sections || []).map((s: any) => s.svg))];
  const dim = (s: string) => ({ w: parseFloat((s.match(/(?<![\w-])width="([\d.]+)"/) || [])[1] || "0"), h: parseFloat((s.match(/(?<![\w-])height="([\d.]+)"/) || [])[1] || "0") });
  let y = 0, maxW = 0; const parts: string[] = [];
  for (const s of svgs) {
    const { w, h } = dim(s); maxW = Math.max(maxW, w);
    const inner = s.replace(/^<svg[^>]*>/, "").replace(/<\/svg>$/, "");
    parts.push(`<svg x="0" y="${y}" width="${w}" height="${h}" viewBox="0 0 ${w} ${h}">${inner}</svg>`);
    y += h + 12;
  }
  // Corner-solution colour legend — only when the design actually uses corner
  // units. Added here (SVG export only) so the DXF, recovered from the raw
  // elevation SVGs, stays a clean CAD drawing.
  const present = new Set<string>();
  for (const r of (layout.runs || [])) for (const c of (r.base || [])) if (c.kind === "corner") {
    const l = c.label || "";
    present.add(/LeMans/.test(l) ? "LeMans" : /Magic/.test(l) ? "Magic Corner" : /Blind/.test(l) ? "Blind Corner" : "Carousel");
  }
  if (present.size) {
    const KEY: [string, string][] = [["LeMans", "#10b981"], ["Magic Corner", "#6366f1"], ["Blind Corner", "#d97706"], ["Carousel", "#e11d48"]];
    const lh = 34, ly = y, items: string[] = [];
    let lx = 130;
    for (const [name, fill] of KEY) {
      const on = present.has(name), txt = name + (on ? " ✓" : "");
      items.push(`<rect x="${lx}" y="${ly + 11}" width="11" height="11" rx="2" fill="${fill}" opacity="${on ? 1 : 0.35}"/>`);
      items.push(`<text x="${lx + 16}" y="${ly + 20}" fill="#475569" font-size="10" font-family="monospace" font-weight="${on ? "bold" : "normal"}" opacity="${on ? 1 : 0.45}">${txt}</text>`);
      lx += 22 + txt.length * 6.1;
    }
    items.push(`<text x="${lx + 4}" y="${ly + 20}" fill="#94a3b8" font-size="9" font-family="monospace">· hierarchy LeMans › Magic › Blind › Carousel</text>`);
    lx += 8 + 52 * 6;
    maxW = Math.max(maxW, lx);
    parts.push(`<rect x="0" y="${ly}" width="${maxW}" height="${lh}" fill="#f4f7fb"/>`);
    parts.push(`<text x="10" y="${ly + 20}" fill="#334155" font-size="11" font-family="monospace" font-weight="bold">Corner solution</text>`);
    parts.push(items.join(""));
    y += lh + 12;
  }
  // ── Professional CAD sheet presentation: double border + bottom title block ──
  // (Website-quality drawing hand-off: project / type / scale / date / sheet, like a real A-series CAD sheet.)
  const M = 18, TB = 56;                                   // sheet margin + title-block height
  const shW = maxW + M * 2, shH = y + M * 2 + TB;
  const today = new Date().toISOString().slice(0, 10);
  const t = meta.type || layout.designType || "Modular Kitchen";
  const idS = meta.id ? meta.id.slice(0, 8).toUpperCase() : "";
  const cellX = [0, Math.round(shW * 0.36), Math.round(shW * 0.64), Math.round(shW * 0.8)];
  const esc = (s: string) => s.replace(/&/g, "&amp;").replace(/</g, "&lt;");
  const tb: string[] = [];
  tb.push(`<rect x="3" y="3" width="${shW - 6}" height="${shH - 6}" fill="none" stroke="#1e3a5f" stroke-width="2"/>`);
  tb.push(`<rect x="8" y="8" width="${shW - 16}" height="${shH - 16}" fill="none" stroke="#64748b" stroke-width="0.7"/>`);
  const tbY = shH - 8 - TB;
  tb.push(`<rect x="8" y="${tbY}" width="${shW - 16}" height="${TB}" fill="#f8fafc" stroke="#1e3a5f" stroke-width="1"/>`);
  for (let i = 1; i < cellX.length; i++) tb.push(`<line x1="${8 + cellX[i]}" y1="${tbY}" x2="${8 + cellX[i]}" y2="${tbY + TB}" stroke="#94a3b8" stroke-width="0.7"/>`);
  const cell = (i: number, l1: string, l2: string, fs = 12) => {
    const x = 16 + cellX[i];
    tb.push(`<text x="${x}" y="${tbY + 16}" fill="#94a3b8" font-size="8" font-family="monospace">${esc(l1)}</text>`);
    tb.push(`<text x="${x}" y="${tbY + 36}" fill="#1e3a5f" font-size="${fs}" font-family="monospace" font-weight="bold">${esc(l2)}</text>`);
  };
  cell(0, "PROJECT — Plan · Elevations · Sections", `${t} — CAD Set`);
  cell(1, "MANUFACTURER", MKW.name, 11);
  cell(2, "DATE", today);
  cell(3, `SHEET${idS ? " · " + idS : ""}`, "A-01 · mm");
  tb.push(`<text x="16" y="${tbY + 48}" fill="#1e3a5f" font-size="8.5" font-family="monospace" font-weight="bold">${esc(`${MKW.phone} · ${MKW.email} · ${MKW.area} — ${MKW.cta}`)}</text>`);
  tb.push(`<text x="${16 + cellX[2]}" y="${tbY + 48}" fill="#64748b" font-size="7.5" font-family="monospace">Scale: elev 0.14 · plan 0.10 px/mm</text>`);
  if (MKW_LOGO_B64) tb.push(`<image x="${shW - 64}" y="${tbY + 5}" width="52" height="46" preserveAspectRatio="xMidYMid meet" href="${MKW_LOGO_B64}"/>`);
  return `<svg xmlns="http://www.w3.org/2000/svg" width="${shW}" height="${shH}" viewBox="0 0 ${shW} ${shH}"><rect width="${shW}" height="${shH}" fill="#ffffff"/><g transform="translate(${M},${M})">${parts.join("")}</g>${tb.join("")}</svg>`;
}

// ════════════════════════════════════════════════════════════════════════════
//  PRESENTATION SPEC SHEET  (StudioNuvique-style 2D-drawing presentation)
//  One polished marketing / hand-off sheet per design — the "concept" of the
//  reference 2D drawing sheets: title banner, annotated hero elevation
//  (numbered component schedule), dimensioned plan + elevation (the embedded
//  views already carry their own dimension chains), material palette swatches,
//  specifications table, key-features, detailing drawings (Phase 2), notes and
//  a branded title footer.  Server-composed SVG, reused by the inline preview
//  AND the Spec-Sheet PDF export.  Distinct from combinedSvg (engineering CAD
//  set) — this is the customer-facing presentation drawing.
// ════════════════════════════════════════════════════════════════════════════
const SS = {
  ink: "#2b2722", sub: "#8a8275", line: "#ddd6c9", hair: "#ece6da",
  panel: "#ffffff", bg: "#f5f1ea", band: "#1d1b18", bandInk: "#f3efe7",
  accent: "#8a6d3b", chip: "#efe9dd", soft: "#faf7f1", ok: "#5a7d4f",
  font: "'Segoe UI','Helvetica Neue',Arial,sans-serif",
};
const ssEsc = (s: any) => String(s == null ? "" : s).replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
function ssViewDim(s: string) { return { w: parseFloat((s.match(/(?<![\w-])width="([\d.]+)"/) || [])[1] || "0"), h: parseFloat((s.match(/(?<![\w-])height="([\d.]+)"/) || [])[1] || "0") }; }
function ssInner(s: string) { return s.replace(/^<svg[^>]*>/, "").replace(/<\/svg>\s*$/, ""); }
// Embed an existing view SVG into a box, aspect-preserved (meet → centred).
function ssEmbed(svg: string, x: number, y: number, boxW: number, boxH: number): string {
  const { w, h } = ssViewDim(svg);
  if (!w || !h) return "";
  return `<svg x="${x.toFixed(1)}" y="${y.toFixed(1)}" width="${boxW.toFixed(1)}" height="${boxH.toFixed(1)}" viewBox="0 0 ${w} ${h}" preserveAspectRatio="xMidYMid meet">${ssInner(svg)}</svg>`;
}
// "meet" letterbox transform: maps a source-view point → on-sheet coords.
function ssMeet(svg: string, x: number, y: number, boxW: number, boxH: number) {
  const { w, h } = ssViewDim(svg);
  const k = Math.min(boxW / (w || 1), boxH / (h || 1));
  return { k, ox: x + (boxW - w * k) / 2, oy: y + (boxH - h * k) / 2, w, h };
}
// A panel/card with optional header strip.
function ssCard(x: number, y: number, w: number, h: number, title?: string, fill = SS.panel): string {
  let o = `<rect x="${x}" y="${y}" width="${w}" height="${h}" rx="3" fill="${fill}" stroke="${SS.line}" stroke-width="1"/>`;
  if (title) o += `<text x="${x + 13}" y="${y + 20}" fill="${SS.ink}" font-size="12.5" font-weight="700" letter-spacing="0.6" font-family="${SS.font}">${ssEsc(title.toUpperCase())}</text>` +
    `<line x1="${x + 13}" y1="${y + 29}" x2="${x + w - 13}" y2="${y + 29}" stroke="${SS.accent}" stroke-width="1.4"/>`;
  return o;
}
function ssText(x: number, y: number, t: string, fs = 10, fill = SS.ink, weight = "400", anchor = "start", extra = ""): string {
  return `<text x="${x.toFixed(1)}" y="${y.toFixed(1)}" fill="${fill}" font-size="${fs}" font-weight="${weight}" text-anchor="${anchor}" font-family="${SS.font}"${extra ? " " + extra : ""}>${ssEsc(t)}</text>`;
}
// Only CONSTRAIN over-wide text (compress) — never stretch short text. Returns a textLength attr or "".
function ssFit(t: string, fs: number, maxW: number): string {
  return (String(t || "").length * fs * 0.56 > maxW) ? `textLength="${Math.max(8, maxW).toFixed(0)}" lengthAdjust="spacingAndGlyphs"` : "";
}
// small ✓ medallion used by the key-features list
function ssCheck(cx: number, cy: number, r = 7): string {
  return `<circle cx="${cx}" cy="${cy}" r="${r}" fill="${SS.ok}"/><path d="M${cx - r * 0.45} ${cy} L${cx - r * 0.1} ${cy + r * 0.4} L${cx + r * 0.5} ${cy - r * 0.45}" fill="none" stroke="#fff" stroke-width="1.6" stroke-linecap="round" stroke-linejoin="round"/>`;
}

// Per-type banner heading + sub-line.
function ssTitleFor(type: string): { title: string; sub: string } {
  const t = (type || "").toLowerCase();
  if (t.includes("kitchen")) return { title: "Kitchen Design", sub: "Functional · Minimal · Timeless — built for everyday living" };
  if (t.includes("wardrobe")) return { title: "Wardrobe — Design & Details", sub: "Sliding / openable shutters · soft-close · optimised storage" };
  if (t.includes("vanity") || t.includes("dress")) return { title: "Dressing / Vanity Unit", sub: "Mirror · storage · designer profile lighting" };
  if (t.includes("lcd") || t.includes("tv")) return { title: "Modular TV Unit Design", sub: "Modern · Minimal · Functional" };
  if (t.includes("crockery")) return { title: "Crockery Unit Design", sub: "Display · storage · soft-close hardware" };
  if (t.includes("mandir") || t.includes("temple") || t.includes("pooja") || t.includes("puja")) return { title: "Mandir Design", sub: "Traditional jali · concealed LED · CNC detail" };
  if (t.includes("wall panel") || t.includes("cladding")) return { title: "Wall Panel Design", sub: "Fluted panel · marble · display niche · LED" };
  return { title: type || "Design", sub: "Modern · Functional · Elegant" };
}

// Material palette swatches per type (name, sub-line, fill, optional fluted overlay).
// `finish` (when supplied) is the user's actual chosen 3D finish — its swatch is
// shown FIRST so the sheet reflects the real selection, not just a per-type default.
function ssMaterials(type: string, layout: any, finish?: string, finishColor?: string): { name: string; sub: string; fill: string; flute?: boolean; glass?: boolean }[] {
  const t = (type || "").toLowerCase();
  const fin = String(finish || (layout && layout.finish) || "").toLowerCase();
  const base = (): { name: string; sub: string; fill: string; flute?: boolean; glass?: boolean }[] => {
  const walnut = { name: "Wood Finish", sub: "Walnut", fill: "#6b4a2f", flute: true };
  const lam = { name: "Matte Laminate", sub: "Beige", fill: "#d8c9b0" };
  const quartz = { name: "Quartz Stone", sub: "Calacatta", fill: "#ece7dd" };
  const led = { name: "LED Strip", sub: "Warm White", fill: "#f3d9a0" };
  const ali = { name: "Aluminium Profile", sub: "Champagne", fill: "#c7a96a" };
  const mirror = { name: "Designer Mirror", sub: "5 mm", fill: "#cfe6ee", glass: true };
  const glass = { name: "Tinted Glass", sub: "Black", fill: "#2a2f36", glass: true };
  const marble = { name: "Marble / UV Sheet", sub: "Vitrified", fill: "#ece7dd" };
  const teak = { name: "Laminate Finish", sub: "Teak Wood", fill: "#7a4a25", flute: true };
  const jali = { name: "MDF Jali", sub: "PU Off-White", fill: "#efe9dd" };
  const brass = { name: "Knob / Profile", sub: "Brass Gold", fill: "#b0892f" };
  const acr = { name: "Acrylic Finish", sub: fin.includes("acrylic") ? "High Gloss" : "White", fill: "#f2efe9" };
  if (t.includes("kitchen")) return [lam, walnut, quartz, { name: "Fluted Tiles", sub: "Off White", fill: "#efe9dd", flute: true }, led];
  if (t.includes("wardrobe")) return [{ name: "Pre-Lam Board", sub: "Light Beige", fill: "#d8c9b0" }, { name: "Wood Texture", sub: "Walnut Band", fill: "#8a5a36", flute: true }, ali, mirror, led];
  if (t.includes("lcd") || t.includes("tv")) return [{ name: "MDF Laminate", sub: "Matte", fill: "#d8c9b0" }, { name: "Fluted WPC", sub: "Wood", fill: "#6b4a2f", flute: true }, marble, glass, led, ali];
  if (t.includes("mandir") || t.includes("temple") || t.includes("puja") || t.includes("pooja")) return [teak, { name: "Acrylic Sheet", sub: "Marble", fill: "#ece7dd" }, jali, brass, led];
  if (t.includes("wall panel") || t.includes("cladding")) return [{ name: "WPC Fluted", sub: "Wood Finish", fill: "#6b4a2f", flute: true }, marble, { name: "Laminate", sub: "Shelf & Niche", fill: "#7a4a25" }, led];
  if (t.includes("vanity") || t.includes("dress")) return [{ name: "Laminate", sub: "Walnut", fill: "#6b4a2f", flute: true }, acr, mirror, ali, led];
  if (t.includes("crockery")) return [lam, { name: "Wood Finish", sub: "Walnut", fill: "#6b4a2f", flute: true }, { name: "Glass Shutter", sub: "Frosted", fill: "#cfe6ee", glass: true }, led];
  return [lam, walnut, quartz, led];
  };
  const list = base();
  if (finish && fin && !/color-?coded/.test(fin)) {   // prepend the user's actual finish swatch
    const isAcr = fin.includes("acrylic"), isVen = fin.includes("veneer"), isPu = fin.includes("pu ") || fin.endsWith(" pu") || fin.includes("paint");
    const valid = typeof finishColor === "string" && /^#[0-9a-fA-F]{6}$/.test(finishColor);
    const fcol = valid ? finishColor! : isAcr ? "#f2efe9" : isVen ? "#7a4a25" : isPu ? "#e7e2d6" : "#d8c9b0";   // the exact chosen colour when available
    const fname = isAcr ? "Acrylic Finish" : isVen ? "Veneer Finish" : isPu ? "PU Paint (Sirca)" : "Laminate Finish";
    const sub = finish.length > 22 ? finish.slice(0, 22) : finish;
    list.unshift({ name: fname, sub, fill: fcol, flute: isVen && !valid });
    if (list.length > 6) list.length = 6;
  }
  return list;
}

// Specifications rows (label, value) derived from the layout (+ the chosen material).
function ssSpecs(type: string, layout: any, material?: any, scopes?: any): [string, string][] {
  const t = (type || "").toLowerCase();
  const rows: [string, string][] = [];
  if (t.includes("kitchen")) {
    const runs = (layout.runs || []).filter((r: any) => r.length);
    const lens = runs.map((r: any) => Math.round(r.length)).join(" + ");
    rows.push(["Layout", type]);
    if (lens) rows.push(["Run length", lens + " mm"]);
    rows.push(["Worktop height", String(STD.baseHeight) + " mm (FFL)"]);
    rows.push(["Base / Wall depth", STD.baseDepth + " / " + STD.wallDepth + " mm"]);
    rows.push(["Carcass", "18 mm BWP plywood"]);
    rows.push(["Shutter", "18 mm laminate / acrylic / PU"]);
    rows.push(["Countertop", "20 mm quartz / granite"]);
    rows.push(["Backsplash", "6 mm toughened glass / tiles"]);
    rows.push(["Handle", String(layout.handle || "D Handle")]);
    rows.push(["Hardware", "Soft-close hinges & telescopic channels"]);
    if (layout.applianceBrand) rows.push(["Appliances", String(layout.applianceBrand)]);
  } else {
    const u = layout.furniture || {};
    const W = Math.round(u.widthMM || (layout.runs && layout.runs[0] && layout.runs[0].length) || 0);
    const H = Math.round(u.heightMM || 0), D = Math.round(u.depthMM || 0);
    if (W && H) rows.push(["Overall size", W + " (W) × " + H + " (H)" + (D ? " × " + D + " (D)" : "") + " mm"]);
    rows.push(["Carcass", "18 mm HDHMR / BWP plywood"]);
    rows.push(["Back panel", "6–8 mm pre-laminated / MDF"]);
    rows.push(["Shutter / Front", "18 mm laminate / acrylic"]);
    if (u.loftMM) rows.push(["Loft / Top storage", Math.round(u.loftMM) + " mm"]);
    rows.push(["Edge band", "1 mm PVC"]);
    rows.push(["Hardware", "Soft-close hinges & telescopic channels"]);
    rows.push(["Finish", "Matte laminate / wood texture"]);
    rows.push(["Lighting", "Warm-white LED profile (optional)"]);
  }
  // Selected material (from the catalog). If scopes carry DIFFERENT materials per
  // area, list a per-scope schedule (§4 Apply-To); else the single finish.
  const sc = scopes || {};
  const codeOf = (m: any) => m ? (m.code || m.colorCode || "") : "";
  const distinct = [sc.base, sc.wall, sc.tall].filter(Boolean).map(codeOf);
  const mixed = new Set(distinct).size > 1;
  if (mixed) {
    for (const s of ["base", "wall", "tall"]) { const m = sc[s]; if (m) rows.push([({ base: "Base finish", wall: "Wall finish", tall: "Tall-unit finish" } as any)[s], ([m.brand, m.colorName].filter(Boolean).join(" ") + (m.code ? " (" + m.code + ")" : "")).slice(0, 40)]); }
  } else if (material && (material.brand || material.colorName)) {
    rows.push(["Finish material", [material.brand, material.colorName].filter(Boolean).join(" ").slice(0, 42)]);
    if (material.code || material.colorCode) rows.push(["Colour code", String(material.code || material.colorCode)]);
    if (material.finishType) rows.push(["Finish type", String(material.finishType)]);
    if (material.customerRate) rows.push(["Material rate", "₹" + material.customerRate + " / " + (material.unit || "sqft")]);
  }
  return rows;
}

// Key-feature chips per type.
function ssFeatures(type: string): string[] {
  const t = (type || "").toLowerCase();
  if (t.includes("kitchen")) return ["Ergonomic work-triangle", "Soft-close hardware", "Ample storage", "Easy-to-clean surfaces", "Integrated appliances", "Durable & long-lasting"];
  if (t.includes("wardrobe")) return ["Optimised hanging & shelving", "Soft-close drawers", "Sliding-track system", "Loft storage", "Scratch-resistant finish"];
  if (t.includes("mandir") || t.includes("temple")) return ["Traditional jali detail", "Concealed warm LED", "Acrylic marble back", "Storage drawer", "Wall-mounted"];
  if (t.includes("wall panel") || t.includes("cladding")) return ["Fluted texture accent", "Display niche with LED", "Floating shelf", "Marble / UV feature", "Customisable size"];
  if (t.includes("tv") || t.includes("lcd")) return ["Open & closed storage", "Concealed cable management", "Warm LED ambience", "Premium textures", "Wall-mounted clean look"];
  return ["Premium materials", "Soft-close hardware", "Ample storage", "Easy maintenance", "Durable & long-lasting"];
}

// Short notes (right column) per type.
function ssNotes(type: string): string[] {
  const t = (type || "").toLowerCase();
  const base = ["All dimensions are in millimetres (mm).", "Dimensions for reference — verify on site before execution.", "Follow carpenter / shop drawings for final cutting."];
  if (t.includes("kitchen")) return ["Counter height 850 mm from FFL.", "Wall-cabinet sill 1450 mm; loft above.", ...base.slice(0, 2)];
  if (t.includes("mandir") || t.includes("temple")) return ["LED strip concealed in top & side grooves.", "Acrylic back panel with CNC-cut design.", "Provide a 5 A power socket behind the unit.", base[1]];
  if (t.includes("wall panel") || t.includes("cladding")) return ["WPC fluted panel thickness 12 mm.", "Floating-shelf load capacity as per wall support.", "Design customisable to wall width & height.", base[1]];
  return base;
}

// Component schedule for the annotated hero (label + centre fraction 0..1 along the run width).
function ssSchedule(type: string, layout: any): { label: string; frac: number }[] {
  const t = (type || "").toLowerCase();
  const out: { label: string; frac: number }[] = [];
  if (t.includes("kitchen")) {
    const run = (layout.runs || []).find((r: any) => (r.base || []).length) || (layout.runs || [])[0];
    if (!run || !run.length) return out;
    const L = run.length, seen = new Set<string>();
    const KIND: Record<string, string> = { sink: "Sink", hob: "Hob / Cooktop", chimney: "Chimney", fridge: "Refrigerator", "tall-fridge": "Refrigerator", "tall-pantry": "Tall Pantry", "tall-hiunit": "Oven Tower", "tall-utility": "Utility Tall Unit", "drawer-atta": "Atta Drawer", corner: "Corner Unit", dishwasher: "Dishwasher" };
    for (const c of (run.base || [])) {
      let lbl = KIND[c.kind];
      if (!lbl) continue;   // explicit hob/chimney cabinets are labelled via KIND; we do NOT infer a hob from a drawer3 + global GEN state (would mislabel re-opened designs)
      if (seen.has(lbl)) continue; seen.add(lbl);
      out.push({ label: lbl, frac: Math.min(0.98, Math.max(0.02, (c.x + c.w / 2) / L)) });
    }
    if (!seen.has("Wall Cabinets") && (run.wallCabs || []).length) { const wc = run.wallCabs[Math.floor(run.wallCabs.length / 2)]; out.push({ label: "Wall Cabinets", frac: Math.min(0.98, Math.max(0.02, (wc.x + wc.w / 2) / L)) }); }
  } else {
    const u = layout.furniture; if (!u || !u.columns) return out;
    const seen = new Set<string>(); const KIND: Record<string, string> = { hang: "Hanging Rod", shelf: "Shelves", drawer: "Drawers", glass: "Glass Display", tv: "TV Recess", mirror: "Mirror", basin: "Wash Basin", open: "Open Display", door: "Cabinet", jali: "Jali Panel", niche: "Display Niche", puja: "Puja Space", fluted: "WPC Fluted Panel", marble: "Marble Sheet", floatshelf: "Floating Shelf" };
    let x = 0;
    for (const col of u.columns) {
      const cx = x + col.wMM / 2;
      for (const cell of (col.cells || [])) {
        const lbl = KIND[cell.kind]; if (!lbl || seen.has(lbl)) continue; seen.add(lbl);
        out.push({ label: lbl, frac: Math.min(0.98, Math.max(0.02, cx / (u.widthMM || 1))) });
      }
      x += col.wMM;
    }
    if (u.loftMM > 0 && !seen.has("Loft")) out.push({ label: "Loft", frac: 0.5 });
  }
  out.sort((a, b) => a.frac - b.frac);
  return out.slice(0, 8);
}

// ════════════════════════════════════════════════════════════════════════════
//  CONSTRUCTION DETAILING / SECTION DRAWINGS  (the reference "Detailing Drawings")
//  Small annotated cross-sections — layered materials + leader-line callouts:
//  base-cabinet section, wall-cabinet section, L-corner detail, countertop +
//  backsplash junction, sliding-door track, and a generic carcass section for
//  furniture (wardrobe / TV / mandir / wall panel). Each returns a self-contained
//  ~250×220 SVG that the spec sheet embeds in its "Detailing Drawings" row.
// ════════════════════════════════════════════════════════════════════════════
const D_INK = "#3a352c", D_LINE = "#6b6557", D_PLY = "#d9c29a", D_PLY2 = "#c7ab7c",
  D_STONE = "#e7e2d6", D_METAL = "#bcc0c6", D_GLASS = "#cfe6ee", D_WOOD = "#7a4a25", D_LED = "#f3d59f", D_BACK = "#efe9dd";
const DW = 250, DH = 224;
function dLeader(x1: number, y1: number, x2: number, y2: number, text: string, anchor = "start"): string {
  return `<line x1="${x1}" y1="${y1}" x2="${x2}" y2="${y2}" stroke="${D_LINE}" stroke-width="0.6"/>` +
    `<circle cx="${x1}" cy="${y1}" r="1.7" fill="${D_INK}"/>` +
    `<text x="${x2 + (anchor === "end" ? -3 : 3)}" y="${y2 + 2.8}" fill="${D_INK}" font-size="7.6" text-anchor="${anchor}" font-family="${SS.font}">${ssEsc(text)}</text>`;
}
function dWrap(title: string, inner: string): string {
  return `<svg xmlns="http://www.w3.org/2000/svg" width="${DW}" height="${DH}" viewBox="0 0 ${DW} ${DH}" font-family="${SS.font}">` +
    `<rect width="${DW}" height="${DH}" fill="#ffffff"/>` +
    `<text x="${DW / 2}" y="14" fill="${D_INK}" font-size="9.5" font-weight="700" text-anchor="middle" letter-spacing="0.3">${ssEsc(title.toUpperCase())}</text>` +
    `<line x1="20" y1="20" x2="${DW - 20}" y2="20" stroke="${D_BACK}" stroke-width="1"/>` + inner + `</svg>`;
}
// Vertical section through a base cabinet (kitchen / general base unit).
function detailBaseCabinet(): string {
  const cx = 95, cw = 70, top = 42, bot = 196, sw = 7;   // carcass box
  const p: string[] = [];
  p.push(`<rect x="${cx - 6}" y="${top - 12}" width="${cw + 12}" height="12" fill="${D_STONE}" stroke="${D_LINE}" stroke-width="0.8"/>`);   // countertop
  p.push(`<rect x="${cx}" y="${top}" width="${cw}" height="${bot - top}" fill="#fff" stroke="${D_LINE}" stroke-width="0.9"/>`);             // carcass outline
  p.push(`<rect x="${cx}" y="${top}" width="${sw}" height="${bot - top}" fill="${D_PLY}"/>`);                                              // left side panel
  p.push(`<rect x="${cx + cw - sw}" y="${top}" width="${sw}" height="${bot - top}" fill="${D_PLY}"/>`);                                    // right side panel
  // 3 drawer fronts
  for (let i = 0; i < 3; i++) { const dy = top + 8 + i * 46; p.push(`<rect x="${cx + sw}" y="${dy}" width="${cw - sw * 2}" height="40" fill="${D_PLY2}" stroke="${D_LINE}" stroke-width="0.6"/>`); p.push(`<line x1="${cx + cw / 2 - 7}" y1="${dy + 20}" x2="${cx + cw / 2 + 7}" y2="${dy + 20}" stroke="${D_INK}" stroke-width="1.4"/>`); }
  p.push(`<rect x="${cx + sw}" y="${bot - 18}" width="${cw - sw * 2}" height="6" fill="${D_METAL}"/>`);          // toe-kick recess
  p.push(`<line x1="${cx + 10}" y1="${bot}" x2="${cx + 10}" y2="${bot + 10}" stroke="${D_INK}" stroke-width="2"/><line x1="${cx + cw - 10}" y1="${bot}" x2="${cx + cw - 10}" y2="${bot + 10}" stroke="${D_INK}" stroke-width="2"/>`);  // adjustable legs
  p.push(`<line x1="${cx}" y1="${bot + 10}" x2="${cx + cw}" y2="${bot + 10}" stroke="${D_LINE}" stroke-width="2"/>`);  // floor
  p.push(dLeader(cx + cw / 2, top - 8, cx + cw + 60, top - 6, "20 mm Countertop"));
  p.push(dLeader(cx + sw / 2, top + 30, cx - 12, top + 34, "18 mm Ply", "end"));
  p.push(dLeader(cx + cw / 2, top + 54, cx + cw + 60, top + 60, "Soft-close Channel"));
  p.push(dLeader(cx + cw / 2, bot - 15, cx + cw + 60, bot - 24, "Toe Kick"));
  p.push(dLeader(cx + 10, bot + 6, cx - 12, bot + 8, "Adjustable Leg", "end"));
  return dWrap("Base Cabinet Detail", p.join(""));
}
// Vertical section through a wall cabinet.
function detailWallCabinet(): string {
  const cx = 95, cw = 70, top = 40, bot = 180, sw = 7;
  const p: string[] = [];
  p.push(`<rect x="${cx}" y="${top}" width="${cw}" height="${bot - top}" fill="#fff" stroke="${D_LINE}" stroke-width="0.9"/>`);
  p.push(`<rect x="${cx}" y="${top}" width="${cw}" height="${sw}" fill="${D_PLY}"/><rect x="${cx}" y="${bot - sw}" width="${cw}" height="${sw}" fill="${D_PLY}"/>`);  // top/bottom
  p.push(`<rect x="${cx}" y="${top}" width="${sw}" height="${bot - top}" fill="${D_PLY}"/>`);
  p.push(`<line x1="${cx + sw}" y1="${(top + bot) / 2}" x2="${cx + cw}" y2="${(top + bot) / 2}" stroke="${D_LINE}" stroke-width="0.8"/>`);  // shelf
  p.push(`<rect x="${cx + cw}" y="${top + 6}" width="6" height="${bot - top - 12}" fill="${D_PLY2}" stroke="${D_LINE}" stroke-width="0.6"/>`);  // shutter
  p.push(`<circle cx="${cx + cw + 3}" cy="${top + 18}" r="2.4" fill="${D_METAL}"/>`);  // hinge
  p.push(dLeader(cx + cw / 2, top + 3, cx + cw + 58, top + 2, "18 mm Ply"));
  p.push(dLeader(cx + cw, top + 18, cx + cw + 58, top + 26, "Soft-close Hinge"));
  p.push(dLeader(cx + cw / 2, (top + bot) / 2, cx - 12, (top + bot) / 2 + 8, "Adjustable Shelf", "end"));
  p.push(dLeader(cx + cw + 3, bot - 14, cx + cw + 58, bot - 6, "Shutter"));
  return dWrap("Wall Cabinet Detail", p.join(""));
}
// Plan detail of an L-shaped corner junction.
function detailCorner(): string {
  const p: string[] = [];
  const ox = 70, oy = 44, t = 14;
  p.push(`<rect x="${ox}" y="${oy}" width="120" height="${t}" fill="${D_BACK}" stroke="${D_LINE}" stroke-width="0.7"/>`);  // wall A
  p.push(`<rect x="${ox}" y="${oy}" width="${t}" height="120" fill="${D_BACK}" stroke="${D_LINE}" stroke-width="0.7"/>`);  // wall B
  p.push(`<rect x="${ox + t}" y="${oy + t}" width="106" height="40" fill="${D_PLY}" stroke="${D_LINE}" stroke-width="0.8"/>`);  // counter A
  p.push(`<rect x="${ox + t}" y="${oy + t}" width="40" height="106" fill="${D_PLY}" stroke="${D_LINE}" stroke-width="0.8"/>`);  // counter B
  p.push(`<rect x="${ox + t + 40}" y="${oy + t + 40}" width="66" height="66" fill="#fff" stroke="${D_LINE}" stroke-width="0.7" stroke-dasharray="3 2"/>`);  // dead corner
  p.push(`<path d="M${ox + t + 40} ${oy + t + 106} L${ox + t + 106} ${oy + t + 40}" stroke="${D_WOOD}" stroke-width="1.4"/>`);   // corner shutter line
  p.push(dLeader(ox + 60, oy + 7, ox + 150, oy + 4, "Back Wall"));
  p.push(dLeader(ox + t + 50, oy + t + 20, ox + 168, oy + 60, "Countertop"));
  p.push(dLeader(ox + t + 73, oy + t + 73, ox + 150, oy + 150, "Blind-corner Carousel"));
  p.push(dLeader(ox + 7, oy + 70, ox - 12, oy + 90, "Base Cabinet", "end"));
  return dWrap("Corner Detail (L-Shape)", p.join(""));
}
// Countertop edge + backsplash junction.
function detailCounterBacksplash(): string {
  const p: string[] = [];
  const wallX = 150, floorRefY = 60, ct = 60;
  p.push(`<rect x="${wallX}" y="40" width="14" height="150" fill="${D_BACK}" stroke="${D_LINE}" stroke-width="0.7"/>`);  // wall
  p.push(`<rect x="${wallX - 6}" y="${floorRefY}" width="6" height="70" fill="${D_GLASS}" stroke="${D_LINE}" stroke-width="0.6"/>`);  // backsplash
  p.push(`<rect x="${ct}" y="${floorRefY + 64}" width="${wallX - 6 - ct}" height="14" fill="${D_STONE}" stroke="${D_LINE}" stroke-width="0.8"/>`);  // countertop slab
  p.push(`<rect x="${ct + 4}" y="${floorRefY + 78}" width="${wallX - 14 - ct}" height="70" fill="${D_PLY}" stroke="${D_LINE}" stroke-width="0.7"/>`);  // carcass below
  p.push(`<path d="M${wallX - 6} ${floorRefY + 64} q-5 0 -5 5" fill="none" stroke="${D_WOOD}" stroke-width="1.4"/>`);   // sealant fillet
  p.push(dLeader(wallX - 3, floorRefY + 20, wallX + 36, floorRefY + 8, "Backsplash"));
  p.push(dLeader(wallX - 8, floorRefY + 66, wallX + 36, floorRefY + 40, "Sealant Joint"));
  p.push(dLeader(ct + 30, floorRefY + 71, ct - 8, floorRefY + 60, "20 mm Countertop", "end"));
  p.push(dLeader(ct + 30, floorRefY + 110, ct - 8, floorRefY + 120, "18 mm Carcass", "end"));
  return dWrap("Countertop & Backsplash", p.join(""));
}
// Sliding-door track cross-section (wardrobe).
function detailSlidingTrack(): string {
  const p: string[] = [];
  // top track
  p.push(`<text x="${DW / 2}" y="34" fill="${D_INK}" font-size="8" text-anchor="middle" font-weight="600">Top Track</text>`);
  p.push(`<rect x="60" y="40" width="130" height="12" fill="${D_METAL}" stroke="${D_LINE}" stroke-width="0.7"/>`);
  p.push(`<rect x="74" y="40" width="6" height="6" fill="#fff" stroke="${D_LINE}" stroke-width="0.5"/><rect x="170" y="40" width="6" height="6" fill="#fff" stroke="${D_LINE}" stroke-width="0.5"/>`);
  p.push(`<rect x="86" y="52" width="50" height="44" fill="${D_PLY2}" stroke="${D_LINE}" stroke-width="0.7"/><rect x="116" y="52" width="50" height="44" fill="${D_PLY}" stroke="${D_LINE}" stroke-width="0.7"/>`);  // overlapping shutters
  // bottom track
  p.push(`<text x="${DW / 2}" y="130" fill="${D_INK}" font-size="8" text-anchor="middle" font-weight="600">Bottom Track</text>`);
  p.push(`<rect x="86" y="138" width="50" height="44" fill="${D_PLY2}" stroke="${D_LINE}" stroke-width="0.7"/><rect x="116" y="138" width="50" height="44" fill="${D_PLY}" stroke="${D_LINE}" stroke-width="0.7"/>`);
  p.push(`<rect x="60" y="182" width="130" height="12" fill="${D_METAL}" stroke="${D_LINE}" stroke-width="0.7"/>`);
  p.push(`<circle cx="100" cy="182" r="4" fill="#fff" stroke="${D_LINE}" stroke-width="0.6"/><circle cx="150" cy="182" r="4" fill="#fff" stroke="${D_LINE}" stroke-width="0.6"/>`);  // wheels
  p.push(dLeader(190, 46, 210, 40, "Alu Top Track", "end"));
  p.push(dLeader(141, 74, 210, 74, "18 mm Shutter", "end"));
  p.push(dLeader(150, 182, 210, 188, "Roller Wheel", "end"));
  p.push(dLeader(60, 188, 44, 196, "Alu Bottom Track", "start"));
  return dWrap("Sliding Door Track", p.join(""));
}
// Generic carcass section (side panel + shelves + back) for furniture units.
function detailCarcassSection(opts: { hang?: boolean; back?: string; topLabel?: string } = {}): string {
  const cx = 92, cw = 76, top = 42, bot = 196, sw = 7;
  const p: string[] = [];
  p.push(`<rect x="${cx}" y="${top}" width="${cw}" height="${bot - top}" fill="#fff" stroke="${D_LINE}" stroke-width="0.9"/>`);
  p.push(`<rect x="${cx}" y="${top}" width="${sw}" height="${bot - top}" fill="${D_PLY}"/><rect x="${cx + cw - sw}" y="${top}" width="${sw}" height="${bot - top}" fill="${D_PLY}"/>`);  // sides
  p.push(`<rect x="${cx}" y="${top}" width="${cw}" height="${sw}" fill="${D_PLY}"/><rect x="${cx}" y="${bot - sw}" width="${cw}" height="${sw}" fill="${D_PLY}"/>`);  // top/bottom
  p.push(`<rect x="${cx + cw}" y="${top}" width="5" height="${bot - top}" fill="${D_BACK}" stroke="${D_LINE}" stroke-width="0.5"/>`);  // back panel
  if (opts.hang) { p.push(`<line x1="${cx + sw + 4}" y1="${top + 22}" x2="${cx + cw - sw - 4}" y2="${top + 22}" stroke="${D_METAL}" stroke-width="2.4"/>`); p.push(dLeader(cx + cw / 2, top + 22, cx + cw + 56, top + 18, "Hanging Rod")); }
  for (let i = 1; i <= 3; i++) { const sy = top + (opts.hang ? 60 : 30) + i * 32; if (sy < bot - sw) p.push(`<line x1="${cx + sw}" y1="${sy}" x2="${cx + cw - sw}" y2="${sy}" stroke="${D_LINE}" stroke-width="0.8"/>`); }
  p.push(dLeader(cx + sw / 2, top + 70, cx - 12, top + 74, "18 mm Side Panel", "end"));
  p.push(dLeader(cx + cw / 2, top + (opts.hang ? 92 : 62), cx + cw + 56, top + (opts.hang ? 96 : 66), "Adjustable Shelf"));
  p.push(dLeader(cx + cw + 2, bot - 30, cx + cw + 56, bot - 26, opts.back || "6 mm Back Panel"));
  p.push(dLeader(cx + cw / 2, top + 3, cx - 12, top + 6, opts.topLabel || "Carcass Top", "end"));
  return dWrap("Carcass Section", p.join(""));
}
// Pick the detailing drawings appropriate to the design type.
function ssDetails(type: string, layout: any): { title: string; svg: string }[] {
  const t = (type || "").toLowerCase();
  if (t.includes("kitchen")) {
    const out = [{ title: "Base", svg: detailBaseCabinet() }, { title: "Wall", svg: detailWallCabinet() }, { title: "Counter", svg: detailCounterBacksplash() }];
    if (t.includes("l-shape") || t.includes("u-shape") || t.includes("g-shape") || t.includes("parallel") || t.includes("peninsula") || t.includes("island")) out.splice(2, 0, { title: "Corner", svg: detailCorner() });
    return out.slice(0, 4);
  }
  if (t.includes("wardrobe")) return [{ title: "Track", svg: detailSlidingTrack() }, { title: "Carcass", svg: detailCarcassSection({ hang: true, topLabel: "Loft / Top Shelf" }) }, { title: "Base", svg: detailBaseCabinet() }];
  if (t.includes("crockery")) return [{ title: "Carcass", svg: detailCarcassSection({ topLabel: "Loft" }) }, { title: "Wall", svg: detailWallCabinet() }];
  if (t.includes("lcd") || t.includes("tv")) return [{ title: "Carcass", svg: detailCarcassSection({ topLabel: "Open Shelf" }) }, { title: "Counter", svg: detailCounterBacksplash() }];
  if (t.includes("vanity") || t.includes("dress")) return [{ title: "Carcass", svg: detailCarcassSection({ topLabel: "Mirror Unit" }) }, { title: "Base", svg: detailBaseCabinet() }];
  return [{ title: "Carcass", svg: detailCarcassSection() }];
}

// Furniture cutting list (carcass + per-kind parts) — the reference sheets' "CUTTING LIST".
function furnitureCutList(unit: FurnitureUnit): [string, number, string][] {
  const D = Math.round(unit.depthMM), H = Math.round(unit.heightMM), W = Math.round(unit.widthMM);
  const cols = unit.columns.length, avgW = Math.round(W / Math.max(1, cols));
  const PARTLBL: Record<string, string> = { shelf: "Shelf", drawer: "Drawer Front", mirror: "Mirror", door: "Shutter", glass: "Glass Shutter", open: "Open Shelf", jali: "Jali Panel", puja: "Marble Back", fluted: "Fluted Panel", marble: "Marble Sheet", niche: "Niche Shelf", floatshelf: "Floating Shelf", tv: "TV Back Panel", basin: "Counter Top", hang: "Hanging Rod" };
  const count: Record<string, number> = {};
  for (const c of unit.columns) for (const cell of (c.cells || [])) if (PARTLBL[cell.kind]) count[cell.kind] = (count[cell.kind] || 0) + 1;
  const rows: [string, number, string][] = [];
  rows.push(["Side / Divider Panel", cols + 1, H + " × " + D]);
  rows.push(["Top Panel", 1, W + " × " + D]);
  rows.push(["Bottom Panel", 1, W + " × " + D]);
  for (const k of Object.keys(count)) {
    const sz = k === "hang" ? avgW + " mm rod" : k === "drawer" ? avgW + " × 150" : k === "floatshelf" ? Math.round(W * 0.6) + " × 250" : k === "marble" || k === "fluted" ? avgW + " × " + H : avgW + " × " + D;
    rows.push([PARTLBL[k], count[k], sz]);
  }
  rows.push(["Back Panel", 1, W + " × " + H]);
  return rows;
}
function furnitureHardware(type: string): string[] {
  const t = (type || "").toLowerCase();
  const base = ["Soft-close hinges", "Telescopic drawer channels", "1 mm PVC edge band", "Profile / handle", "Confirmat screws"];
  if (t.includes("wardrobe")) return ["Sliding / openable track", "Hanging rod (Alu)", ...base];
  if (t.includes("mandir") || t.includes("temple")) return ["LED profile light (2–3 m)", "Brass knob", "CNC jali panel", "Mirror / acrylic adhesive", ...base.slice(0, 3)];
  if (t.includes("wall panel") || t.includes("cladding")) return ["LED profile light (2–3 m)", "Floating-shelf brackets", "WPC / panel adhesive", "PVC edge band", "Confirmat screws"];
  if (t.includes("vanity") || t.includes("dress")) return ["Designer mirror (5 mm)", "LED profile light", "Telescopic channels", ...base.slice(0, 3)];
  if (t.includes("lcd") || t.includes("tv")) return ["LED strip (warm white)", "Cable manager", "Soft-close hinges", "Premium drawer channels", "PVC edge band"];
  return base;
}
const SHEET_W = 1240;        // fixed presentation-sheet width (px)
// Build the full presentation spec sheet for a generated layout.
// meta.finish = the user's actual chosen 3D finish (palette reflects it);
// meta.client = Bill-To dict (shows "Prepared for"); meta.heroDataUrl = a rendered
// 3D / photoreal image to use as the hero instead of the line elevation.
function specSheet(layout: any, meta: { type?: string; id?: string; finish?: string; finishColor?: string; client?: any; material?: any; materialScopes?: any; heroDataUrl?: string } = {}): string {
  const type = meta.type || layout.designType || layout.type || "Modular Kitchen";
  const W = SHEET_W, M = 22, gut = 16;
  const innerW = W - M * 2;
  const parts: string[] = [];
  const { title, sub } = ssTitleFor(type);
  let y = M;

  // ── 1. Banner ───────────────────────────────────────────────────────────
  const bH = 78;
  parts.push(`<rect x="${M}" y="${y}" width="${innerW}" height="${bH}" rx="3" fill="${SS.band}"/>`);
  parts.push(ssText(M + 22, y + 38, title.toUpperCase(), 30, SS.bandInk, "800"));
  parts.push(ssText(M + 23, y + 60, sub, 11.5, "#c9c0ad", "400"));
  parts.push(ssText(W - M - 18, y + 32, MKW.name, 12, "#e9e1cd", "700", "end"));
  parts.push(ssText(W - M - 18, y + 50, "2D Drawing · Plan · Elevation · Detail", 9.5, "#b3a98f", "400", "end"));
  const cl = meta.client;
  if (cl && (cl.name || cl.phone)) parts.push(ssText(W - M - 18, y + 66, "Prepared for: " + [cl.name, cl.phone].filter(Boolean).join(" · "), 9, "#d9cdb0", "600", "end"));
  else parts.push(ssText(W - M - 18, y + 66, MKW.area, 9, "#9b917a", "400", "end"));
  y += bH + gut;

  // ── 2. Hero (annotated elevation) + right column (palette + highlights) ──
  const heroW = Math.round(innerW * 0.62), rcX = M + heroW + gut, rcW = innerW - heroW - gut;
  const heroH = 360;
  const heroSvg = (layout.elevations && layout.elevations[0] && layout.elevations[0].svg) || layout.planSvg || "";
  const usingRender = !!meta.heroDataUrl;
  parts.push(ssCard(M, y, heroW, heroH, usingRender ? "Rendered View" : "Annotated Elevation"));
  const ex = M + 12, ew = heroW - 24;
  const sched = ssSchedule(type, layout);
  if (usingRender) {
    // Rendered 3D / photoreal hero image (data-URL validated raster) + numbered legend.
    const imgH = heroH - (sched.length ? 80 : 50);
    parts.push(`<image x="${ex}" y="${y + 38}" width="${ew}" height="${imgH}" href="${meta.heroDataUrl}" preserveAspectRatio="xMidYMid meet"/>`);
    if (sched.length) {
      const lyY = y + heroH - 30, perRow = Math.ceil(sched.length / 2), colW = (heroW - 26) / perRow;
      parts.push(`<line x1="${M + 13}" y1="${lyY - 8}" x2="${M + heroW - 13}" y2="${lyY - 8}" stroke="${SS.hair}" stroke-width="1"/>`);
      sched.forEach((s, i) => {
        const row = Math.floor(i / perRow), col = i % perRow, lx = M + 15 + col * colW, ly = lyY + row * 15;
        parts.push(`<circle cx="${lx + 6}" cy="${ly - 3}" r="6.5" fill="${SS.band}"/>`);
        parts.push(ssText(lx + 6, ly - 0.2, String(i + 1), 8, "#fff", "700", "middle"));
        parts.push(ssText(lx + 17, ly, s.label, 9, SS.ink, "400", "start", ssFit(s.label, 9, colW - 26)));
      });
    }
  } else {
    // Annotated line elevation with TRUE leader-line callouts — names in a top band,
    // each connected by a fanning leader to its component. The elevation's own centred
    // title (#1e3a5f / 11px) is stripped from the hero copy so it doesn't collide with
    // the callouts — the card header already reads "Annotated Elevation".
    const heroClean = heroSvg.replace(/<text\b[^>]*fill="#1e3a5f"[^>]*font-size="11"[^>]*text-anchor="middle"[^>]*>[^<]*<\/text>/g, "");
    const bandY0 = y + 33, elevY = y + 74, elevH = heroH - 86;
    parts.push(ssEmbed(heroClean, ex, elevY, ew, elevH));
    if (heroSvg && sched.length) {
      const mt = ssMeet(heroSvg, ex, elevY, ew, elevH);
      const t = (type || "").toLowerCase(), isKit = t.includes("kitchen");
      const padL = isKit ? 60 : 50, padSum = isKit ? 190 : 80, drawPx = mt.w - padSum;
      const n = sched.length, slot = (ew - 20) / n, elbowY = bandY0 + 34, trackY = elevY + Math.round(elevH * 0.1) + 8;
      sched.forEach((s, i) => {
        const sx = mt.ox + (padL + s.frac * drawPx) * mt.k;             // component x on the elevation
        const lx = ex + 10 + slot * (i + 0.5), row = i % 2, labY = bandY0 + 8 + row * 14;
        parts.push(ssText(lx, labY, s.label, 7.6, SS.ink, "700", "middle", ssFit(s.label, 7.6, slot - 2)));
        parts.push(`<path d="M${lx.toFixed(1)} ${(labY + 3).toFixed(1)} L${lx.toFixed(1)} ${elbowY.toFixed(1)} L${sx.toFixed(1)} ${trackY.toFixed(1)}" fill="none" stroke="${SS.accent}" stroke-width="0.7"/>`);
        parts.push(`<circle cx="${sx.toFixed(1)}" cy="${trackY.toFixed(1)}" r="2.4" fill="${SS.band}"/>`);
      });
    }
  }
  // right column: material palette
  const mats = ssMaterials(type, layout, meta.finish, meta.finishColor);
  const palH = 200;
  parts.push(ssCard(rcX, y, rcW, palH, "Material Palette"));
  const swPerRow = 3, swGap = 10, swW = (rcW - 26 - swGap * (swPerRow - 1)) / swPerRow, swH = 52;
  mats.forEach((m, i) => {
    const r = Math.floor(i / swPerRow), c = i % swPerRow;
    const sx = rcX + 13 + c * (swW + swGap), sy = y + 40 + r * (swH + 30);
    parts.push(`<rect x="${sx.toFixed(1)}" y="${sy}" width="${swW.toFixed(1)}" height="${swH}" rx="2" fill="${m.fill}" stroke="${SS.line}" stroke-width="0.8"/>`);
    if (m.flute) for (let f = 1; f < 7; f++) parts.push(`<line x1="${(sx + swW * f / 7).toFixed(1)}" y1="${sy}" x2="${(sx + swW * f / 7).toFixed(1)}" y2="${sy + swH}" stroke="#00000022" stroke-width="1"/>`);
    if (m.glass) parts.push(`<line x1="${sx.toFixed(1)}" y1="${sy + swH}" x2="${(sx + swW * 0.5).toFixed(1)}" y2="${sy}" stroke="#ffffff55" stroke-width="2"/>`);
    parts.push(ssText(sx, sy + swH + 12, m.name, 8.6, SS.ink, "700", "start", ssFit(m.name, 8.6, swW)));
    parts.push(ssText(sx, sy + swH + 23, m.sub, 8, SS.sub, "400"));
  });
  // right column: design highlights
  const hlY = y + palH + gut, hlH = heroH - palH - gut;
  parts.push(ssCard(rcX, hlY, rcW, hlH, "Design Highlights"));
  const feats = ssFeatures(type);
  feats.slice(0, Math.floor((hlH - 40) / 22)).forEach((f, i) => {
    const fy = hlY + 50 + i * 22;
    parts.push(ssCheck(rcX + 20, fy - 3.5));
    parts.push(ssText(rcX + 35, fy, f, 10, SS.ink, "400"));
  });
  y += heroH + gut;

  // ── 3. Plan (top view) ───────────────────────────────────────────────────
  if (layout.planSvg) {
    const pd = ssViewDim(layout.planSvg);
    const planH = Math.min(280, Math.max(150, Math.round(innerW * (pd.h / (pd.w || 1)) * 0.5)));
    parts.push(ssCard(M, y, innerW, planH, "Plan — Top View"));
    parts.push(ssEmbed(layout.planSvg, M + 14, y + 36, innerW - 28, planH - 48));
    y += planH + gut;
  }

  // ── 4. Elevation(s) — front view (embedded; carries its own dim chains) ───
  const elevs = (layout.elevations || []);
  if (elevs.length) {
    const elH = 280;
    parts.push(ssCard(M, y, innerW, elH, "Elevation — Front View"));
    const n = Math.min(elevs.length, 3);
    const cw = (innerW - 28 - (n - 1) * 12) / n;
    for (let i = 0; i < n; i++) {
      const cx = M + 14 + i * (cw + 12);
      parts.push(ssEmbed(elevs[i].svg, cx, y + 36, cw, elH - 60));
      parts.push(ssText(cx + cw / 2, y + elH - 12, elevs[i].name || ("View " + (i + 1)), 9, SS.sub, "600", "middle"));
    }
    y += elH + gut;
  }

  // ── 4a. Extra dimensioned views (wardrobe inside view + depth section, …) ─
  const extra = ssExtraViews(type, layout);
  if (extra.length) {
    const evH = 300;
    parts.push(ssCard(M, y, innerW, evH, "Internal Layout & Section"));
    const n = extra.length, cw = (innerW - 28 - (n - 1) * 12) / n;
    for (let i = 0; i < n; i++) {
      const cx = M + 14 + i * (cw + 12);
      parts.push(ssEmbed(extra[i].svg, cx, y + 36, cw, evH - 50));
      if (i < n - 1) parts.push(`<line x1="${(cx + cw + 6).toFixed(1)}" y1="${y + 42}" x2="${(cx + cw + 6).toFixed(1)}" y2="${y + evH - 14}" stroke="${SS.hair}" stroke-width="1"/>`);
    }
    y += evH + gut;
  }

  // ── 4b. Detailing drawings (construction sections) ───────────────────────
  const details = ssDetails(type, layout);
  if (details.length) {
    const dwH = 220;
    parts.push(ssCard(M, y, innerW, dwH, "Detailing Drawings"));
    const n = details.length, cw = (innerW - 28 - (n - 1) * 12) / n;
    for (let i = 0; i < n; i++) {
      const cx = M + 14 + i * (cw + 12);
      parts.push(ssEmbed(details[i].svg, cx, y + 36, cw, dwH - 50));
      if (i < n - 1) parts.push(`<line x1="${(cx + cw + 6).toFixed(1)}" y1="${y + 42}" x2="${(cx + cw + 6).toFixed(1)}" y2="${y + dwH - 14}" stroke="${SS.hair}" stroke-width="1"/>`);
    }
    y += dwH + gut;
  }

  // ── 5. Specifications + Key features / notes ──────────────────────────────
  const specRows = ssSpecs(type, layout, meta.material, meta.materialScopes), notes = ssNotes(type);
  const specH = Math.max(190, 52 + specRows.length * 19);
  const halfW = (innerW - gut) / 2;
  parts.push(ssCard(M, y, halfW, specH, "Specifications & Materials"));
  specRows.forEach((r, i) => {
    const ry = y + 50 + i * 19;
    parts.push(ssText(M + 16, ry, r[0], 9.5, SS.sub, "600"));
    parts.push(ssText(M + 150, ry, r[1], 9.5, SS.ink, "400", "start", ssFit(r[1], 9.5, halfW - 165)));
    if (i < specRows.length - 1) parts.push(`<line x1="${M + 16}" y1="${ry + 6}" x2="${M + halfW - 16}" y2="${ry + 6}" stroke="${SS.hair}" stroke-width="0.7"/>`);
  });
  // right: notes
  const nX = M + halfW + gut;
  parts.push(ssCard(nX, y, halfW, specH, "Notes & Specifications"));
  notes.forEach((nt, i) => {
    const ry = y + 50 + i * 22;
    parts.push(`<circle cx="${nX + 19}" cy="${ry - 3}" r="2.4" fill="${SS.accent}"/>`);
    parts.push(ssText(nX + 30, ry, nt, 9.5, SS.ink, "400", "start", ssFit(nt, 9.5, halfW - 46)));
  });
  y += specH + gut;

  // ── 5b. Cutting list + hardware required (furniture types) ────────────────
  if (layout.furniture) {
    const cuts = furnitureCutList(layout.furniture), hw = furnitureHardware(type);
    const chH = Math.max(170, 56 + Math.max(cuts.length, hw.length) * 17);
    parts.push(ssCard(M, y, halfW, chH, "Cutting List"));
    parts.push(ssText(M + 16, y + 44, "PART", 8.5, SS.sub, "700"));
    parts.push(ssText(M + halfW * 0.62, y + 44, "QTY", 8.5, SS.sub, "700", "middle"));
    parts.push(ssText(M + halfW - 16, y + 44, "SIZE (mm)", 8.5, SS.sub, "700", "end"));
    parts.push(`<line x1="${M + 16}" y1="${y + 48}" x2="${M + halfW - 16}" y2="${y + 48}" stroke="${SS.line}" stroke-width="0.8"/>`);
    cuts.forEach((r, i) => {
      const ry = y + 62 + i * 17;
      parts.push(ssText(M + 16, ry, r[0], 9, SS.ink, "400", "start", ssFit(r[0], 9, halfW * 0.55)));
      parts.push(ssText(M + halfW * 0.62, ry, String(r[1]), 9, SS.ink, "400", "middle"));
      parts.push(ssText(M + halfW - 16, ry, r[2], 9, SS.ink, "400", "end"));
    });
    parts.push(ssCard(nX, y, halfW, chH, "Hardware Required"));
    hw.forEach((h, i) => {
      const ry = y + 58 + i * 19;
      parts.push(ssCheck(nX + 20, ry - 3.5, 6));
      parts.push(ssText(nX + 34, ry, h, 9.5, SS.ink, "400", "start", ssFit(h, 9.5, halfW - 50)));
    });
    y += chH + gut;
  }

  // ── 6. Branded title footer ──────────────────────────────────────────────
  const fH = 50, today = new Date().toISOString().slice(0, 10);
  const idS = meta.id ? meta.id.slice(0, 8).toUpperCase() : "";
  parts.push(`<rect x="${M}" y="${y}" width="${innerW}" height="${fH}" rx="3" fill="${SS.band}"/>`);
  if (MKW_LOGO_B64) parts.push(`<image x="${M + 12}" y="${y + 7}" width="40" height="36" preserveAspectRatio="xMidYMid meet" href="${MKW_LOGO_B64}"/>`);
  parts.push(ssText(M + 62, y + 22, MKW.name, 12.5, SS.bandInk, "700"));
  parts.push(ssText(M + 62, y + 39, MKW.phone + "  ·  " + MKW.email + "  ·  " + MKW.cta, 9.5, "#c9c0ad", "400"));
  parts.push(ssText(W - M - 16, y + 22, type, 11, "#e9e1cd", "700", "end"));
  parts.push(ssText(W - M - 16, y + 39, "DATE " + today + (idS ? "   ·   SHEET " + idS : "") + "   ·   PRESENTATION 2D", 9, "#b3a98f", "400", "end"));
  y += fH + M;

  const H = y;
  return `<svg xmlns="http://www.w3.org/2000/svg" width="${W}" height="${H}" viewBox="0 0 ${W} ${H}" font-family="${SS.font}"><rect width="${W}" height="${H}" fill="${SS.bg}"/>${parts.join("")}</svg>`;
}

// 4-TYPE MODULAR KITCHEN comparison sheet (the reference "4 Type Modular Kitchen").
// Generates the four canonical kitchen shapes and lays them side by side — plan +
// elevation thumbnails + a one-line note each — plus shared detailing + materials.
function kitchenCompareSheet(): string {
  const defs = [
    { type: "Straight Kitchen", dims: { wall: 3000 } as any, desc: "Ideal for compact spaces — efficient, minimal single-wall layout." },
    { type: "Parallel Kitchen", dims: { wall: 3000, wallB: 3000 } as any, desc: "Two parallel platforms — maximum efficiency & worktop." },
    { type: "L-Shape Kitchen", dims: { wall: 3000, wallB: 2400 } as any, desc: "Uses corner space; natural ergonomic work-triangle." },
    { type: "U-Shape Kitchen", dims: { wall: 3000, wallB: 2400, wallC: 2400 } as any, desc: "Best for larger rooms — ample storage & work area." },
    { type: "G-Shape Kitchen", dims: { wall: 3000, wallB: 2400, wallC: 2400 } as any, desc: "U-shape plus a peninsula return — extra worktop & breakfast bar." },
  ];
  const items = defs.map((d) => { try { return { ...d, layout: buildLayout(d.type, d.dims) }; } catch { return { ...d, layout: null }; } });
  const W = SHEET_W, M = 22, gut = 16, innerW = W - M * 2;
  const parts: string[] = []; let y = M;
  // banner
  const bH = 78;
  parts.push(`<rect x="${M}" y="${y}" width="${innerW}" height="${bH}" rx="3" fill="${SS.band}"/>`);
  parts.push(ssText(M + 22, y + 38, "4-TYPE MODULAR KITCHEN", 28, SS.bandInk, "800"));
  parts.push(ssText(M + 23, y + 60, "Straight · Parallel · L-Shape · U-Shape — smart storage with an efficient workflow", 11.5, "#c9c0ad"));
  parts.push(ssText(W - M - 18, y + 32, MKW.name, 12, "#e9e1cd", "700", "end"));
  parts.push(ssText(W - M - 18, y + 50, "Comparison 2D Drawing Sheet", 9.5, "#b3a98f", "400", "end"));
  y += bH + gut;
  // four type columns
  const colW = (innerW - gut * 3) / 4, colH = 386;
  items.forEach((it, i) => {
    const cx = M + i * (colW + gut);
    parts.push(ssCard(cx, y, colW, colH, "Type " + (i + 1)));
    parts.push(ssText(cx + colW / 2, y + 48, it.type.replace(" Kitchen", "").toUpperCase(), 13, SS.accent, "800", "middle"));
    if (it.layout) {
      parts.push(ssText(cx + 12, y + 66, "PLAN", 8, SS.sub, "700"));
      parts.push(ssEmbed(it.layout.planSvg, cx + 8, y + 70, colW - 16, 120));
      parts.push(ssText(cx + 12, y + 200, "ELEVATION", 8, SS.sub, "700"));
      parts.push(ssEmbed((it.layout.elevations[0] || {}).svg || "", cx + 8, y + 204, colW - 16, 110));
    }
    // wrap the description over up to 3 lines
    const words = it.desc.split(" "); let line = "", ln = 0;
    for (const w of words) { if ((line + " " + w).length * 5.0 > colW - 24 && line) { parts.push(ssText(cx + 12, y + 330 + ln * 12, line, 8.4, SS.ink)); line = w; ln++; if (ln > 2) break; } else line = line ? line + " " + w : w; }
    if (ln <= 2) parts.push(ssText(cx + 12, y + 330 + ln * 12, line, 8.4, SS.ink));
  });
  y += colH + gut;
  // shared detailing drawings
  const details = ssDetails("L-Shape Kitchen", {});
  const dwH = 220;
  parts.push(ssCard(M, y, innerW, dwH, "Detailing Drawings"));
  { const n = details.length, cw = (innerW - 28 - (n - 1) * 12) / n;
    for (let i = 0; i < n; i++) { const cx = M + 14 + i * (cw + 12); parts.push(ssEmbed(details[i].svg, cx, y + 36, cw, dwH - 50)); if (i < n - 1) parts.push(`<line x1="${(cx + cw + 6).toFixed(1)}" y1="${y + 42}" x2="${(cx + cw + 6).toFixed(1)}" y2="${y + dwH - 14}" stroke="${SS.hair}" stroke-width="1"/>`); } }
  y += dwH + gut;
  // materials + key features strip
  const halfW = (innerW - gut) / 2, mats = ssMaterials("Kitchen", {}), feats = ssFeatures("Kitchen");
  const sH = 150;
  parts.push(ssCard(M, y, halfW, sH, "Material Palette"));
  const swPerRow = 5, swGap = 8, swW = (halfW - 26 - swGap * (swPerRow - 1)) / swPerRow;
  mats.slice(0, 5).forEach((m, i) => { const sx = M + 13 + i * (swW + swGap), sy = y + 42;
    parts.push(`<rect x="${sx.toFixed(1)}" y="${sy}" width="${swW.toFixed(1)}" height="48" rx="2" fill="${m.fill}" stroke="${SS.line}" stroke-width="0.8"/>`);
    if (m.flute) for (let f = 1; f < 6; f++) parts.push(`<line x1="${(sx + swW * f / 6).toFixed(1)}" y1="${sy}" x2="${(sx + swW * f / 6).toFixed(1)}" y2="${sy + 48}" stroke="#00000022" stroke-width="1"/>`);
    parts.push(ssText(sx, sy + 60, m.name, 8, SS.ink, "700", "start", ssFit(m.name, 8, swW))); parts.push(ssText(sx, sy + 70, m.sub, 7.6, SS.sub)); });
  parts.push(ssCard(M + halfW + gut, y, halfW, sH, "Key Features"));
  feats.slice(0, 6).forEach((f, i) => { const r = i % 3, col = Math.floor(i / 3); const fx = M + halfW + gut + 18 + col * (halfW / 2); const fy = y + 50 + r * 26;
    parts.push(ssCheck(fx, fy - 3.5)); parts.push(ssText(fx + 14, fy, f, 9, SS.ink, "400", "start", ssFit(f, 9, halfW / 2 - 28))); });
  y += sH + gut;
  // footer
  const fH = 50, today = new Date().toISOString().slice(0, 10);
  parts.push(`<rect x="${M}" y="${y}" width="${innerW}" height="${fH}" rx="3" fill="${SS.band}"/>`);
  if (MKW_LOGO_B64) parts.push(`<image x="${M + 12}" y="${y + 7}" width="40" height="36" preserveAspectRatio="xMidYMid meet" href="${MKW_LOGO_B64}"/>`);
  parts.push(ssText(M + 62, y + 22, MKW.name, 12.5, SS.bandInk, "700"));
  parts.push(ssText(M + 62, y + 39, MKW.phone + "  ·  " + MKW.email + "  ·  " + MKW.cta, 9.5, "#c9c0ad"));
  parts.push(ssText(W - M - 16, y + 22, "4-Type Modular Kitchen", 11, "#e9e1cd", "700", "end"));
  parts.push(ssText(W - M - 16, y + 39, "DATE " + today + "   ·   COMPARISON 2D", 9, "#b3a98f", "400", "end"));
  y += fH + M;
  return `<svg xmlns="http://www.w3.org/2000/svg" width="${W}" height="${y}" viewBox="0 0 ${W} ${y}" font-family="${SS.font}"><rect width="${W}" height="${y}" fill="${SS.bg}"/>${parts.join("")}</svg>`;
}

// ── Production panel cut list (12.pdf §5.7.12) — per-cabinet carcass panels for
//    factory cutting (NOT sheet-nesting/optimization, which is forbidden). Each
//    row: Height × Width × Qty × Description, 18 mm board, 3 mm shutter gaps. ──
interface CutRow { h: number; w: number; qty: number; desc: string; scope?: string; face?: boolean; ck?: string; }
function cutList(layout: any): CutRow[] {
  const rows: CutRow[] = [], t = 18, gap = 3, red = handleReduction(layout.handle || "D Handle");
  // scope = base|wall|tall (which finish applies), face = true for visible fronts
  // (shutters/drawer fronts → finish material), false for carcass panels (→ ply).
  // ck = cabinet key (section:runIndex:arrayIndex) so a per-cabinet finish override (§2) can be joined per row.
  let curCK = "";
  const add = (h: number, w: number, qty: number, desc: string, scope: string, face: boolean) => { if (w > 0 && h > 0) rows.push({ h: Math.round(h), w: Math.round(w), qty, desc, scope, face, ck: curCK }); };
  const carcass = (rn: string, c: any, Hc: number, D: number, prefix: string, scope: string) => {
    const W = c.w;
    add(Hc, D, 2, `${rn}: ${prefix}${c.label} — Side Panel`, scope, false);
    add(D, W - 2 * t, 1, `${rn}: ${prefix}${c.label} — Bottom`, scope, false);
    add(D, W - 2 * t, 1, `${rn}: ${prefix}${c.label} — Top / Rail`, scope, false);
    add(Hc, W, 1, `${rn}: ${prefix}${c.label} — Back`, scope, false);
  };
  (layout.runs || []).forEach((run: any, ri: number) => {
    const rn = run.name;
    (run.base || []).forEach((c: any, bi: number) => {
      curCK = "base:" + ri + ":" + bi;
      if (c.kind === "filler") { add(720, c.w, 1, `${rn}: Filler Panel`, "base", false); return; }
      if (c.kind === "sidepanel" || c.kind === "chimney" || c.kind === "hob") return;
      const tall = isTall(c.kind), Hc = tall ? 2100 : 720, D = 560, scope = tall ? "tall" : "base";
      carcass(rn, c, Hc, D, "", scope);
      if (isDrawerKind(c.kind) && c.drawers > 0) {
        const dh = c.dh && c.dh.length === c.drawers ? c.dh : Array(c.drawers).fill(1);
        const tot = dh.reduce((a: number, b: number) => a + b, 0);
        dh.forEach((dv: number, i: number) => add(dv / tot * Hc - 6 - red, c.w - 6, 1, `${rn}: ${c.label} — Drawer Front ${i + 1}`, scope, true));
      } else if (c.kind === "open-shelf") {
        add(D - 20, c.w - 2 * t, 3, `${rn}: ${c.label} — Shelf`, scope, false);
      } else {
        const n = shutterCount(c.w);
        add(Hc - 6 - red, (c.w - (n + 1) * gap) / n, n, `${rn}: ${c.label} — Shutter`, scope, true);
        if (tall) add(D - 20, c.w - 2 * t, c.kind === "tall-hiunit" ? 2 : 5, `${rn}: ${c.label} — Shelf`, scope, false);
      }
    });
    (run.wallCabs || []).forEach((c: any, bi: number) => {
      curCK = "wall:" + ri + ":" + bi;
      if (c.kind === "chimney" || c.kind === "sidepanel") return;
      const Hc = 720, D = 320;
      carcass(rn, c, Hc, D, "Wall ", "wall");
      const n = shutterCount(c.w);
      add(Hc - 6 - red, (c.w - (n + 1) * gap) / n, n, `${rn}: Wall ${c.label} — Shutter`, "wall", true);
      if (c.kind !== "gtpt") add(D - 20, c.w - 2 * t, 2, `${rn}: Wall ${c.label} — Shelf`, "wall", false);
    });
  });
  return rows;
}
// Material label for a scope (falls back to the primary finish, else generic).
function materialLabelFor(scopes: any, scope: string): string {
  const m = scopes && (scopes[scope] || primaryMaterial(scopes));
  return m ? [m.brand, m.colorName].filter(Boolean).join(" ") + (m.code ? " (" + m.code + ")" : "") : "";
}
// Manufacturing practicality validation (11.pdf / 12.pdf "Automatic Manufacturing
// Validation") — clearance / interference / standards checks run before approval.
function validateManufacturing(layout: any): { name: string; ok: boolean; note: string }[] {
  const runs = layout.runs || [], allBase = runs.flatMap((r: any) => r.base || []), checks: { name: string; ok: boolean; note: string }[] = [];
  // 14.pdf: a sink + a GTPT above it (matching width) are MANDATORY in every kitchen.
  { let sink: any = null, gtpt: any = null;
    for (const r of runs) { for (const c of (r.base || [])) if (c.kind === "sink") sink = c; for (const c of (r.wallCabs || [])) if (c.kind === "gtpt") gtpt = c; }
    const ok = !!sink && !!gtpt && Math.abs(sink.w - gtpt.w) < 1;
    const note = !sink ? "Sink cabinet MISSING (mandatory)." : !gtpt ? "GTPT cabinet above the sink MISSING (mandatory)." : Math.abs(sink.w - gtpt.w) >= 1 ? `Sink ${Math.round(sink.w)} / GTPT ${Math.round(gtpt.w)} mm width mismatch.` : `Sink ${Math.round(sink.w)} mm with matching GTPT above (cleaning zone OK).`;
    checks.push({ name: "Sink + GTPT (14.pdf)", ok, note });
    if (!ok) GEN_LOG.conflicts.push("14.pdf cleaning-zone: " + note);
  }
  // Run-length consistency: panels must fill each run.
  let lenOk = true, lenNote = "";
  for (const r of runs) { const sum = (r.base || []).reduce((s: number, c: any) => s + c.w, 0); if (Math.abs(sum - r.length) > 5) { lenOk = false; lenNote += `${r.name} ${Math.round(sum)}≠${Math.round(r.length)}mm. `; } }
  checks.push({ name: "Run-length consistency", ok: lenOk, note: lenOk ? "Panels fill every run exactly." : lenNote });
  // Drawer/3-drawer cabinets must be standard widths (never resized).
  const badDr = allBase.filter((c: any) => isDrawerKind(c.kind) && !DRAWER_WIDTHS.includes(Math.round(c.w)));
  checks.push({ name: "Drawer widths standard", ok: badDr.length === 0, note: badDr.length ? badDr.map((c: any) => c.label + " " + Math.round(c.w)).join(", ") : "All drawer cabinets on standard widths." });
  // Corner drawer/pull-out clearance: a drawer must not abut a corner return.
  let cornerOk = true, cn = "";
  for (const r of runs) (r.base || []).forEach((c: any, i: number) => { if (c.kind === "corner") { const nb = (r.base[i + 1] || r.base[i - 1]); if (nb && (isDrawerKind(nb.kind) || nb.kind === "pullout")) { cornerOk = false; cn += `${nb.label} abuts corner in ${r.name}. `; } } });
  checks.push({ name: "Corner drawer/pull-out clearance", ok: cornerOk, note: cornerOk ? "No drawer/pull-out blocked by a corner unit." : cn });
  // Sink must sit on a shutter cabinet (plumbing access), not over a drawer stack.
  const sinkOverDr = allBase.some((c: any) => c.kind === "sink" && c.drawers > 0);
  checks.push({ name: "Sink not over a drawer stack", ok: !sinkOverDr, note: sinkOverDr ? "Sink placed over drawers — no plumbing access." : "Sink on a shutter cabinet." });
  // Tall-unit accessibility: tall units should reach a run end or sit beside a non-tall unit.
  let tallOk = true, tn = "";
  for (const r of runs) { const b = r.base || []; b.forEach((c: any, i: number) => { if (isTall(c.kind) && i > 0 && i < b.length - 1 && isTall(b[i - 1].kind) && isTall(b[i + 1].kind)) { tallOk = false; tn += `${c.label} boxed by tall units in ${r.name}. `; } }); }
  checks.push({ name: "Tall-unit accessibility", ok: tallOk, note: tallOk ? "Tall units reach a run end / remain accessible." : tn });
  // Single-shutter width: a single shutter must not exceed 600 mm (else double/triple).
  const wideSingle = allBase.concat(runs.flatMap((r: any) => r.wallCabs || [])).filter((c: any) => (c.kind === "shutter" || c.kind === "wall") && c.drawers === 0 && c.w > 1200 && shutterCount(c.w) < 2);
  checks.push({ name: "Shutter span within limits", ok: wideSingle.length === 0, note: wideSingle.length ? "Oversized single shutter found." : "Shutters split to double/triple beyond 600/1200 mm." });
  // Appliance install/ventilation clearance (5.9.13): the housing for a built-in
  // appliance must be at least the brand appliance width + side install clearance.
  const ab = applianceBrandOf(layout.applianceBrand || "Custom");
  const APPL_KINDS: Record<string, number> = { hob: ab.hob[0], oven: ab.oven[0], dishwasher: ab.dishwasher[0], "tall-hiunit": ab.oven[0], "tall-fridge": ab.refrigerator[0] };
  const brandName = layout.applianceBrand || "Custom";
  let clrOk = true, clrNote = "";
  for (const c of allBase) { const need = APPL_KINDS[c.kind]; if (need) { const mod = nearestCab(need); if (c.w + 1 < mod) { clrOk = false; clrNote += `${c.label || c.kind} ${Math.round(c.w)}mm < ${mod}mm module (${brandName} appliance ${need}mm + ${ab.vent}mm vent / ${ab.install}mm install reserved). `; } } }
  checks.push({ name: "Appliance install/ventilation clearance", ok: clrOk, note: clrOk ? `Built-in appliance housings reserve brand width + ${ab.install} mm side install and ${ab.vent} mm ventilation clearance.` : clrNote });
  // 5.11 (preferential): wall cabinets should mirror base-cabinet module widths where practical;
  // mismatches are allowed but the reason is reported (chimney/glass zone, GTPT-over-sink, fillers).
  { let aligned = 0, total = 0; const reasons = new Set<string>();
    const edges = (arr: any[]) => { const e: number[] = []; let x = 0; for (const c of arr) { e.push(x); x += c.w; } e.push(x); return e; };
    for (const r of runs) {
      const wc = r.wallCabs || []; if (!wc.length) continue;
      const be = edges(r.base || []); let x = 0;
      for (const c of wc) { total++; const l = x, rr = x + c.w; x = rr; const near = (v: number) => be.some((p: number) => Math.abs(p - v) <= 32);
        if (near(l) && near(rr)) aligned++;
        else if (c.kind === "chimney" || c.kind === "glass-wall" || c.kind === "display") reasons.add("chimney/glass zone centred by mandatory rule");
        else if (c.kind === "gtpt") reasons.add("GTPT sized to the sink (cleaning zone)");
        else if (c.kind === "filler" || c.kind === "sidepanel") reasons.add("fillers/side-panels absorb residual");
        else reasons.add("wall module kept to preserve fixed wall length");
      }
    }
    const pct = total ? Math.round(aligned / total * 100) : 100;
    // Preferential rule → never blocks (always reported as honoured); the note carries the alignment % and the reason for any mismatch.
    const note = total === 0 ? "No wall cabinets in this layout." : `${aligned}/${total} wall cabinets align to base modules (${pct}%)` + (reasons.size ? " — mismatches by rule: " + [...reasons].join("; ") + "." : ", fully symmetric.");
    checks.push({ name: "Wall–base symmetry (5.11)", ok: true, note });
  }
  // ── Handle-collision clearance (Risk #9) — handle-knuckle / corner-pinch ──
  // A protruding handle system (D/C handle, knob) can clash where a handle falls into a
  // dead corner, or where two tall full-height doors meet edge-to-edge. Handle-less
  // groove/gola/push systems carry no external handle and never clash.
  {
    const handle = layout.handle || GEN.handle || "D Handle";
    const handleLess = HANDLELESS.has(handle);
    const HW_SKIP = new Set(["filler", "sidepanel", "chimney", "hob", "open-shelf"]);
    const handled = (c: any) => !handleLess && !HW_SKIP.has(c.kind);
    const clashes: string[] = [];
    if (!handleLess) for (const r of runs) {
      const b = r.base || [];
      b.forEach((c: any, i: number) => {
        if (!handled(c)) return;
        const nb = b[i + 1], pb = b[i - 1];
        // a handled door/drawer immediately next to a corner unit → handle pinched in the dead corner.
        if ((nb && nb.kind === "corner") || (pb && pb.kind === "corner"))
          clashes.push(`${c.label || c.kind} handle sits against a corner unit in ${r.name} (handle pinched in the dead corner)`);
        // two tall full-height doors meeting edge-to-edge → long bar handles foul each other.
        else if (nb && isTall(c.kind) && isTall(nb.kind) && c.kind !== "tall-hiunit" && nb.kind !== "tall-hiunit" && handled(nb))
          clashes.push(`${c.label || c.kind} + ${nb.label || nb.kind} tall doors meet in ${r.name} — add an 18–25 mm reveal or alternate the hinges so the ${handle} handles clear`);
      });
    }
    const ok = clashes.length === 0;
    checks.push({ name: "Handle-collision clearance", ok, note: handleLess
      ? `Handle-less ${handle}: one continuous groove/profile channel, no protruding handle to clash.`
      : ok ? `Protruding ${handle} handles clear of corners and adjoining tall doors.`
           : clashes.slice(0, 4).join("; ") + "." });
    if (!ok) GEN_LOG.conflicts.push("Handle clearance: " + clashes[0]);
  }
  // ── Appliance-swing clearance (Risk #9) — door/drop arc must be unobstructed ──
  // A fridge/dishwasher/oven door blocked by a perpendicular corner return, or two
  // appliance doors meeting edge-to-edge, cannot fully open.
  {
    const APPL = new Set(["dishwasher", "fridge", "tall-fridge", "tall-hiunit", "oven"]);
    const issues: string[] = [];
    for (const r of runs) {
      const b = r.base || [];
      b.forEach((c: any, i: number) => {
        if (!APPL.has(c.kind)) return;
        const nb = b[i + 1], pb = b[i - 1];
        if ((nb && nb.kind === "corner") || (pb && pb.kind === "corner"))
          issues.push(`${c.label || c.kind} swing/drop arc blocked by a corner unit in ${r.name}`);
        else if (nb && APPL.has(nb.kind))
          issues.push(`${c.label || c.kind} and ${nb.label || nb.kind} sit edge-to-edge in ${r.name} — opposing appliance doors clash; add a 50–100 mm buffer`);
      });
    }
    const ok = issues.length === 0;
    checks.push({ name: "Appliance-swing clearance", ok, note: ok
      ? "Appliance doors (fridge / dishwasher / oven) have clear swing & drop arcs."
      : issues.slice(0, 4).join("; ") + "." });
    if (!ok) GEN_LOG.conflicts.push("Appliance swing: " + issues[0]);
  }
  // §3/§15: no cabinet may overlap a door / column / ventilator / balcony / stair opening.
  // Wall cabinets are auto-cleared by applyOpenings; this catches any BASE unit still standing
  // over a floor-blocking opening (the designer relocates it via the Top-View planner).
  {
    const structs = (layout.structures || []) as any[];
    const FLOORBLOCK = new Set(["door", "balcony", "stair", "column"]);
    const clashes: string[] = [];
    for (const s of structs) {
      if (!FLOORBLOCK.has(s.kind)) continue;
      const w = s.width && s.width > 0 ? s.width : (s.kind === "column" ? 300 : 800);
      const a = s.pos == null ? null : s.pos, b = a == null ? null : a + w;
      if (a == null) continue;
      for (const r of runs) for (const c of ((r.base || []) as any[])) {
        const cc = c.x + c.w / 2;
        if (cc > a && cc < (b as number) && c.kind !== "filler")
          clashes.push(`${c.label || c.kind} over a ${s.kind} (${Math.round(a)}–${Math.round(b as number)} mm) in ${r.name}`);
      }
    }
    const ok = clashes.length === 0;
    checks.push({ name: "Opening clearance (doors/columns)", ok, note: ok
      ? (structs.length ? "No cabinet overlaps any door / column / ventilator / balcony / stair opening." : "No door/column openings defined for this room.")
      : clashes.slice(0, 4).join("; ") + " — relocate (drag in the Top View) or move the opening." });
    if (!ok) GEN_LOG.conflicts.push("Opening clearance: " + clashes[0]);
  }
  return checks;
}

// ── Indian ergonomic-standards validation (Output: standardsChecks) ────────────
// Cross-checks the GENERATED geometry against published Indian wardrobe & modular-kitchen
// standards (STD_RANGES). Same {name,ok,note} shape as validateManufacturing + a severity
// `level`: "error" = unusable / not buildable as drawn (hanging rod too short to hang clothes,
// columns/bands that don't sum to the carcass — the exact mistakes found in AI-drawn dimension
// images); "warning" = buildable but outside the ideal band. Runs for every design type.
function validateStandards(layout: any): { name: string; ok: boolean; note: string; level: string }[] {
  const R = STD_RANGES, checks: { name: string; ok: boolean; note: string; level: string }[] = [];
  const add = (name: string, ok: boolean, note: string, level = "warning") => checks.push({ name, ok, note, level: ok ? "ok" : level });
  const t = String(layout.type || "").toLowerCase();
  const isKitchen = t.includes("kitchen");

  // ── FURNITURE (wardrobe / crockery / vanity / TV …) — read the actual columns/cells ──
  const u = layout.furniture;
  if (u && Array.isArray(u.columns)) {
    const isWardrobe = t.includes("wardrobe") || t.includes("crockery");
    if (isWardrobe) {
      add("Wardrobe depth (550–650 mm)", inRange(u.depthMM, R.wardrobeDepth), `Depth ${u.depthMM} mm` + (inRange(u.depthMM, R.wardrobeDepth) ? " — fits hangers." : " — outside 550–650 mm (hangers need ~600)."));
      add("Loft height (≥300 mm)", u.loftMM === 0 || u.loftMM >= R.loftMin, `Loft ${u.loftMM} mm` + (u.loftMM === 0 || u.loftMM >= R.loftMin ? "." : " — too shallow for storage bins."));
      // Parts-to-whole: columns must sum to the carcass width (the carcass-deduction lesson).
      const wSum = u.columns.reduce((s: number, c: any) => s + (c.wMM || 0), 0);
      add("Width closes to overall", Math.abs(wSum - u.widthMM) <= 5, `Columns Σ ${Math.round(wSum)} vs ${Math.round(u.widthMM)} mm` + (Math.abs(wSum - u.widthMM) <= 5 ? " — parts sum to the whole." : " — columns do not fill the carcass width."), "error");
      // Per-column: bands must sum to the body height (loft + body = total).
      const body = u.heightMM - (u.loftMM || 0);
      u.columns.forEach((col: any, ci: number) => {
        const hSum = (col.cells || []).reduce((s: number, c: any) => s + (c.hMM || 0), 0);
        if (Math.abs(hSum - body) > 15) add(`Column ${ci + 1} bands close`, false, `Cells Σ ${Math.round(hSum)} vs body ${Math.round(body)} mm — bands don't sum to height.`, "error");
      });
    }
    // Per-cell ergonomics (valid for any furniture column).
    u.columns.forEach((col: any, ci: number) => {
      for (const cell of (col.cells || [])) {
        const h = Math.round(cell.hMM || 0);
        if (cell.kind === "hang") {
          if (h < R.hangMin) add(`Hanging rod usable (col ${ci + 1})`, false, `Hanging gap ${h} mm — too short to hang clothes (need ≥${R.shortHang[0]} short / ${R.longHang[0]}–${R.longHang[1]} long).`, "error");
          else if (!inRange(h, R.shortHang) && !inRange(h, R.longHang)) add(`Hanging height band (col ${ci + 1})`, false, `Hanging ${h} mm — between short (${R.shortHang[0]}–${R.shortHang[1]}) and long (${R.longHang[0]}–${R.longHang[1]}) bands.`, "warning");
        } else if (cell.kind === "drawer") {
          if (!inRange(h, R.drawerH)) add(`Drawer height (col ${ci + 1})`, false, `Drawer ${h} mm — outside ${R.drawerH[0]}–${R.drawerH[1]} mm.`, "warning");
        } else if (cell.kind === "shelf" && /shelf$/i.test(String(cell.label || ""))) {
          // singular "Shelf" = one gap; "Shelves" (plural, aggregate stack) is skipped for the upper bound.
          if (h < R.shelfMin) add(`Shelf spacing (col ${ci + 1})`, false, `Shelf gap ${h} mm — too tight (min ~${R.shelfMin}).`, "warning");
          else if (h > R.shelfGap[1] + 150) add(`Shelf spacing (col ${ci + 1})`, false, `Shelf gap ${h} mm — wider than the ${R.shelfGap[0]}–${R.shelfGap[1]} mm folded-clothes band.`, "warning");
        }
      }
    });
  }

  // ── KITCHEN — scalar ergonomics (driven by STD / learned standards + chosen chimney) ──
  if (isKitchen) {
    const counter = STD.baseHeight + STD.counterThk;
    add("Base cabinet height", inRange(STD.baseHeight, R.baseHeight), `Carcass ${STD.baseHeight} mm (+${STD.counterThk} top = ${counter} mm counter).`);
    add("Countertop height", inRange(counter, R.counterTop), `Finished counter ${counter} mm` + (inRange(counter, R.counterTop) ? " — ergonomic." : " — outside 840–940 mm."));
    add("Base depth", inRange(STD.baseDepth, R.baseDepth), `Base depth ${STD.baseDepth} mm.`);
    add("Wall cabinet depth", inRange(STD.wallDepth, R.wallDepth), `Wall depth ${STD.wallDepth} mm.`);
    add("Wall cabinet height", inRange(STD.wallHeight, R.wallHeight), `Wall height ${STD.wallHeight} mm.`);
    const gap = STD.wallStart - counter;
    add("Counter→wall-cabinet gap", inRange(gap, R.counterToWall), `Gap ${gap} mm (sill ${STD.wallStart} − counter ${counter})` + (inRange(gap, R.counterToWall) ? " — 450–650 mm worktop clearance." : " — outside 450–650 mm."));
    const cw = GEN.chimneyWidth || STD.chimneyWidth;
    add("Chimney width", inRange(cw, R.chimneyW), `Chimney ${cw} mm (standard 600 / 900).`);
  }

  return checks;
}

function cutListCsv(layout: any, scopes?: any, cabMats?: any): string {
  cabMats = cabMats || {};
  const rows = cutList(layout);
  const lines = ["S.No,Height(mm),Width(mm),Qty,Material,Description"];
  rows.forEach((r, i) => { const mat = r.face ? (matLabelOf(cabMaterialFor(scopes, cabMats, r.ck || "", r.scope || "base")) || "Finish: laminate / acrylic / PU") : "18 mm BWP ply"; lines.push(`${i + 1},${r.h},${r.w},${r.qty},"${mat.replace(/"/g, '""')}","${r.desc.replace(/"/g, '""')}"`); });
  return lines.join("\n");
}
// BOQ summary with finish-material lines appended (face area × +15% wastage per scope).
function boqWithMaterial(layout: any, scopes: any, cabMats?: any): { item: string; qty: number; unit: string }[] {
  const rows = boq(layout);
  if (scopes) for (const fl of materialFaceLines(layout, scopes, cabMats)) {
    const m = fl.mat; if (!m) continue;
    const face = mm2ToSqft(fl.faceMm2); if (face <= 0) continue;
    const scopeLbl = fl.override ? "Custom · per-cabinet" : (SCOPE_LABEL[fl.scope] || fl.scope);
    rows.push({ item: "Finish [" + scopeLbl + "] — " + matLabelOf(m) + " · incl. 15% wastage", qty: Math.round(face * 1.15 * 10) / 10, unit: "sq.ft" });
  }
  return rows;
}
// Production data with the chosen MATERIAL joined per scope — cut list (face panels
// get the finish material, carcass panels get 18 mm ply) + cabinet schedule + BOQ.
function productionData(layout: any, scopes: any, cabMats?: any): { cutList: any[]; cabinetSchedule: any[]; boq: any[] } {
  cabMats = cabMats || {};
  const shN = (w: number) => (w <= 600 ? 1 : w <= 1200 ? 2 : 3);
  // §2: a face panel adopts its cabinet's own override finish if set, else the scope finish.
  const cl = (layout.cutList || cutList(layout)).map((r: any) => ({ h: r.h, w: r.w, qty: r.qty, desc: r.desc, material: r.face ? (matLabelOf(cabMaterialFor(scopes, cabMats, r.ck || "", r.scope || "base")) || "Finish: laminate / acrylic / PU") : "18 mm BWP ply" }));
  const cab: any[] = []; let n = 0;
  const matCols = (m: any) => [m ? [m.brand, m.colorName].filter(Boolean).join(" ") : "", m ? (m.finishType || "") : "", m ? (m.code || "") : ""];
  (layout.runs || []).forEach((r: any, ri: number) => {
    (r.base || []).forEach((c: any, bi: number) => {
      if (c.kind === "filler" || c.kind === "sidepanel") return;
      const tall = isTall(c.kind), m = cabMaterialFor(scopes, cabMats, "base:" + ri + ":" + bi, tall ? "tall" : "base");
      cab.push([++n, r.name || "", tall ? "Tall" : "Base", c.label || c.kind, Math.round(c.w), tall ? (STD.wallStart + STD.wallHeight) : STD.baseHeight, STD.baseDepth, c.drawers > 0 ? c.drawers + " drawer fronts" : (c.kind === "open-shelf" ? "open" : shN(c.w) + " shutter" + (shN(c.w) > 1 ? "s" : "")), ...matCols(m)]);
    });
    (r.wallCabs || []).forEach((c: any, bi: number) => {
      if (c.kind === "filler" || c.kind === "sidepanel" || c.kind === "chimney") return;
      const m = cabMaterialFor(scopes, cabMats, "wall:" + ri + ":" + bi, "wall");
      cab.push([++n, r.name || "", "Wall", c.label || c.kind, Math.round(c.w), STD.wallHeight, STD.wallDepth, c.kind === "open-shelf" ? "open" : shN(c.w) + " shutter" + (shN(c.w) > 1 ? "s" : ""), ...matCols(m)]);
    });
  });
  return { cutList: cl, cabinetSchedule: cab, boq: boqWithMaterial(layout, scopes, cabMats) };
}

// ── Hardware schedule (12.pdf master rule) — soft-close hinges, drawer slides,
//    handles per the selected system, and per-cabinet accessories. Aggregated. ──
interface HwRow { item: string; qty: number; unit: string; spec: string; }
function hardwareSchedule(layout: any): HwRow[] {
  const m = new Map<string, HwRow>(), handle = layout.handle || "D Handle";
  const hl = HANDLELESS.has(handle), knob = handle === "Knob", push = handle === "Push-To-Open" || handle === "Tip-On";
  const bump = (k: string, item: string, qty: number, unit: string, spec: string) => { const e = m.get(k) || { item, qty: 0, unit, spec }; e.qty += qty; m.set(k, e); };
  const runs = layout.runs || [];
  for (const r of runs) for (const c of [...(r.base || []), ...(r.wallCabs || [])]) {
    if (["filler", "sidepanel", "chimney", "hob"].includes(c.kind)) continue;
    const tall = isTall(c.kind), hpd = tall ? 4 : 2;   // hinges per door
    if (isDrawerKind(c.kind) && c.drawers > 0) {
      const heavy = c.kind === "drawer-atta";
      bump("slide" + (heavy ? "hd" : ""), "Soft-close drawer slide" + (heavy ? " (heavy-duty)" : ""), c.drawers, "pair", "Tandem/telescopic");
      if (!hl) bump(knob ? "knob" : "handle", knob ? "Cabinet knob" : "Handle — " + handle, c.drawers, "no", handle);
    } else if (c.kind !== "open-shelf") {
      const n = shutterCount(c.w);
      bump(c.kind === "glass-wall" ? "hingeg" : "hinge", c.kind === "glass-wall" ? "Soft-close glass hinge" : "Soft-close hinge", n * hpd, "no", "Soft-close");
      if (push) bump("push", "Push-to-open catch", n, "no", "Tip-on/push");
      else if (!hl) bump(knob ? "knob" : "handle", knob ? "Cabinet knob" : "Handle — " + handle, n, "no", handle);
    }
    if (c.kind === "pullout") bump("acc-po-" + (/Spice/.test(c.label) ? "s" : "b"), "Pull-out basket — " + (/Spice/.test(c.label) ? "spice" : "bottle"), 1, "no", "Wire/SS");
    if (c.kind === "corner") bump("acc-corner-" + c.label, c.label + " mechanism", 1, "no", "Soft-close pull-out");
    if (c.kind === "sink") bump("acc-waste", "Waste bin (under-sink)", 1, "no", "Pull-out");
    if (c.kind === "gtpt") bump("acc-gtpt", "GTPT basket", 1, "no", "SS");
    if (c.kind === "tall-pantry") bump("acc-pantry", "Pantry pull-out unit", 1, "no", "Multi-shelf");
    if (c.kind === "tall-hiunit") bump("acc-hiunit", "Hi-unit (oven+MW housing trims)", 1, "no", "Vented");
    if (/Cutlery/.test(c.label)) bump("acc-cutlery", "Cutlery tray", 1, "no", "Modular");
  }
  if (hl) { let len = 0; for (const r of runs) for (const c of [...(r.base || []), ...(r.wallCabs || [])]) if (!["filler", "sidepanel", "chimney", "hob"].includes(c.kind)) len += c.w; bump("gola", "Gola / J profile — " + handle, Math.round(len / 100) / 10, "m", "Aluminium profile"); }
  return [...m.values()];
}
function boq(layout: any): { item: string; qty: number; unit: string }[] {
  if (layout && layout.wardrobe) return wardrobeBoqRows(layout);   // wardrobe designs use their own BOQ engine
  const cl = cutList(layout), hw = hardwareSchedule(layout), runs = layout.runs || [];
  const panels = cl.reduce((s, r) => s + r.qty, 0);
  const areaft = cl.reduce((s, r) => s + r.h * r.w * r.qty / 1e6, 0) * 10.7639;
  const edgeM = cl.reduce((s, r) => s + 2 * (r.h + r.w) * r.qty / 1000, 0);
  const cabs = runs.reduce((s: number, r: any) => s + (r.base || []).length + (r.wallCabs || []).length, 0);
  const drawers = runs.flatMap((r: any) => r.base || []).filter((c: any) => isDrawerKind(c.kind)).reduce((s: number, c: any) => s + c.drawers, 0);
  const rows = [
    { item: "Cabinets (carcasses)", qty: cabs, unit: "no" },
    { item: "Panels to cut", qty: panels, unit: "no" },
    { item: "Board area (18 mm)", qty: Math.round(areaft * 10) / 10, unit: "sq.ft" },
    { item: "Edge banding (approx)", qty: Math.round(edgeM), unit: "m" },
    { item: "Drawer fronts", qty: drawers, unit: "no" },
  ];
  for (const h of hw) rows.push({ item: h.item, qty: h.qty, unit: h.unit });
  return rows;
}
function hardwareCsv(layout: any): string {
  const lines = ["S.No,Item,Qty,Unit,Spec"];
  hardwareSchedule(layout).forEach((h, i) => lines.push(`${i + 1},"${h.item.replace(/"/g, '""')}",${h.qty},${h.unit},"${h.spec}"`));
  return lines.join("\n");
}

// Convert the views to a single R12-compatible DXF. Entities are placed on
// DISCIPLINE layers (CABINETS / ELECTRICAL / DIMENSIONS / WALLS / APPLIANCES /
// HARDWARE / ANNOTATION) inferred from each primitive; views are stacked
// vertically in real millimetres.
function dxfFromViews(views: Array<{ layer: string; svg: string }>): string {
  const ents: string[] = [];
  const layers = new Set<string>();
  let yOffset = 0; const GAP = 300;
  const L = (lay: string, x1: number, y1: number, x2: number, y2: number) => {
    layers.add(lay);
    ents.push(`0\nLINE\n8\n${lay}\n10\n${x1.toFixed(2)}\n20\n${y1.toFixed(2)}\n30\n0\n11\n${x2.toFixed(2)}\n21\n${y2.toFixed(2)}\n31\n0`);
  };
  const T = (lay: string, x: number, y: number, h: number, s: string) => {
    layers.add(lay);
    ents.push(`0\nTEXT\n8\n${lay}\n10\n${x.toFixed(2)}\n20\n${y.toFixed(2)}\n30\n0\n40\n${h.toFixed(2)}\n1\n${s.replace(/\s+/g, " ").trim()}`);
  };

  for (const v of views) {
    const p = parseSvgPrimitives(v.svg);
    const s = p.scale || 1, viewHmm = p.height / s;
    const X = (px: number) => px / s;
    const Y = (py: number) => (p.height - py) / s - yOffset;   // flip Y, stack down
    for (const r of p.rects) {
      const x1 = X(r.x), y1 = Y(r.y + r.h), x2 = X(r.x + r.w), y2 = Y(r.y);
      L(r.layer, x1, y1, x2, y1); L(r.layer, x2, y1, x2, y2); L(r.layer, x2, y2, x1, y2); L(r.layer, x1, y2, x1, y1);
    }
    for (const ln of p.lines) L(ln.layer, X(ln.x1), Y(ln.y1), X(ln.x2), Y(ln.y2));
    for (const poly of p.polys) for (let i = 0; i < poly.pts.length; i++) { const A = poly.pts[i], B = poly.pts[(i + 1) % poly.pts.length]; L(poly.layer, X(A.x), Y(A.y), X(B.x), Y(B.y)); }
    for (const e of p.ellipses) { const N = 16; let prev: { x: number; y: number } | null = null; for (let i = 0; i <= N; i++) { const t = (i / N) * Math.PI * 2; const cur = { x: X(e.cx + e.rx * Math.cos(t)), y: Y(e.cy + e.ry * Math.sin(t)) }; if (prev) L(e.layer, prev.x, prev.y, cur.x, cur.y); prev = cur; } }
    for (const tx of p.texts) T(tx.layer, X(tx.x), Y(tx.y), 50, tx.s);
    yOffset += viewHmm + GAP;
  }

  const layerTable = [...layers].map((lay) => `0\nLAYER\n2\n${lay}\n70\n0\n62\n${LAYER_COLOR[lay] ?? 7}\n6\nCONTINUOUS`).join("\n");
  return [
    "0\nSECTION\n2\nHEADER\n0\nENDSEC",
    `0\nSECTION\n2\nTABLES\n0\nTABLE\n2\nLAYER\n70\n${layers.size}\n${layerTable}\n0\nENDTAB\n0\nENDSEC`,
    `0\nSECTION\n2\nENTITIES\n${ents.join("\n")}\n0\nENDSEC`,
    "0\nEOF",
  ].join("\n");
}

