// ── Panel cutting list for ONE cabinet (bottom-between-sides carcass) ─────────
// Returns panels with grain direction + which 4 edges get banded (T/B/L/R).
function fabCabinetPanels(cab: any) {
  const W = fabRound(cab.w), H = fabRound(cab.h), D = fabRound(cab.d || FAB.ergonomics.baseDepth);
  const thk = fabThk(cab.material || "18mm BWR Plywood");
  const mat = cab.material || "18mm BWR Plywood";
  const back = "6mm Back Panel";
  const innerW = Math.max(0, W - 2 * thk);
  const nShutters = cab.shutters && +cab.shutters > 0 ? +cab.shutters : (W > 1000 ? 2 : 1);
  const drawers: any[] = Array.isArray(cab.drawers) ? cab.drawers : [];
  const isDrawerUnit = drawers.length > 0;
  // shelves: none in a full drawer bank, else by height
  const shelves = isDrawerUnit ? 0 : (H > 1800 ? 3 : H > 1000 ? 2 : 1);
  const id = (cab.code || "C") + "-";
  const E = (t: boolean, b: boolean, l: boolean, r: boolean) => ({ top: t, bottom: b, left: l, right: r });
  const panels: any[] = [
    { code: id + "LS", panel: "Left Side",  w: D, h: H, thk, qty: 1, material: mat, grain: "Vertical",   edges: E(false, false, true, false), remarks: "front edge banded" },
    { code: id + "RS", panel: "Right Side", w: D, h: H, thk, qty: 1, material: mat, grain: "Vertical",   edges: E(false, false, false, true), remarks: "front edge banded" },
    { code: id + "BT", panel: "Bottom",     w: innerW, h: D, thk, qty: 1, material: mat, grain: "Horizontal", edges: E(false, false, false, false), remarks: "between sides" },
    { code: id + "TP", panel: H > 1000 ? "Top" : "Top Rail", w: innerW, h: H > 1000 ? D : 100, thk, qty: H > 1000 ? 1 : 2, material: mat, grain: "Horizontal", edges: E(false, false, false, false), remarks: H > 1000 ? "between sides" : "stretchers (front+back)" },
  ];
  if (shelves > 0) panels.push({ code: id + "SH", panel: "Adjustable Shelf", w: innerW - 2, h: D - 20, thk, qty: shelves, material: mat, grain: "Horizontal", edges: E(false, false, false, true), remarks: "front edge banded · on shelf-pins" });
  panels.push({ code: id + "BK", panel: "Back Panel", w: W - 2 * FAB.backInset + 12, h: H - 2 * FAB.backInset + 12, thk: 6, qty: 1, material: back, grain: "Vertical", edges: E(false, false, false, false), remarks: "grooved into carcass" });
  if (cab.toeKick !== false && H > 1000) panels.push({ code: id + "TK", panel: "Toe Kick", w: innerW, h: FAB.toeKick, thk, qty: 1, material: mat, grain: "Horizontal", edges: E(true, false, false, false), remarks: "set back 50 mm" });
  return { W, H, D, thk, mat, nShutters, shelves, drawers, isDrawerUnit, innerW, panels };
}

// ── Shutter list for ONE cabinet (full-overlay) ──────────────────────────────
function fabCabinetShutters(cab: any, geo: any) {
  if (cab.shutterless || geo.isDrawerUnit) return [];
  const finish = cab.shutterFinish || "Laminate";
  const n = geo.nShutters;
  const gap = FAB.shutterGap;
  const sw = fabRound((geo.W - gap * (n + 1)) / n + gap);  // each leaf width (full overlay, 3mm reveals)
  const sh = fabRound(geo.H - 2 * gap);
  const hinges = sh <= 900 ? 2 : sh <= 1600 ? 3 : sh <= 2000 ? 4 : 5;
  const isGlass = /glass/i.test(finish);
  const out: any[] = [];
  for (let i = 0; i < n; i++) {
    const handleSide = n === 1 ? "Right" : (i === 0 ? "Right" : i === n - 1 ? "Left" : "Both");
    out.push({
      code: (cab.code || "C") + "-S" + (i + 1), cabinet: cab.code || "C",
      w: Math.max(0, sw), h: Math.max(0, sh), thk: isGlass ? 5 : FAB.shutterThk, qty: 1,
      finish, overlay: "Full Overlay", gap, hinges, hingeType: "Clip-on Soft-close",
      handleSide, handleFromBottom: Math.min(950, geo.H - FAB.handleFromTop),
      grain: isGlass ? "N/A" : "Vertical",
    });
  }
  return out;
}

// ── Drawer components for ONE cabinet (§14 hardware-driven auto-sizing) ───────
function fabCabinetDrawers(cab: any, geo: any, defaults?: any) {
  if (!geo.isDrawerUnit) return { drawers: [], components: [] };
  const gap = FAB.shutterGap;
  const defType = cab.drawerType || (defaults && defaults.drawerType) || fabDrawerTypeFor(cab.unitType || (defaults && defaults.unitType));
  const drawers: any[] = [], components: any[] = [];
  geo.drawers.forEach((dr: any, i: number) => {
    const frontH = fabRound(dr.height || (geo.H - gap * (geo.drawers.length + 1)) / geo.drawers.length);
    const dType = dr.type || defType;
    const hwId = dr.hardware || cab.drawerHardware || (defaults && defaults.drawerHardware) || fabDefaultHardwareFor(dType);
    const hw = fabHardwareById(hwId) || fabHardwareById(fabDefaultHardwareFor(dType));
    const s = fabDrawerSizing(geo, hw, dType, frontH);
    const code = (cab.code || "C") + "-D" + (i + 1);
    const mat = cab.material || "18mm BWR Plywood";
    drawers.push({
      code, type: dType, typeLabel: (FAB_DRAWER_TYPES[dType] && FAB_DRAWER_TYPES[dType].label) || dType,
      frontH, boxW: s.boxW, boxH: s.boxH, backW: s.backW, depth: s.depth, usableDepth: s.usableDepthIn,
      channel: s.depth, channelType: hw.category, mount: hw.mount, metalSide: hw.metalSide,
      load: hw.load, softClose: hw.softClose, pushOpen: hw.pushOpen, profileNote: s.profileNote,
      hardware: { id: hw.id, brand: hw.brand, model: hw.model, category: hw.category, load: hw.load, softClose: hw.softClose, pushOpen: hw.pushOpen },
      drills: s.drills, warnings: s.warnings,
    });
    // Front (always wood). Metal-side systems have no wooden sides — only Front/Back/Bottom.
    const handleClause = hw.pushOpen ? "push-to-open · no handle" : "handle centred · " + (cab.shutterFinish || "matches shutter");
    components.push({ code: code + "-F", drawer: code, panel: "Drawer Front", w: s.frontW, h: frontH, thk: 18, qty: 1, material: mat, grain: "Horizontal", remarks: handleClause });
    components.push({ code: code + "-B", drawer: code, panel: "Drawer Back", w: s.backW, h: s.boxH, thk: hw.metalSide ? 16 : 12, qty: 1, material: hw.metalSide ? "16mm BWR Plywood" : "12mm Plywood", grain: "Horizontal", remarks: hw.metalSide ? "sits between metal gallery sides" : "" });
    if (!hw.metalSide) components.push({ code: code + "-S", drawer: code, panel: "Drawer Side", w: s.depth, h: s.boxH, thk: s.boxSideThk, qty: 2, material: s.boxSideThk >= 18 ? mat : "12mm Plywood", grain: "Horizontal", remarks: "L+R · runner-drilled" });
    components.push({ code: code + "-BT", drawer: code, panel: "Drawer Bottom", w: s.bottomW, h: s.bottomD, thk: 6, qty: 1, material: "6mm Back Panel", grain: "Horizontal", remarks: "grooved in 10mm" });
  });
  return { drawers, components };
}

// ── Edge-banding report (per banded edge + totals by thickness) ───────────────
function fabEdgeBanding(allPanels: any[]) {
  const lines: any[] = [];
  let total1 = 0;
  for (const p of allPanels) {
    if (!p.edges) continue;
    const map: [string, number][] = [["Top", p.w], ["Bottom", p.w], ["Left", p.h], ["Right", p.h]];
    for (const [edge, len] of map) {
      if (p.edges[edge.toLowerCase()]) {
        for (let q = 0; q < p.qty; q++) { lines.push({ panel: p.panel, code: p.code, edge, len: fabRound(len), thk: FAB.edgeBandThk }); total1 += len; }
      }
    }
  }
  const rmTotal = rmeter(total1);
  return {
    lines: lines.slice(0, 400),
    totals: [{ thk: FAB.edgeBandThk, color: "Matching", type: "PVC", runningM: rmTotal, runningFt: +(rmTotal * 3.281).toFixed(1), rolls: Math.max(1, Math.ceil(total1 / FAB.rollLen)) }],
    totalRunningM: rmTotal,
  };
}

// ── 32-mm system CNC drilling/routing for ONE panel ──────────────────────────
function fabCncForPanel(p: any) {
  const ops: any[] = [];
  const W = p.w, H = p.h;
  const isSide = /Side/.test(p.panel), isShutter = /Shutter/.test(p.panel) || p.finish, isBottomTop = /Bottom|Top/.test(p.panel);
  if (isSide) {
    // two vertical system rows (front @37, back @ D-37) — construction + shelf-pin holes
    for (const x of [FAB.systemEdge, W - FAB.systemEdge]) {
      for (let y = FAB.systemEdge; y <= H - FAB.systemEdge; y += 320) // sample every 10 pitches for readability
        ops.push({ type: "drill", x, y: fabRound(y), dia: FAB.systemHoleDia, depth: FAB.systemHoleDepth, note: "32mm system" });
    }
    // construction dowels into top/bottom
    for (const y of [FAB.systemEdge, H - FAB.systemEdge]) for (const x of [FAB.systemEdge, W - FAB.systemEdge])
      ops.push({ type: "drill", x, y, dia: FAB.dowelDia, depth: FAB.dowelDepth, note: "carcass dowel" });
    ops.push({ type: "groove", x: FAB.backInset, len: H, width: 6, depth: 8, note: "back-panel groove" });
  } else if (isShutter && !/N\/A/.test(p.grain || "")) {
    for (let i = 0; i < (p.hinges || 2); i++) {
      const y = (p.hinges || 2) === 2 ? [100, H - 100][i] : Math.round(100 + i * (H - 200) / ((p.hinges || 2) - 1));
      ops.push({ type: "bore", x: FAB.hingeCupOffset, y, dia: FAB.hingeCupDia, depth: 13, note: "hinge cup" });
    }
  } else if (isBottomTop) {
    for (const x of [FAB.systemEdge, W - FAB.systemEdge]) for (const y of [FAB.systemEdge, H - FAB.systemEdge])
      ops.push({ type: "drill", x, y, dia: FAB.dowelDia, depth: FAB.dowelDepth, note: "carcass dowel" });
  }
  return { code: p.code, panel: p.panel, w: W, h: H, thk: p.thk, ops };
}

// ── Plywood nesting (shelf / first-fit-decreasing) per material+thickness ─────
function fabNest(panels: any[], sheetKey: string) {
  const sheet = (FAB.sheets as any)[sheetKey] || FAB.sheets["8x4"];
  const K = FAB.kerf;
  // group by material+thickness
  const groups: Record<string, any[]> = {};
  for (const p of panels) {
    const key = p.material + " · " + p.thk + "mm";
    (groups[key] = groups[key] || []).push(p);
  }
  const result: any[] = [];
  for (const key of Object.keys(groups)) {
    // expand by qty, cap to avoid runaway
    const rects: any[] = [];
    for (const p of groups[key]) for (let q = 0; q < p.qty && rects.length < 1500; q++)
      rects.push({ code: p.code, w: Math.min(p.w, sheet.w), h: Math.min(p.h, sheet.h), grain: p.grain });
    rects.sort((a, b) => b.h - a.h || b.w - a.w);
    const sheets: any[] = [];
    for (const r of rects) {
      let placed = false;
      for (const sh of sheets) {
        for (const shelf of sh.shelves) {
          if (r.h <= shelf.h && r.w <= sheet.w - shelf.cx) {
            shelf.placements.push({ x: shelf.cx, y: shelf.y, w: r.w, h: r.h, code: r.code });
            sh.placements.push({ x: shelf.cx, y: shelf.y, w: r.w, h: r.h, code: r.code });
            shelf.cx += r.w + K; placed = true; break;
          }
        }
        if (!placed && sh.cy + r.h + K <= sheet.h) {     // new shelf on this sheet
          const shelf = { y: sh.cy, h: r.h, cx: r.w + K, placements: [{ x: 0, y: sh.cy, w: r.w, h: r.h, code: r.code }] };
          sh.shelves.push(shelf); sh.placements.push({ x: 0, y: sh.cy, w: r.w, h: r.h, code: r.code });
          sh.cy += r.h + K; placed = true;
        }
        if (placed) break;
      }
      if (!placed) {       // new sheet
        const sh: any = { placements: [], shelves: [{ y: 0, h: r.h, cx: r.w + K, placements: [{ x: 0, y: 0, w: r.w, h: r.h, code: r.code }] }], cy: r.h + K };
        sh.placements.push({ x: 0, y: 0, w: r.w, h: r.h, code: r.code });
        sheets.push(sh);
      }
    }
    const sheetArea = sheet.w * sheet.h;
    const nest = sheets.map((sh, i) => {
      const used = sh.placements.reduce((s: number, p: any) => s + p.w * p.h, 0);
      return { index: i + 1, placements: sh.placements, utilization: +((used / sheetArea) * 100).toFixed(1) };
    });
    const usedTotal = sheets.reduce((s, sh) => s + sh.placements.reduce((a: number, p: any) => a + p.w * p.h, 0), 0);
    result.push({ material: key, sheetKey, sheetW: sheet.w, sheetH: sheet.h, count: sheets.length, sheets: nest, avgUtil: sheets.length ? +((usedTotal / (sheets.length * sheetArea)) * 100).toFixed(1) : 0, areaSqft: sqft(usedTotal) });
  }
  return result;
}

// ── Material + hardware BOM ───────────────────────────────────────────────────
function fabBom(cabs: any[], allPanels: any[], allShutters: any[], drawerData: any[], nest: any[]) {
  // sheet material from nesting (real) + area
  const material = nest.map((g) => ({ material: g.material, sheets: g.count, areaSqft: g.areaSqft, wastePct: +(100 - g.avgUtil).toFixed(1), sheetSize: (FAB.sheets as any)[g.sheetKey].label }));
  // hinges
  let hinges = 0; for (const s of allShutters) hinges += s.hinges;
  let handles = allShutters.length; let legs = 0;
  for (const c of cabs) if ((c.h || 0) > 1000) legs += 4; else legs += 2;
  // §14: drawer runners itemised by the ACTUAL selected model/depth/load (one pair per drawer)
  const runnerMap = new Map<string, any>();
  for (const d of drawerData) for (const dr of d.drawers) {
    const key = dr.hardware.brand + "|" + dr.hardware.model + "|" + dr.depth;
    const row = runnerMap.get(key) || { item: dr.hardware.model + (dr.softClose ? " (soft-close)" : dr.pushOpen ? " (push-open)" : ""), size: dr.depth + "mm · " + dr.load + "kg", qty: 0, brand: dr.hardware.brand };
    row.qty += 1; runnerMap.set(key, row);
  }
  const runnerRows = [...runnerMap.values()].map((r) => ({ ...r, qty: r.qty + " pairs" }));
  const hardware = [
    { item: "Soft-close Hinges (Clip-on)", size: "35mm cup", qty: hinges, brand: "Blum / Hettich" },
    ...runnerRows,
    { item: "Cabinet Handles / Profiles", size: "128mm", qty: handles, brand: "Hafele" },
    { item: "Adjustable Legs", size: "100mm", qty: legs, brand: "Ebco" },
    { item: "Shelf Pins", size: "5mm", qty: allPanels.filter((p) => /Shelf/.test(p.panel)).reduce((s, p) => s + p.qty * 4, 0), brand: "Generic" },
  ].filter((h) => (typeof h.qty === "number" ? h.qty > 0 : true));
  // fasteners
  const carcassCount = cabs.length;
  const fasteners = [
    { item: "Confirmat / Euro Screws", size: "5×50mm", qty: carcassCount * 16 + 20, type: "KD" },
    { item: "Wooden Dowels", size: "8×40mm", qty: carcassCount * 8, type: "Joinery" },
    { item: "Cabinet Screws", size: "4×16mm", qty: carcassCount * 24, type: "Countersunk" },
  ];
  const totalSqft = nest.reduce((s, g) => s + g.areaSqft, 0);
  const adhesives = [
    { item: "Hot-melt EVA (edge banding)", qty: +(totalSqft / 25).toFixed(1), unit: "kg" },
    { item: "PVA Wood Glue", qty: +(totalSqft / 20).toFixed(1), unit: "L" },
  ];
  return { material, hardware, fasteners, adhesives };
}

// ── 3D verification + AI error detection ─────────────────────────────────────
function fabVerify(cabs: any[], geos: any[]) {
  const checks: any[] = [], errors: any[] = [], questions: string[] = [], estimates: any[] = [];
  cabs.forEach((c, i) => {
    const g = geos[i];
    const need = 4 + g.shelves + 1 + (g.isDrawerUnit ? 0 : 0); // sides+top+bottom+shelves+back
    checks.push({ cabinet: c.code, label: "Panel set complete", ok: g.panels.length >= 5, detail: g.panels.length + " panels generated" });
    checks.push({ cabinet: c.code, label: "Depth within ergonomics", ok: g.D >= 250 && g.D <= 700, detail: g.D + "mm" });
    checks.push({ cabinet: c.code, label: "No shelf/drawer collision", ok: !(g.isDrawerUnit && g.shelves > 0), detail: g.isDrawerUnit ? "drawer bank" : g.shelves + " shelves" });
    if (!c.d) { errors.push({ level: "warn", cabinet: c.code, msg: "Depth not specified — estimated " + g.D + "mm (Indian base-unit standard)" }); estimates.push({ cabinet: c.code, field: "Depth", value: g.D + "mm", basis: "Indian standard base depth", confidence: "85%" }); }
    if (!c.material) estimates.push({ cabinet: c.code, field: "Material", value: "18mm BWR Plywood", basis: "default carcass material", confidence: "75%" });
    if (g.W < 150 || g.W > 3000) errors.push({ level: "error", cabinet: c.code, msg: "Width " + g.W + "mm looks out of range — verify the drawing" });
    if (!g.H) errors.push({ level: "error", cabinet: c.code, msg: "Height missing — cannot cut panels" });
  });
  if (cabs.some((c) => !c.material)) questions.push("Confirm carcass material & thickness (18mm BWR Ply / HDHMR / MDF)?");
  if (cabs.some((c) => !c.shutterFinish && !c.shutterless)) questions.push("Confirm shutter finish (Laminate / Acrylic / PU / Glass)?");
  const pass = checks.filter((c) => c.ok).length;
  return { checks, passed: pass, total: checks.length, errors, questions, estimates };
}

// ── Module 5: FLOATING FURNITURE, INSTALL GUIDE, PANEL NUMBERING, PACKING ─────
// Wall load capacities (kg pull-out per fixing point) + suspension hardware for
// wall-hung cabinets. Safety factor 2× per the spec.
const FAB_WALL_TYPES: Record<string, { label: string; perPoint: number; fixing: string; note: string }> = {
  concrete: { label: "RCC / Concrete", perPoint: 60, fixing: "M8 sleeve/chemical anchor", note: "Strongest — takes heavy wall-hung units." },
  brick:    { label: "Solid Brick",    perPoint: 35, fixing: "10mm nylon plug + chemical anchor", note: "Good for medium units; use chemical anchor for heavy." },
  aac:      { label: "AAC / Fly-ash Block", perPoint: 18, fixing: "AAC-specific anchor (Fischer GB)", note: "Weaker — spread the load, prefer a suspension rail." },
  drywall:  { label: "Drywall / Gypsum", perPoint: 8, fixing: "Toggle/butterfly anchor into a stud", note: "Low — must hit studs or add a backing frame." },
  wood:     { label: "Wood / Ply partition", perPoint: 25, fixing: "Wood screw into stud/backing", note: "OK when fixed into solid studs or a ply backing." },
};
const FAB_FLOATING_HW = [
  { item: "Cabinet Hanger Bracket (pair)", brand: "Hettich", model: "Cabinet Hanger + Suspension Rail", load: 120, note: "Adjustable self-locking — primary suspension for wall-hung cabinets." },
  { item: "French Cleat (aluminium)", brand: "Hafele", model: "AL French Cleat", load: 80, note: "Continuous rail — spreads load along the wall." },
  { item: "Heavy L-bracket", brand: "Ebco", model: "HD L-Bracket", load: 40, note: "Secondary/bottom support." },
  { item: "Anti-lift safety lock", brand: "Hettich", model: "Anti-lift clip", load: 0, note: "Prevents accidental lift-off — mandatory on floating units." },
];
function fabCabinetWeightKg(cab: any, geo: any): number {
  // panel area × board density (~11.6 kg/m² for 18mm ply) + shutters + hardware, then contents.
  let mm2 = 0; for (const p of geo.panels) mm2 += (p.w || 0) * (p.h || 0) * (p.qty || 1);
  const boardKg = (mm2 / 1_000_000) * (geo.thk >= 18 ? 11.6 : 8);
  const shutterKg = (geo.nShutters || 0) * ((geo.W * geo.H) / 1_000_000) * 9;
  const carcassKg = boardKg + shutterKg + 3;                       // + hinges/handles/rail
  const volM3 = (geo.W * geo.H * geo.D) / 1_000_000_000;
  const contentsKg = volM3 * (geo.isDrawerUnit ? 120 : 60);        // loaded drawers heavier than shelves
  return Math.round(carcassKg + contentsKg);
}
function fabFloatingCheck(cab: any, geo: any): any {
  const wallKey = String(cab.wallType || "brick");
  const wall = FAB_WALL_TYPES[wallKey] || FAB_WALL_TYPES.brick;
  const totalKg = fabCabinetWeightKg(cab, geo);
  const points = Math.max(2, Math.round((geo.W || 600) / 300));    // one fixing ~ every 300 mm
  const wallCapacity = points * wall.perPoint;
  const safety = 2;
  const required = totalKg * safety;
  const ok = wallCapacity >= required;
  const rail = FAB_FLOATING_HW[0];
  const warnings: string[] = [];
  if (!ok) warnings.push("Wall capacity " + wallCapacity + "kg (" + points + " × " + wall.perPoint + "kg on " + wall.label + ") is below the " + required + "kg needed (" + totalKg + "kg × " + safety + " safety) — add fixing points, use chemical anchors, or a full suspension rail + backing frame.");
  if (wallKey === "drywall" && totalKg > 30) warnings.push("Drywall cannot safely carry " + totalKg + "kg wall-hung — fix into studs or add a plywood backing frame first.");
  const hardware = ok ? [FAB_FLOATING_HW[0], FAB_FLOATING_HW[3]] : FAB_FLOATING_HW.slice();
  return { floating: true, wallType: wallKey, wallLabel: wall.label, fixing: wall.fixing, weightKg: totalKg, fixingPoints: points, wallCapacityKg: wallCapacity, requiredKg: required, safetyFactor: safety, ok, hardware, rail: rail.model, warnings };
}
// Step-by-step installation guide (site-worker friendly) for the whole project.
function fabInstallGuide(cabinets: any[], unitType: string): any {
  const floating = cabinets.some((c) => c.floatingCheck);
  const steps: any[] = [];
  let n = 1;
  steps.push({ no: n++, title: "Site check & marking", detail: "Check wall plumb & level. Mark the cabinet base/hang line with a laser level; mark stud/beam positions.", tools: ["Laser level", "Tape", "Pencil", "Stud finder"], hardware: "—" });
  if (floating) steps.push({ no: n++, title: "Fix the suspension rail", detail: "Drill and fix the Hettich suspension rail / French cleat to the marked line using the wall-appropriate anchors. Verify it is dead level.", tools: ["Hammer drill", "8mm bit", "Spirit level", "Spanner"], hardware: "Suspension rail + " + (FAB_WALL_TYPES[String(cabinets.find((c) => c.floatingCheck)?.floatingCheck?.wallType || "brick")]?.fixing || "wall anchors") });
  steps.push({ no: n++, title: "Assemble carcasses", detail: "Assemble each cabinet carcass on a clean floor per its panel numbers (sides → bottom → top → back). Square each box with the back panel before the glue sets.", tools: ["Cordless drill", "4mm bit", "Rubber mallet", "Square"], hardware: "Confirmat screws 5×50, 8mm dowels, cam locks" });
  steps.push({ no: n++, title: "Install carcasses in sequence", detail: floating ? "Hang each carcass on the rail from the corner outward; level with the bracket adjusters; engage the anti-lift lock." : "Set base cabinets from the corner outward on adjustable legs; level each; clamp and join adjacent cabinets.", tools: ["Level", "Clamps", "Spanner"], hardware: floating ? "Cabinet hangers + anti-lift clips" : "Adjustable legs, inter-cabinet connectors" });
  steps.push({ no: n++, title: "Fit shutters, drawers & hardware", detail: "Hang shutters on soft-close hinges and adjust the 3-way gap to an even reveal. Fit drawer runners at the marked drill positions and install drawer boxes; set handles.", tools: ["Screwdriver", "Drawer jig"], hardware: "Hinges, drawer runners, handles" });
  if (/kitchen/i.test(unitType)) steps.push({ no: n++, title: "Countertop, appliances & services", detail: "Place the countertop, cut the sink/hob openings, connect plumbing/electrical, then fit the chimney and built-in appliances leaving the specified ventilation gaps.", tools: ["Jigsaw", "Silicone gun"], hardware: "Sink clips, appliance brackets" });
  steps.push({ no: n++, title: "Final alignment & safety", detail: "Align all reveals, tighten every fixing, confirm floating units pass the pull/lift test, clean, and hand over.", tools: ["Screwdriver", "Cloth"], hardware: "—" });
  return { steps, floating, safety: ["Wear safety glasses when drilling.", "Never stand a loaded floating cabinet on hardware not rated for it.", "Two people to lift tall/heavy units.", "Verify anchors are fully cured before loading (chemical anchors)."] };
}
// Cabinet/room-wise packing list with carton grouping.
function fabPackingList(project: any, unitType: string, cabinets: any[]): any {
  const room = (project && project.room) || (unitType ? unitType.charAt(0).toUpperCase() + unitType.slice(1) : "Room");
  const rows: any[] = [];
  let carton = 1, inCarton = 0, seq = 1;
  for (const cab of cabinets) {
    const allParts = (cab.panels || []).concat(cab.drawerComponents || []);
    for (const p of allParts) {
      if (inCarton >= 8) { carton++; inCarton = 0; }
      rows.push({
        seq: seq++, room, furniture: unitType, cabinet: cab.code, cabinetName: cab.name,
        panelNo: p.code, panelName: p.panel, size: (p.w || 0) + "×" + (p.h || 0) + "×" + (p.thk || 18),
        material: p.material || cab.material, finish: cab.shutterFinish || "—",
        edge: p.edges ? ["top", "bottom", "left", "right"].filter((e) => p.edges[e]).map((e) => e[0].toUpperCase()).join("") || "—" : "—",
        hardwarePacket: "HW-" + cab.code, carton: "BOX-" + String(carton).padStart(2, "0"),
      });
      inCarton += (p.qty || 1);
    }
  }
  const cartonSet = new Set(rows.map((r) => r.carton));
  return { project: (project && project.name) || "Untitled", room, rows: rows.slice(0, 600), totalPanels: rows.length, cartons: cartonSet.size };
}

// ── Orchestrator: spec → full manufacturing package ──────────────────────────
function fabrikGenerate(spec: any) {
  const defaults = spec.defaults || {};
  const sheetKey = defaults.sheet || "8x4";
  const cabs = (Array.isArray(spec.cabinets) ? spec.cabinets : []).map((c: any, i: number) => ({
    code: c.code || ("C-" + String(i + 1).padStart(3, "0")),
    name: c.name || c.label || ("Cabinet " + (i + 1)),
    w: +c.w || +c.widthMm || 0, h: +c.h || +c.heightMm || 0, d: +c.d || +c.depthMm || 0,
    material: c.material || defaults.material || "18mm BWR Plywood",
    shutterFinish: c.shutterFinish || defaults.shutterFinish || "Laminate",
    shutters: c.shutters, shutterless: !!c.shutterless, drawers: c.drawers || [], toeKick: c.toeKick,
    floating: !!c.floating, wallType: c.wallType || defaults.wallType || "brick",
  })).filter((c: any) => c.w && c.h);

  // Freeform per-panel overrides (keyed by panel/shutter code) — a single part can be
  // forced to a custom W/H/Thk/Qty independent of the cabinet derivation.
  const overrides: Record<string, any> = (spec.overrides && typeof spec.overrides === "object") ? spec.overrides : {};
  const applyOv = (p: any) => {
    const o = overrides[p.code]; if (!o) return p;
    const num = (v: any, d: number) => (v === undefined || v === null || v === "" || isNaN(+v)) ? d : +v;
    return { ...p, w: num(o.w, p.w), h: num(o.h, p.h), thk: num(o.thk, p.thk), qty: Math.max(1, Math.round(num(o.qty, p.qty))), overridden: true, orig: { w: p.w, h: p.h, thk: p.thk, qty: p.qty } };
  };

  const drawerDefaults = { drawerHardware: defaults.drawerHardware || "", drawerType: defaults.drawerType || "", unitType: spec.unitType || "" };
  const cabinets: any[] = [], geos: any[] = [], allPanels: any[] = [], allShutters: any[] = [], drawerData: any[] = [];
  for (const c of cabs) {
    const geo = fabCabinetPanels(c);
    geos.push(geo);
    const shutters = fabCabinetShutters(c, geo).map(applyOv);
    const dr = fabCabinetDrawers(c, geo, drawerDefaults);
    const drComps = dr.components.map((x: any) => applyOv({ ...x, edges: { top: false, bottom: false, left: false, right: false } }));
    const carcass = geo.panels.map(applyOv);
    const panels = carcass.concat(drComps);
    allPanels.push(...panels);
    allShutters.push(...shutters);
    drawerData.push(dr);
    cabinets.push({
      code: c.code, name: c.name, w: geo.W, h: geo.H, d: geo.D, material: geo.mat, thk: geo.thk,
      panels, shutters, drawers: dr.drawers, drawerComponents: drComps,
      floating: !!c.floating, floatingCheck: c.floating ? fabFloatingCheck(c, geo) : null,
    });
  }
  const overrideCount = Object.keys(overrides).length;
  const edgeBanding = fabEdgeBanding(allPanels);
  const nest = fabNest(allPanels, sheetKey);
  const bom = fabBom(cabs, allPanels, allShutters, drawerData, nest);
  const cnc = allPanels.filter((p) => !/Drawer/.test(p.panel)).slice(0, 60).map(fabCncForPanel);
  const verify = fabVerify(cabs, geos);
  // §14: surface drawer-hardware suitability warnings into the verify/error stream
  const hwWarnings: any[] = [];
  cabinets.forEach((cab) => (cab.drawers || []).forEach((dr: any) => (dr.warnings || []).forEach((w: string) => hwWarnings.push({ level: "warn", cabinet: cab.code, msg: dr.code + " · " + w }))));
  verify.errors = verify.errors.concat(hwWarnings);
  verify.checks.push({ cabinet: "—", label: "Drawer hardware suitability", ok: hwWarnings.length === 0, detail: hwWarnings.length ? hwWarnings.length + " warning(s)" : "all drawers within hardware limits" });
  verify.total = verify.checks.length; verify.passed = verify.checks.filter((c: any) => c.ok).length;
  // §14: project-level hardware summary (which runner models, totals, load range)
  const usedHw = new Map<string, any>();
  cabinets.forEach((cab) => (cab.drawers || []).forEach((dr: any) => { const h = usedHw.get(dr.hardware.id) || { ...dr.hardware, count: 0 }; h.count += 1; usedHw.set(dr.hardware.id, h); }));
  const hardwareSummary = { systems: [...usedHw.values()], totalDrawers: drawerData.reduce((s, d) => s + d.drawers.length, 0), warnings: hwWarnings.length };
  // Module 5: floating checks → verify stream; install guide + packing list
  const floatingCabs = cabinets.filter((cab) => cab.floatingCheck);
  floatingCabs.forEach((cab) => (cab.floatingCheck.warnings || []).forEach((w: string) => verify.errors.push({ level: cab.floatingCheck.ok ? "warn" : "error", cabinet: cab.code, msg: "Floating: " + w })));
  if (floatingCabs.length) { verify.checks.push({ cabinet: "—", label: "Floating fixing capacity", ok: floatingCabs.every((cab) => cab.floatingCheck.ok), detail: floatingCabs.filter((cab) => cab.floatingCheck.ok).length + "/" + floatingCabs.length + " within safe wall load (2× safety)" }); verify.total = verify.checks.length; verify.passed = verify.checks.filter((c: any) => c.ok).length; }
  const installGuide = fabInstallGuide(cabinets, spec.unitType || "kitchen");
  const packingList = fabPackingList(spec.project || {}, spec.unitType || "kitchen", cabinets);
  const floatingSummary = floatingCabs.length ? { count: floatingCabs.length, allOk: floatingCabs.every((cab) => cab.floatingCheck.ok), totalWeightKg: floatingCabs.reduce((s, cab) => s + cab.floatingCheck.weightKg, 0) } : null;
  const totalSheets = nest.reduce((s, g) => s + g.count, 0);
  return {
    project: spec.project || { name: "Untitled", client: "" },
    unitType: spec.unitType || "kitchen",
    summary: {
      cabinets: cabinets.length, panels: allPanels.reduce((s, p) => s + p.qty, 0), shutters: allShutters.length,
      drawers: drawerData.reduce((s, d) => s + d.drawers.length, 0), sheets: totalSheets,
      edgeBandM: edgeBanding.totalRunningM, verifyPass: verify.passed + "/" + verify.total, overrides: overrideCount,
      cartons: packingList.cartons, floating: floatingCabs.length,
    },
    cabinets, edgeBanding, nest, bom, cnc, verify, sheetKey, hardwareSummary, installGuide, packingList, floatingSummary,
    standards: { thickness: FAB.carcassThk + "mm carcass / " + FAB.backThk + "mm back", system: "32mm", gap: FAB.shutterGap + "mm full-overlay", note: "Indian modular-furniture standards" },
  };
}

