// =============================================================================
// WARDROBE OPTIONS ENGINE — lifestyle-driven 3-option wardrobe designer.
// Encodes the Indian standard arrangements from the reference chart
// (male/female standard sections; 3 layouts Max Hanging / Balanced / Max Folding;
// loft; AutoCAD-style dimensioned elevations; scorecard + manufacturing reports).
// Deterministic (no external AI).
// =============================================================================
const WARDROBE_STD = {
  depth: 600, loftDepth: 550, plinth: 100,
  hangLong: 1050, hangShort: 900, pantRack: 900,
  drawerH: 200, drawerMinH: 150, shelfGap: 350, shelfMinH: 200,
  loftBand: 600, shoeH: 300, safeH: 300, accH: 150, handbagH: 400, kidsHang: 800, garmentBagH: 1350, skirtHangH: 850, hookH: 640,
  colTarget: 500, colMin: 350, colMax: 650,
  carcass: "18mm BWP / MR-grade plywood", back: "6mm BWP plywood",
  edgeBand: "1-2mm PVC", hinge: "Soft-close hinge (110°)", drawerBox: "Tandem box, soft-close",
  handle: "Profile / knob / long handle",
  finishes: ["Laminate", "Acrylic", "PU", "Veneer", "Rattan", "Glass"],
};
// ── LEARNED DESIGN STANDARDS ── aggregate the vision-learned reference images (wardrobe_learnings)
// into effective standards that OVERRIDE the hardcoded defaults, so all 3 generated options reflect
// what the reference folder taught. Recomputed whenever a new image is learned (always-on watcher).
let WARD_LEARNED: { std: Record<string, number>; dims: Record<string, { def: number; n: number }>; palette: string[]; glass: string[]; compartments: string[]; count: number } | null = null;
function wardLearnedStd() {
  const out = { std: {} as Record<string, number>, dims: {} as Record<string, { def: number; n: number }>, palette: [] as string[], glass: [] as string[], compartments: [] as string[], count: 0 };
  let rows: any[] = [];
  try { rows = sqlite.prepare("SELECT data FROM wardrobe_learnings WHERE engine != 'pending'").all() as any[]; } catch { return out; }
  // learned dimension key (lower-cased, as vision reports it) → [WARDROBE_STD field, sane min, sane max]
  const MAP: Record<string, [string, number, number]> = {
    longhang: ["hangLong", 1300, 1800], shorthang: ["hangShort", 800, 1200],
    shelfpitch: ["shelfGap", 250, 420], shelfgap: ["shelfGap", 250, 420], shelf: ["shelfGap", 250, 420],
    drawer: ["drawerH", 150, 260], drawerh: ["drawerH", 150, 260],
    loft: ["loftBand", 300, 700], depth: ["depth", 500, 700],
    pantrack: ["pantRack", 350, 680], pant: ["pantRack", 350, 680], shoe: ["shoeH", 250, 350], plinth: ["plinth", 75, 120],
  };
  const dimVals: Record<string, number[]> = {}, pal: Record<string, number> = {}, gl: Record<string, number> = {}, comp: Record<string, number> = {};
  for (const r of rows) {
    let d: any; try { d = JSON.parse(r.data); } catch { continue; }
    if (!d || d.subCategory === "pending") continue;
    out.count++;
    const dm = d.dimensionsMm || {};
    for (const k in dm) { const v = +dm[k]; if (!isFinite(v) || v <= 0) continue; const m = MAP[String(k).toLowerCase()]; if (!m) continue; const [f, lo, hi] = m; if (v < lo * 0.55 || v > hi * 1.45) continue; (dimVals[f] = dimVals[f] || []).push(Math.max(lo, Math.min(hi, v))); }
    for (const p of (d.palette || [])) { const s = String(p).toLowerCase().trim(); if (s && s.length < 24) pal[s] = (pal[s] || 0) + 1; }
    if (d.glassType && d.glassType !== "none") gl[d.glassType] = (gl[d.glassType] || 0) + 1;
    for (const c of (d.compartments || [])) { const s = String(c).toLowerCase().trim(); if (s) comp[s] = (comp[s] || 0) + 1; }
  }
  const median = (a: number[]) => { const s = [...a].sort((x, y) => x - y); return s[Math.floor(s.length / 2)]; };
  for (const f in dimVals) { if (dimVals[f].length >= 2) { const v = Math.round(median(dimVals[f])); out.std[f] = v; out.dims[f] = { def: v, n: dimVals[f].length }; } }
  const topK = (o: Record<string, number>, n: number) => Object.entries(o).sort((a, b) => b[1] - a[1]).slice(0, n).map((e) => e[0]);
  out.palette = topK(pal, 5); out.glass = topK(gl, 3); out.compartments = topK(comp, 10);
  return out;
}
function wardLearnedRefresh() { try { WARD_LEARNED = wardLearnedStd(); } catch { WARD_LEARNED = null; } }
// effective standards = defaults overlaid with the learned medians (only dims ≥2 reference images agreed on)
function wardEffStd(): typeof WARDROBE_STD { return (WARD_LEARNED && WARD_LEARNED.count && Object.keys(WARD_LEARNED.std).length) ? (Object.assign({}, WARDROBE_STD, WARD_LEARNED.std) as any) : WARDROBE_STD; }
const WARD_COLORS: Record<string, string> = {
  longHang: "#3b82f6", shortHang: "#8b5cf6", pantRack: "#7c3aed", suit: "#2563eb",
  shelf: "#22c55e", drawer: "#ec4899", shoe: "#d4a574", safe: "#ef4444",
  tieBelt: "#f59e0b", laptop: "#dc2626", loft: "#fcd34d",
  saree: "#ec4899", sareeShelf: "#f472b6", dress: "#f472b6", lehenga: "#db2777",
  salwar: "#f9a8d4", jewellery: "#fcd34d", cosmetics: "#fca5a5", handbag: "#a78bfa",
  skirtHang: "#c084fc", garmentHang: "#6366f1", blazerHook: "#38bdf8", towelHook: "#2dd4bf",
  dupatta: "#f472b6", seasonal: "#78716c", winter: "#78716c",
  kidsHang: "#60a5fa", kidsShelf: "#34d399", mirror: "#94a3b8", filler: "#e2e8f0",
  cornerLemans: "#14b8a6", cornerCarousel: "#0d9488", cornerHang: "#0ea5e9", cornerShelf: "#5eead4",
};
const WARD_LEGEND: [string, string][] = [
  ["longHang", "Long Hanging — shirts/coat/blazer"], ["shortHang", "Short Hanging — shirts/tees"],
  ["pantRack", "Pant Rack — trousers"], ["shelf", "Shelf — sweaters/folded"], ["drawer", "Drawer — innerwear/socks"],
  ["shoe", "Shoe Rack"], ["safe", "Safe Locker — valuables"], ["tieBelt", "Tie & Belt Rack"],
  ["saree", "Saree Hanging"], ["sareeShelf", "Saree (folded)"], ["dress", "Dress Hanging"], ["lehenga", "Lehenga"],
  ["jewellery", "Jewellery Drawer"], ["cosmetics", "Cosmetics Drawer"], ["handbag", "Handbag Shelf"],
  ["skirtHang", "Skirt Hanging"], ["garmentHang", "Garment Bag"], ["blazerHook", "Blazer / Coat Hook"], ["towelHook", "Towel Hook"],
  ["dupatta", "Dupatta"], ["loft", "Loft Area"], ["mirror", "Mirror"],
  ["cornerLemans", "LeMans corner pull-out"], ["cornerCarousel", "Carousel (360°)"], ["cornerHang", "Diagonal corner hanging"], ["cornerShelf", "Blind-corner shelf"],
];
// L/U-shape corner solutions (Module 2 §20) — each has a real hardware + panel signature.
const WARD_CORNERS: Record<string, { label: string; hardware: string; rate: number; note: string }> = {
  lemans: { label: "LeMans II pull-out", hardware: "LeMans II corner set (2 trays)", rate: 8500, note: "Two kidney trays swing out fully — best access, no dead corner." },
  carousel: { label: "Carousel (360°)", hardware: "Full-round carousel unit", rate: 6500, note: "360° rotating shelves — good for a square blind corner." },
  diagonal: { label: "Diagonal corner unit", hardware: "Corner hinge + diagonal shutter", rate: 2200, note: "Angled 45° face with a diagonal hanging rail + shelf; simplest joinery." },
  blind: { label: "Blind corner (deep shelves)", hardware: "Blind-corner pull-out (optional)", rate: 1400, note: "Deep fixed shelves reached from one side — cheapest, partial access." },
};
const WARD_TEMPLATES: Record<string, any> = {
  couple: { maleUsers: 1, femaleUsers: 1, children: 0, professionals: 1, width: 2400, height: 2400, depth: 600, label: "Husband & Wife" },
  bachelor: { maleUsers: 1, femaleUsers: 0, children: 0, professionals: 1, width: 1800, height: 2100, depth: 600, label: "Bachelor" },
  luxury: { maleUsers: 1, femaleUsers: 1, children: 0, professionals: 2, luxury: "high", width: 3000, height: 2700, depth: 600, label: "Luxury" },
  premium: { maleUsers: 1, femaleUsers: 1, children: 0, professionals: 1, luxury: "medium", width: 2700, height: 2400, depth: 600, label: "Premium" },
  budget: { maleUsers: 1, femaleUsers: 1, children: 0, professionals: 1, width: 2000, height: 2100, depth: 600, label: "Budget" },
  kids: { maleUsers: 0, femaleUsers: 0, children: 2, professionals: 0, width: 1800, height: 2100, depth: 600, label: "Kids" },
  walkin: { maleUsers: 1, femaleUsers: 1, children: 0, professionals: 1, width: 3600, height: 2700, depth: 600, label: "Walk-in" },
  family: { maleUsers: 1, femaleUsers: 1, children: 2, professionals: 1, width: 3200, height: 2400, depth: 600, label: "Family" },
};
const wardClamp = (v: number, a: number, b: number) => Math.max(a, Math.min(b, v));
type WCell = { kind: string; label: string; hMM: number };
// A column recipe → cells bottom→top, normalized to sum to usableH.
function wardColumn(recipe: string, usableH: number): WCell[] {
  const S = wardEffStd(), cells: WCell[] = [];
  const push = (kind: string, label: string, hMM: number) => cells.push({ kind, label, hMM: Math.round(Math.max(60, hMM)) });
  const shelves = (h: number, label: string) => { const n = Math.max(2, Math.round(h / S.shelfGap)); for (let i = 0; i < n; i++) push("shelf", label, h / n); };
  switch (recipe) {
    case "hang-long": push("drawer", "Innerwear", S.drawerH); push("drawer", "Socks", S.drawerH); push("longHang", "Long Hanging", usableH - 2 * S.drawerH); break;
    case "hang-short-double":
      if (usableH >= 1950) { push("shortHang", "Short Hanging", S.hangShort); push("shortHang", "Short Hanging", usableH - S.hangShort); }
      else { push("drawer", "Socks", S.drawerH); push("shortHang", "Short Hanging", usableH - S.drawerH); }
      break;
    case "pant+shelves": push("pantRack", "Pant Rack", S.pantRack); shelves(usableH - S.pantRack, "Sweaters"); break;
    case "shelves": shelves(usableH, "Folded"); break;
    case "shoe+drawers": push("shoe", "Shoe Rack", S.shoeH); push("drawer", "Drawer", S.drawerH); push("drawer", "Drawer", S.drawerH); shelves(usableH - S.shoeH - 2 * S.drawerH, "Folded"); break;
    case "accessories": push("safe", "Safe Locker", S.safeH); push("drawer", "Watches", S.accH); push("tieBelt", "Tie & Belt", S.accH); shelves(usableH - S.safeH - 2 * S.accH, "Shelf"); break;
    case "saree": push("drawer", "Petticoat", S.drawerH); push("saree", "Saree Hanging", usableH - S.drawerH); break;
    case "saree-shelves": push("drawer", "Blouse", S.drawerH); shelves(usableH - S.drawerH, "Saree (folded)"); break;
    case "dress": push("drawer", "Innerwear", S.drawerH); push("dress", "Dress Hanging", usableH - S.drawerH); break;
    case "lehenga": push("drawer", "Petticoat", S.drawerH); push("lehenga", "Lehenga", usableH - S.drawerH); break;
    case "female-acc": push("jewellery", "Jewellery", S.accH); push("cosmetics", "Cosmetics", S.accH); push("drawer", "Dupatta", S.drawerH); push("handbag", "Handbags", S.handbagH); shelves(usableH - 2 * S.accH - S.drawerH - S.handbagH, "Shelf"); break;
    case "kids-hang": push("drawer", "Kids", S.drawerH); push("kidsHang", "Kids Hanging", S.kidsHang); shelves(usableH - S.drawerH - S.kidsHang, "Kids Folded"); break;
    case "garment-bag": { push("drawer", "Storage", S.drawerH); const gb = Math.min(S.garmentBagH, usableH - S.drawerH); push("garmentHang", "Garment Bag", gb); const rem = usableH - S.drawerH - gb; if (rem > S.shelfMinH) shelves(rem, "Folded"); break; }
    case "skirt": { push("drawer", "Innerwear", S.drawerH); const sk = Math.min(S.skirtHangH, usableH - S.drawerH); push("skirtHang", "Skirt Hanging", sk); const rem = usableH - S.drawerH - sk; if (rem > S.shelfMinH) shelves(rem, "Folded"); break; }
    case "hooks": { const hh = Math.min(S.hookH, Math.max(300, (usableH - S.shelfGap) / 2)); push("blazerHook", "Blazer Hook", hh); push("towelHook", "Towel Hook", hh); shelves(Math.max(S.shelfMinH, usableH - 2 * hh), "Shelf"); break; }
    default: push("longHang", "Hanging", usableH);
  }
  const sum = cells.reduce((a, c) => a + c.hMM, 0) || 1;
  if (Math.abs(sum - usableH) > 1) { const f = usableH / sum; cells.forEach(c => c.hMM = Math.round(c.hMM * f)); }
  return wardShelfCapHang(wardSuggestFillBlank(cells));
}
// SUGGEST A USE FOR BLANK SPACE: a hanging cell stretched taller than the garment needs leaves dead
// space below the clothes. Cap each oversized hang at its natural clear height and fill the reclaimed
// height with useful shelves (placed below the rod) so no wardrobe has a large unused void.
function wardSuggestFillBlank(cells: WCell[]): WCell[] {
  const NAT: Record<string, number> = { longHang: 1650, hang: 1650, shortHang: 1050, suit: 1300, saree: 1350, dress: 1400, lehenga: 1400, dupatta: 1350, kidsHang: 950, skirtHang: 950, garmentHang: 1400 };
  const isHang = (k: string) => k.toLowerCase().indexOf("hang") >= 0 || k === "saree" || k === "dress" || k === "lehenga" || k === "suit" || k === "dupatta";
  const out: WCell[] = [];
  for (const c of cells) {
    const nat = NAT[c.kind] || (isHang(c.kind) ? 1650 : 0);
    if (nat && isHang(c.kind) && c.hMM > nat + 260) {
      const excess = c.hMM - nat, n = Math.max(1, Math.min(4, Math.round(excess / 340))), sh = Math.round(excess / n);
      for (let i = 0; i < n; i++) out.push({ kind: "shelf", label: "Extra Shelf", hMM: sh });   // reclaimed space → adjustable shelves (suggested use)
      out.push({ kind: c.kind, label: c.label, hMM: nat });   // capped hang sits on top of the new shelves
    } else out.push(c);
  }
  return out;
}
// DESIGN RULE (owner 2026-07-12): a short/long hanging section must always have a SHELF above it, so two
// stacked hanging sections read as separate. Inserts a thin divider shelf above any hanging cell whose
// upper neighbour isn't already shelf-like (steals a slice from the hanging). Idempotent; skips merged
// columns (span/covered) so it can't break a colspan merge. Topmost hangings are capped by the top panel/loft.
function wardShelfCapHang(cells: any[]): any[] {
  if (!Array.isArray(cells) || cells.length < 2) return cells;
  if (cells.some((c: any) => (+c.span > 1) || c.covered)) return cells;   // don't disturb merges
  const isHang = (k: string) => { const s = String(k || "").toLowerCase(); return s.indexOf("hang") >= 0 || k === "saree" || k === "dress" || k === "lehenga" || k === "suit"; };
  const isShelfLike = (k: string) => k === "shelf" || k === "handbag" || k === "kidsShelf" || k === "cornerShelf" || k === "loft";
  const SH = 40, out: any[] = [];
  for (let i = 0; i < cells.length; i++) {
    const cur = cells[i], nxt = cells[i + 1];
    out.push(cur);
    if (isHang(cur.kind) && nxt && !isShelfLike(nxt.kind) && cur.hMM - SH >= 200) {
      cur.hMM -= SH;
      out.push({ kind: "shelf", label: "Divider Shelf", hMM: SH, color: (WARD_COLORS as any).shelf || "#22c55e" });
    }
  }
  return out;
}
// Corner-unit column (L/U-shape §20) — cells for the chosen corner solution.
function wardCornerColumn(solution: string, usableH: number): WCell[] {
  const S = wardEffStd(), cells: WCell[] = [];
  const push = (kind: string, label: string, hMM: number) => cells.push({ kind, label, hMM: Math.round(Math.max(60, hMM)) });
  switch (solution) {
    case "carousel": push("cornerCarousel", "Carousel 360°", usableH); break;
    case "diagonal": push("drawer", "Corner drawer", S.drawerH); push("cornerShelf", "Corner shelf", S.shelfGap); push("cornerHang", "Diagonal hanging", usableH - S.drawerH - S.shelfGap); break;
    case "blind": { const n = Math.max(3, Math.round(usableH / S.shelfGap)); for (let i = 0; i < n; i++) push("cornerShelf", "Blind-corner shelf", usableH / n); break; }
    default: push("drawer", "Corner drawer", S.drawerH); push("cornerLemans", "LeMans pull-out", (usableH - S.drawerH) / 2); push("cornerLemans", "LeMans pull-out", (usableH - S.drawerH) / 2);   // lemans
  }
  const sum = cells.reduce((a, c) => a + c.hMM, 0) || 1;
  if (Math.abs(sum - usableH) > 1) { const f = usableH / sum; cells.forEach(c => c.hMM = Math.round(c.hMM * f)); }
  return cells;
}
// Fold an unfolded (straight-tiled) section list into an L/U shape: split columns into wings
// at wing-width boundaries and insert a corner unit between wings. Reflows x; returns metadata.
function foldWardrobeIntoShape(baseSections: any[], shape: string, wingWidths: number[], cornerSol: string, depth: number, ctx: { usableH: number; height: number; loftH: number }): any {
  const flat: any[] = [];
  for (const s of baseSections) for (const c of (s.columns || [])) flat.push({ ...c, secKind: s.kind, secLabel: s.label });
  const cornerW = depth;
  const wingLabels = shape === "u" ? ["Left Wing", "Back Wing", "Right Wing"] : ["Wing A", "Wing B"];
  const newSections: any[] = [], wings: any[] = [], corners: any[] = [];
  let ci = 0, xOff = 0;
  for (let wi = 0; wi < wingWidths.length; wi++) {
    const budget = wingWidths[wi], last = wi === wingWidths.length - 1;
    const wingCols: any[] = []; let acc = 0;
    while (ci < flat.length && (last || acc + flat[ci].w / 2 <= budget)) { wingCols.push(flat[ci]); acc += flat[ci].w; ci++; }
    if (!wingCols.length && ci < flat.length) { wingCols.push(flat[ci]); ci++; }   // guarantee ≥1 col/wing
    const wingStart = xOff;
    let gi = 0;
    while (gi < wingCols.length) {
      const kind = wingCols[gi].secKind, label = wingCols[gi].secLabel, grp: any[] = [];
      while (gi < wingCols.length && wingCols[gi].secKind === kind) { grp.push(wingCols[gi]); gi++; }
      let gx = xOff; const cols = grp.map((c) => { const col: any = { ...c, x: Math.round(gx), w: Math.round(c.w) }; delete col.secKind; delete col.secLabel; gx += c.w; return col; });
      const gw = cols.reduce((a: number, c: any) => a + c.w, 0);
      newSections.push({ kind, label, x: Math.round(xOff), width: Math.round(gw), columns: cols, wing: wi });
      xOff += gw;
    }
    wings.push({ index: wi, label: wingLabels[wi], x0: Math.round(wingStart), x1: Math.round(xOff), lengthMM: Math.round(xOff - wingStart) });
    if (!last) {
      const cornerCells = wardCornerColumn(cornerSol, ctx.usableH).map((c) => ({ ...c, color: WARD_COLORS[c.kind] || "#cbd5e1" }));
      const cornerCol = { x: Math.round(xOff), w: cornerW, recipe: "corner-" + cornerSol, top: ctx.height, loftH: ctx.loftH, underBeam: false, corner: true, cells: cornerCells };
      newSections.push({ kind: "corner", label: "Corner (" + (WARD_CORNERS[cornerSol] || WARD_CORNERS.lemans).label + ")", x: Math.round(xOff), width: cornerW, columns: [cornerCol], corner: true, wing: -1 });
      corners.push({ index: corners.length, solution: cornerSol, x: Math.round(xOff), widthMM: cornerW, depthMM: depth, between: [wi, wi + 1] });
      xOff += cornerW;
    }
  }
  return { sections: newSections, wings, corners, totalWidth: xOff };
}
// ordered column recipes for a section given strategy + lifestyle
function wardSectionRecipes(sec: string, n: number, strategy: string, L: any): string[] {
  const out: string[] = [], prof = +L.professionals > 0;
  let pool: string[] = [];
  if (sec === "male") {
    // Three BALANCED variants — all keep a healthy mix of hanging + folding/drawers,
    // they differ only in emphasis & column order so the user gets 3 real choices:
    //   balanced       (Everyday)     = even hang/fold alternation (the classic mix)
    //   balanced-hang  (Hanging-Led)  = same mix but leans to hanging, hang columns first
    //   balanced-fold  (Storage-Led)  = same mix but leans to shelves/drawers first
    if (strategy === "balanced-hang") { pool = ["hang-long", "hang-short-double", "garment-bag", "pant+shelves", "shoe+drawers", "accessories"]; if (prof) pool.unshift("hang-long"); }
    else if (strategy === "balanced-fold") pool = ["shelves", "shoe+drawers", "hang-long", "hooks", "pant+shelves", "accessories"];
    else pool = ["hang-long", "garment-bag", "pant+shelves", "hooks", "shoe+drawers", "accessories", "hang-short-double"];
  } else if (sec === "female") {
    const hangItems: string[] = [], foldItems: string[] = [];
    if (L.traditional !== "low") { hangItems.push("saree"); foldItems.push("saree-shelves"); }
    if (L.western !== "low") hangItems.push("dress");
    if (L.traditional === "high") hangItems.push("lehenga");
    if (!hangItems.length) hangItems.push("dress");
    if (strategy === "balanced-hang") pool = [hangItems[0], ...(hangItems[1] ? [hangItems[1]] : []), "skirt", "female-acc", ...foldItems, "shoe+drawers"];
    else if (strategy === "balanced-fold") pool = [...foldItems, "shelves", hangItems[0], "skirt", "female-acc", "shoe+drawers"];
    else pool = [hangItems[0], "female-acc", "skirt", ...(hangItems[1] ? [hangItems[1]] : []), ...foldItems, "shoe+drawers"];
    if (!pool.length) pool = ["shelves"];
  } else {
    for (let i = 0; i < n; i++) out.push(i === n - 1 ? "shelves" : "kids-hang");
    return out;
  }
  for (let i = 0; i < n; i++) out.push(pool[i % pool.length]);
  return out;
}
function buildWardrobeOption(strategy: string, input: any): any {
  const S = wardEffStd();
  const mainWidth = wardClamp(Math.round(+input.width || 2400), 1200, 4800);
  // §20 L/U-shape: the lifestyle sections tile across the UNFOLDED total (all wings); the option
  // is then folded into wings with corner units between them. Straight = unchanged.
  const shape = /^(l|u)$/i.test(String(input.shape || "")) ? String(input.shape).toLowerCase() : "straight";
  const cornerSol = WARD_CORNERS[String(input.corner || "").toLowerCase()] ? String(input.corner).toLowerCase() : "lemans";
  const wingB = wardClamp(Math.round(+input.wingB || 1800), 600, 4800);
  const wingC = wardClamp(Math.round(+input.wingC || 1800), 600, 4800);
  const wingWidths = shape === "u" ? [wingB, mainWidth, wingC] : shape === "l" ? [mainWidth, wingB] : [mainWidth];
  const tileWidth = wardClamp(wingWidths.reduce((a, b) => a + b, 0), 1200, 12000);
  let width = tileWidth;   // final unfolded width (folding adds corner widths below)
  const height = wardClamp(Math.round(+input.height || 2400), 1800, 3000);
  const depth = wardClamp(Math.round(+input.depth || 600), 450, 900);
  const male = wardClamp(+input.maleUsers || 0, 0, 3), female = wardClamp(+input.femaleUsers || 0, 0, 3), kids = wardClamp(+input.children || 0, 0, 3);
  const maleRatio = wardClamp(+input.maleRatio || 50, 25, 75) / 100;
  const hasLoft = height >= 2400;
  const loftH = hasLoft ? wardClamp(Math.round(+input.loftH || S.loftBand), 300, 750) : 0;
  const usableH = height - S.plinth - loftH;
  // §13 beam awareness: a ceiling beam (projection + soffit-height + span) lowers the columns
  // beneath it to the soffit and splits the loft to clear it.
  const bm = input.beam || {};
  const beam: any = { on: false, proj: Math.round(+bm.proj || 0), soffit: Math.round(+bm.soffit || 0), pos: wardClamp(Math.round(+bm.pos || 0), 0, Math.max(0, width - 100)), width: 0 };
  beam.width = wardClamp(Math.round(+bm.width || 0), 0, width - beam.pos);
  beam.on = beam.proj > 0 && beam.width > 0 && beam.soffit > 800 && beam.soffit < height - 150;
  const L = { traditional: input.traditional || "medium", western: input.western || "medium", winter: input.winter || "low", luxury: input.luxury || "low", professionals: +input.professionals || 0 };
  const secs: { kind: string; label: string; frac: number }[] = [];
  if (male > 0 && female > 0) { secs.push({ kind: "male", label: "Male", frac: maleRatio }); secs.push({ kind: "female", label: "Female", frac: 1 - maleRatio }); }
  else if (female > 0) secs.push({ kind: "female", label: "Female", frac: 1 });
  else if (male > 0) secs.push({ kind: "male", label: "Male", frac: 1 });
  else secs.push({ kind: "male", label: "Wardrobe", frac: 1 });
  if (kids > 0) { const kf = Math.min(0.32, 0.16 * kids); secs.forEach(s => s.frac *= (1 - kf)); secs.push({ kind: "kids", label: "Kids", frac: kf }); }
  let x = 0; const sections: any[] = [];
  for (const sec of secs) {
    const secW = Math.round(width * sec.frac);
    const n = wardClamp(Math.round(secW / S.colTarget), 1, 4);
    const colW = secW / n;
    const recipes = wardSectionRecipes(sec.kind, n, strategy, L);
    const columns = recipes.map((r, i) => {
      const cx = Math.round(x + i * colW), cwv = Math.round(colW);
      const ub = beam.on && (cx < beam.pos + beam.width) && (cx + cwv > beam.pos);
      const top = ub ? beam.soffit : height, cLoft = ub ? 0 : loftH;
      const cUse = Math.max(300, top - S.plinth - cLoft);
      return { x: cx, w: cwv, recipe: r, top, loftH: cLoft, underBeam: ub, cells: wardColumn(r, cUse).map(c => ({ ...c, color: WARD_COLORS[c.kind] || "#cbd5e1" })) };
    });
    sections.push({ kind: sec.kind, label: sec.label, x: Math.round(x), width: secW, columns });
    x += secW;
  }
  // §20 fold the unfolded lifestyle sections into L/U wings + corner units.
  let shapeMeta: any = null;
  if (shape !== "straight") {
    const folded = foldWardrobeIntoShape(sections, shape, wingWidths, cornerSol, depth, { usableH, height, loftH });
    sections.length = 0; for (const s of folded.sections) sections.push(s);
    width = folded.totalWidth;
    shapeMeta = { shape, wings: folded.wings, corners: folded.corners, wallWidths: wingWidths, cornerSolution: cornerSol };
  }
  const beamCols = sections.reduce((a: number, s: any) => a + s.columns.filter((c: any) => c.underBeam).length, 0);
  const beamNote = beam.on ? "Beam " + beam.proj + " mm proj · soffit " + beam.soffit + " mm · " + beam.pos + "–" + (beam.pos + beam.width) + " mm: " + beamCols + " column(s) lowered to the soffit · loft split to clear the beam · beam-boxed with a filler above." : null;
  const allCells = sections.flatMap((s: any) => s.columns.flatMap((c: any) => (c.cells || []).filter((x: any) => !x.covered)));
  const cnt = (pred: (k: string) => boolean) => allCells.filter((c: any) => pred(c.kind)).length;
  const stats = {
    hanging: cnt(k => k.toLowerCase().indexOf("hang") >= 0 || k === "saree" || k === "dress" || k === "lehenga" || k === "suit"),
    shelves: cnt(k => k === "shelf" || k === "handbag" || k === "kidsShelf"),
    drawers: cnt(k => k === "drawer" || k === "jewellery" || k === "cosmetics"),
    shoe: cnt(k => k === "shoe"), accessories: cnt(k => k === "safe" || k === "tieBelt" || k === "blazerHook" || k === "towelHook"),
    columns: sections.reduce((a: number, s: any) => a + s.columns.length, 0), totalItems: allCells.length,
  };
  const label = strategy === "balanced-hang" ? "Balanced · Hanging-Led" : strategy === "balanced-fold" ? "Balanced · Storage-Led" : "Balanced · Everyday";
  const finishes = (input.finishes && typeof input.finishes === "object") ? input.finishes : {};
  const corners = shapeMeta ? shapeMeta.corners.length : 0;
  const cornerNote = shapeMeta ? (shapeMeta.shape === "u" ? "U-shape" : "L-shape") + " · " + corners + " corner unit(s) — " + (WARD_CORNERS[cornerSol] || WARD_CORNERS.lemans).label + " (" + (WARD_CORNERS[cornerSol] || WARD_CORNERS.lemans).note + ")" : null;
  return { id: strategy, label, strategy, shape: shapeMeta ? shape : "straight", width, mainWidth, height, depth, plinth: S.plinth, hasLoft, loftH, loftDepth: S.loftDepth, usableH, sections, stats, beam, beamNote, finishes, wings: shapeMeta ? shapeMeta.wings : null, corners: shapeMeta ? shapeMeta.corners : null, wallWidths: shapeMeta ? shapeMeta.wallWidths : null, cornerSolution: shapeMeta ? cornerSol : null, cornerNote };
}
// §14 resolve a section/scope's applied catalog finish (falls back to the whole-project "all").
function wardFinishFor(finishes: any, scope: string): any { return (finishes && (finishes[scope] || finishes.all)) || null; }
// ── Merged compartments (user "select & merge"): a MASTER cell carries span:n (n>1) and covers
// the next n-1 columns at the same vertical band; the absorbed neighbour cells carry covered:true
// (kept in the model so column-height math stays valid, but they render nothing / cost no parts).
// Both master + covered share a mergeId so a rerender can re-snap the band. Helpers below let every
// renderer widen the master and skip the covered twins.
function wardCellSpan(cell: any): number { const n = Math.round(+((cell && cell.span) || 1)); return n > 1 ? n : 1; }
function wardSpanWmm(cols: any[], ci: number, cell: any): number { const n = wardCellSpan(cell); let w = 0; for (let j = 0; j < n && ci + j < cols.length; j++) w += (+cols[ci + j].w || 0); return w; }
// Count the horizontal divider shelves created by editable per-column loftCells
