  hsh = Math.imul(hsh ^ (hsh >>> 13), 1274126177) >>> 0; hsh = (hsh ^ (hsh >>> 16)) >>> 0;
  const isHang = (kk: string) => kk.toLowerCase().indexOf("hang") >= 0 || kk === "saree" || kk === "dress" || kk === "lehenga" || kk === "suit" || kk === "dupatta";
  const isCorner = (kk: string) => kk.indexOf("corner") === 0;

  // ---- a real wire hanger: hook curling over the rod + sloping shoulders ----
  const hanger = (gx: number, rodY: number, shY: number, sw: number) =>
    `<path d="M${f1(gx)},${f1(shY)} L${f1(gx)},${f1(rodY - 1)} q0,${f1(-2.6)} ${f1(-2)},${f1(-2.6)}" fill="none" stroke="${MID}" stroke-width="0.7"/>` +
    `<path d="M${f1(gx - sw / 2)},${f1(shY + 2.4)} L${f1(gx)},${f1(shY)} L${f1(gx + sw / 2)},${f1(shY + 2.4)}" fill="none" stroke="${INK}" stroke-width="0.8"/>`;
  // shirt draping from the shoulders — collar notch + centre placket, near-straight sides
