  // blazer/coat — near-straight sides, collar + lapels + button row + slight flare
  const gCoat = (gx: number, topY: number, gh: number, gw: number) => { const sh = gw / 2, bt = gw * 0.5, ty = topY + 2.4, by = topY + gh, cY = topY + gh * 0.1; let s = `<path d="M${f1(gx - sh)},${f1(ty)} L${f1(gx + sh)},${f1(ty)} L${f1(gx + bt)},${f1(by)} L${f1(gx - bt)},${f1(by)} Z" fill="${WHITE}" stroke="${INK}" stroke-width="0.7"/>`; s += `<path d="M${f1(gx - gw * 0.13)},${f1(ty)} L${f1(gx)},${f1(cY)} L${f1(gx + gw * 0.13)},${f1(ty)}" fill="none" stroke="${INK}" stroke-width="0.55"/><line x1="${f1(gx)}" y1="${f1(cY)}" x2="${f1(gx)}" y2="${f1(by - 1)}" stroke="${MID}" stroke-width="0.5"/>`; const nb = Math.max(2, Math.min(4, Math.floor(gh / 34))); for (let b = 0; b < nb; b++) { const by2 = cY + (by - cY) * 0.28 + b * ((by - cY) * 0.5 / nb); s += `<circle cx="${f1(gx + 1.4)}" cy="${f1(by2)}" r="0.9" fill="none" stroke="${MID}" stroke-width="0.45"/>`; } return s; };
