  const leaf = (lcx: number, lcy: number, len: number, wid: number, deg: number) => { const rad = deg * Math.PI / 180, c = Math.cos(rad), s = Math.sin(rad); const pt = (x: number, y: number) => `${f1(lcx + x * c - y * s)},${f1(lcy + x * s + y * c)}`; return `<path d="M${pt(-len / 2, 0)} Q${pt(0, -wid / 2)} ${pt(len / 2, 0)} Q${pt(0, wid / 2)} ${pt(-len / 2, 0)} Z" fill="${WHITE}" stroke="${INK}" stroke-width="0.7"/>`; };
  const cushions = (cx: number, yt: number, cw: number, ch: number) => { const ccx = cx + cw / 2, len = Math.min(cw * 0.72, 44), wid = len * 0.44; let g = ""; if (ch > 56) { const py = yt + ch - 6, pw = Math.min(cw * 0.7, 46), ph = Math.min(ch * 0.32, 16); g += `<rect x="${f1(ccx - pw / 2)}" y="${f1(py - ph)}" width="${f1(pw)}" height="${f1(ph)}" rx="${f1(ph / 2)}" fill="${WHITE}" stroke="${INK}" stroke-width="0.7"/>`; const ccy = py - ph - 4 - wid / 2; g += leaf(ccx, ccy, len, wid, 30) + leaf(ccx, ccy, len, wid, -30); } else { const ccy = yt + ch * 0.52; g += leaf(ccx, ccy, len, wid, 30) + leaf(ccx, ccy, len, wid, -30); } return g; };
  // ---- a hat resting on a shelf: brim ellipse + dome + band ----
