  p.push(`<text x="${(x0 + wpx / 2).toFixed(1)}" y="${(floorY + plinthPx / 2 + 4).toFixed(1)}" fill="${INK}" font-size="10" font-weight="700" text-anchor="middle">${wardMm(S.plinth)} THADA</text>`);
