  p.push(`<text x="${padL}" y="38" fill="${MID}" font-size="9.5">${esc(String(opt.label || ""))} · overall ${opt.width} × ${opt.height} × ${opt.depth} mm · hinged shutters (≤600 mm leaf)</text>`);
