  for (let i = 0; i < opt.sections.length - 1; i++) { const dx = xOf(opt.sections[i].x + opt.sections[i].width); p.push(`<line x1="${dx.toFixed(1)}" y1="${backY}" x2="${dx.toFixed(1)}" y2="${frontY.toFixed(1)}" stroke="#475569" stroke-width="1.6"/>`); }
