// Seed / overwrite learnings directly (bypasses the vision API — used when a vision key is unavailable
// or to record an expert analysis). Body: { items: [{ filename, category?, data:{...vision schema} }] }.
app.post("/api/wardrobe/learnings/seed", async (c) => {
  try {
    const body = await c.req.json().catch(() => ({} as any));
    const items = Array.isArray(body.items) ? body.items : [];
    if (!items.length) return c.json({ error: "no items" }, 400);
    const stmt = sqlite.prepare("INSERT OR REPLACE INTO wardrobe_learnings (id,path,category,filename,mtime,engine,data,created_at) VALUES (?,?,?,?,?,?,?,?)");
    let n = 0;
    for (const it of items) {
      const fn = String(it.filename || "").trim(); if (!fn) continue;
      const cat = String(it.category || "root"); const id = cat === "root" ? fn : cat + "/" + fn;
      const abs = WARD_LEARN_DIR + "/" + id; let mt = 1; try { if (fsExists(abs)) mt = Math.round(fsStat(abs).mtimeMs); } catch { }
      stmt.run(id, abs, cat, fn, mt, String(it.engine || "expert-seed"), JSON.stringify(it.data || {}), Date.now()); n++;
    }
    wardLearnedRefresh();
    return c.json({ data: { seeded: n, learned: WARD_LEARNED } });
  } catch (err) { console.error(err); return c.json({ error: "seed failed", message: String(err) }, 500); }
});
app.post("/api/wardrobe/rerender", async (c) => {
  try {
    const body = await c.req.json().catch(() => ({} as any));
    const o = (body && body.option) || body;
    if (!o || !Array.isArray(o.sections)) return c.json({ error: "bad option" }, 400);
    o.id = String(o.id || "custom"); o.label = String(o.label || "Custom");
    o.width = wardClamp(Math.round(+o.width || 2400), 1200, (o.shape === "l" || o.shape === "u") ? 14000 : 4800);
    o.height = wardClamp(Math.round(+o.height || 2400), 1800, 3000);
    o.depth = wardClamp(Math.round(+o.depth || 600), 450, 900);
    o.plinth = WARDROBE_STD.plinth; o.loftDepth = WARDROBE_STD.loftDepth;
    o.hasLoft = !!o.hasLoft && o.height >= 2400;
    o.loftH = o.hasLoft ? wardClamp(Math.round(+o.loftH || 600), 300, 750) : 0;
    o.usableH = o.height - o.plinth - o.loftH;
    // beam-aware per-column target: columns under the beam renormalise to the soffit height
    const beam = o.beam && o.beam.on && +o.beam.proj > 0 && +o.beam.width > 0 ? o.beam : null;
    for (const sec of o.sections) for (const col of (sec.columns || [])) {
      const ub = beam && col.x < beam.pos + beam.width && col.x + col.w > beam.pos;
      const target = Math.max(300, (ub ? beam.soffit : o.height) - o.plinth - (ub ? 0 : o.loftH));
      let cells = (col.cells || []).filter((cc: any) => cc && +cc.hMM > 0).map((cc: any) => { const oc: any = { kind: String(cc.kind || "shelf"), label: String(cc.label || ""), hMM: Math.max(40, Math.round(+cc.hMM)), color: WARD_COLORS[String(cc.kind)] || "#cbd5e1", locked: !!cc.locked }; if (+cc.span > 1) oc.span = Math.round(+cc.span); if (cc.covered) oc.covered = true; if (cc.mergeId != null) oc.mergeId = String(cc.mergeId); return oc; });
      if (!cells.length) cells = [{ kind: "shelf", label: "Shelf", hMM: target, color: WARD_COLORS.shelf }];
      const sum = cells.reduce((a: number, cc: any) => a + cc.hMM, 0) || 1, f = target / sum;
      cells.forEach((cc: any) => cc.hMM = Math.round(cc.hMM * f));
      col.cells = wardShelfCapHang(cells);   // owner rule: a shelf always caps a hanging section
      // preserve + normalise editable loft compartments (sum → loftH); drop them when there is no loft
      if (o.hasLoft && !(ub)) {
        let lc = (Array.isArray(col.loftCells) ? col.loftCells : []).filter((x: any) => x && +x.hMM > 0).map((x: any) => ({ kind: String(x.kind || "loft"), label: String(x.label || "Loft"), hMM: Math.max(40, Math.round(+x.hMM)), color: String(x.color || "#fcd34d") }));
        if (!lc.length) lc = [{ kind: "loft", label: "Loft", hMM: o.loftH, color: "#fcd34d" }];
        const ls = lc.reduce((a: number, x: any) => a + x.hMM, 0) || 1, lf = o.loftH / ls; lc.forEach((x: any) => x.hMM = Math.round(x.hMM * lf));
        col.loftCells = lc;
      } else { delete col.loftCells; }
    }
    // keep merged bands aligned after the per-column rescale: each covered twin re-snaps to its master's height
    { const masters: Record<string, any> = {}; for (const sec of o.sections) for (const col of (sec.columns || [])) for (const cc of col.cells) if (+cc.span > 1 && cc.mergeId != null) masters[String(cc.mergeId)] = cc;
      for (const sec of o.sections) for (const col of (sec.columns || [])) for (const cc of col.cells) if (cc.covered && cc.mergeId != null && masters[String(cc.mergeId)]) cc.hMM = masters[String(cc.mergeId)].hMM; }
    const allCells = o.sections.flatMap((s: any) => (s.columns || []).flatMap((cc: any) => (cc.cells || []).filter((x: any) => !x.covered)));
    const cnt = (pred: (k: string) => boolean) => allCells.filter((cc: any) => pred(cc.kind)).length;
    o.stats = { hanging: cnt(k => k.toLowerCase().indexOf("hang") >= 0 || k === "saree" || k === "dress" || k === "lehenga" || k === "suit"), shelves: cnt(k => k === "shelf" || k === "handbag" || k === "kidsShelf"), drawers: cnt(k => k === "drawer" || k === "jewellery" || k === "cosmetics"), shoe: cnt(k => k === "shoe"), accessories: cnt(k => k === "safe" || k === "tieBelt"), columns: o.sections.reduce((a: number, s: any) => a + (s.columns || []).length, 0), totalItems: allCells.length };
    o.reports = wardReports(o); o.scorecard = wardScorecard(o); o.suggestions = wardSuggestions(o);
    o.views = { Front: renderWardrobeElevationSvg(o, "front"), Internal: renderWardrobeElevationSvg(o, "internal"), "Shop Drawing": renderWardrobeShopDrawing(o), Shutters: renderWardrobeShutterCompareSvg(o), Top: renderWardrobeTopSvg(o), Side: renderWardrobeSideSvg(o), Loft: renderWardrobeLoftSvg(o), "Item Art": renderWardrobeItemCatalog() };
    o.boq = wardBOQ(o); o.cnc = wardCNC(o);
    o.svg = o.views.Front;
    return c.json({ data: o });
  } catch (err) { console.error(err); return c.json({ error: "Wardrobe rerender failed" }, 500); }
});

