app.get("/api/render/jobs/:jid/file", (c) => {
  const row = sqlite.prepare(`SELECT kind,status,result FROM render_jobs WHERE id=?`).get(c.req.param("jid")) as any;
  if (!row || row.status !== "done" || !row.result) return c.json({ error: "no artifact" }, 404);
  const buf = dataUrlToBuffer(row.result); if (!buf) return c.json({ error: "bad artifact" }, 500);
  const ext = row.result.startsWith("data:image/gif") ? "gif" : "png";
  c.header("Content-Type", ext === "gif" ? "image/gif" : "image/png");
  c.header("Content-Disposition", `attachment; filename="${row.kind}-${c.req.param("jid").slice(0, 8)}.${ext}"`);
  return c.body(buf);
});

// ── Design version history — snapshot / list / restore (production "version history") ──
function versionSummary(layout: any) {
  const runs = layout.runs || [];
  const cabs = runs.reduce((s: number, r: any) => s + (r.base || []).length + (r.wallCabs || []).length, 0);
  const mfg = layout.mfgChecks || [];
  return { runs: runs.length, cabinets: cabs, panels: (layout.cutList || []).length, mfgPass: mfg.filter((m: any) => m.ok).length, mfgTotal: mfg.length, handle: layout.handle, finish: layout.applianceBrand };
}
app.post("/api/designs/:id/version", async (c) => {
  const id = c.req.param("id"); const d = loadDesign(id); if (!d) return c.json({ error: "Design not found" }, 404);
  const b = await c.req.json().catch(() => ({} as any));
  const vid = randomUUID();
  const label = String(b.label || "").slice(0, 80) || ("Snapshot " + new Date(Date.now()).toISOString().slice(0, 19).replace("T", " "));
  sqlite.prepare(`INSERT INTO design_versions(id,design_id,label,layout,created_at) VALUES(?,?,?,?,?)`).run(vid, id, label, JSON.stringify(d.layout), Date.now());
  auditEdit(id, d.row.designType, "adjustment", `version snapshot — ${label}`);
  broadcast(id, "version", { action: "snapshot", id: vid, label });
  return c.json({ data: { ok: true, id: vid, label, summary: versionSummary(d.layout) } });
});
app.get("/api/designs/:id/versions", (c) => {
  const rows = sqlite.prepare(`SELECT id,label,layout,created_at FROM design_versions WHERE design_id=? ORDER BY created_at DESC LIMIT 50`).all(c.req.param("id")) as any[];
  return c.json({ data: rows.map((r) => ({ id: r.id, label: r.label, createdAt: r.created_at, summary: versionSummary(JSON.parse(r.layout)) })) });
});
// full snapshot of ONE version — the stored layout's plan drawing + rich metrics, for side-by-side compare.
app.get("/api/designs/:id/versions/:vid", (c) => {
  const row = sqlite.prepare(`SELECT id,label,layout,created_at FROM design_versions WHERE id=? AND design_id=?`).get(c.req.param("vid"), c.req.param("id")) as any;
  if (!row) return c.json({ error: "version not found" }, 404);
  let layout: any; try { layout = JSON.parse(row.layout); } catch { return c.json({ error: "corrupt version data" }, 500); }
  try { rederiveLayout(layout); } catch {}   // refresh planSvg/cutList/boq/mfg from stored runs if stale
  let metrics: any = null; try { metrics = designMetrics(layout); } catch {}
  return c.json({ data: { id: row.id, label: row.label, createdAt: row.created_at, type: layout.type, dims: layout.dims, planSvg: layout.planSvg || "", summary: versionSummary(layout), metrics } });
});
app.post("/api/designs/:id/restore/:vid", async (c) => {
  const id = c.req.param("id"); const d = loadDesign(id); if (!d) return c.json({ error: "Design not found" }, 404);
  const row = sqlite.prepare(`SELECT label,layout FROM design_versions WHERE id=? AND design_id=?`).get(c.req.param("vid"), id) as any;
  if (!row) return c.json({ error: "version not found" }, 404);
  // auto-snapshot the current state before overwriting, so a restore is itself undoable.
  sqlite.prepare(`INSERT INTO design_versions(id,design_id,label,layout,created_at) VALUES(?,?,?,?,?)`).run(randomUUID(), id, "Auto-save before restore", JSON.stringify(d.layout), Date.now());
  const restored = JSON.parse(row.layout);
  rederiveLayout(restored); saveLayout(id, restored);
  auditEdit(id, d.row.designType, "adjustment", `restored version — ${row.label}`);
  broadcast(id, "layout", { runs: restored.runs, by: null });
  broadcast(id, "version", { action: "restore", label: row.label });
  return c.json({ data: { ok: true, label: row.label, runs: restored.runs, mfgChecks: restored.mfgChecks } });
});

// ── Priced quotation ("Estimate") — rate-card × BOQ → client-ready INR quote ──
//   Deterministic, no external API. Reuses boq()/hardwareSchedule(); price is
//   derived on read (never stored in layout) so it stays orthogonal to autosave.
sqlite.exec(`CREATE TABLE IF NOT EXISTS rate_cards (
  design_id TEXT PRIMARY KEY, rates TEXT NOT NULL, updated_at INTEGER NOT NULL);`);

const DEFAULT_RATES: Record<string, number> = {
  board_sqft: 250, edgeband_m: 25, carcass_labour_per_cab: 1200, drawer_front: 350,
  hinge: 90, glass_hinge: 220, drawer_slide: 450, handle: 180, knob: 60, gola_m: 350,
  push_catch: 250, pullout_basket: 2500, corner_mech: 6500, waste_bin: 1200,
  gtpt_basket: 3500, pantry_pullout: 9000, hi_unit: 1500, cutlery_tray: 900,
  accessory_default: 1500, margin_pct: 18, gst_pct: 18,
};
// Map a BOQ row's item label to its rate-card key (keyword match, hardware-aware).
function rateKeyFor(item: string): string {
  const s = item.toLowerCase();
  if (item === "Cabinets (carcasses)") return "carcass_labour_per_cab";
  if (item === "Board area (18 mm)") return "board_sqft";
  if (item === "Edge banding (approx)") return "edgeband_m";
  if (item === "Drawer fronts") return "drawer_front";
  if (item === "Panels to cut") return "_free";           // priced via board area
  if (/glass hinge/.test(s)) return "glass_hinge";
  if (/hinge/.test(s)) return "hinge";
  if (/drawer slide/.test(s)) return "drawer_slide";
  if (/gola|j profile/.test(s)) return "gola_m";
  if (/knob/.test(s)) return "knob";
  if (/handle/.test(s)) return "handle";
  if (/push-to-open/.test(s)) return "push_catch";
  if (/pull-out basket/.test(s)) return "pullout_basket";
  if (/mechanism/.test(s)) return "corner_mech";
  if (/waste bin/.test(s)) return "waste_bin";
  if (/gtpt/.test(s)) return "gtpt_basket";
  if (/pantry pull-out/.test(s)) return "pantry_pullout";
  if (/hi-unit/.test(s)) return "hi_unit";
  if (/cutlery tray/.test(s)) return "cutlery_tray";
  return "accessory_default";
}
// Per-design selected MATERIAL (from the catalog) — drives finish colour, costing + docs.
sqlite.exec(`CREATE TABLE IF NOT EXISTS design_materials (
  design_id TEXT PRIMARY KEY, material TEXT NOT NULL, updated_at INTEGER NOT NULL);`);
function designMaterial(id: string): any {
  try { const row = sqlite.prepare(`SELECT material FROM design_materials WHERE design_id=?`).get(id) as any; return row ? JSON.parse(row.material) : null; } catch { return null; }
}
// §4 Apply-To: material is stored per SCOPE (base / wall / tall). A legacy flat
// record (or a "whole unit" pick) maps to all three. primaryMaterial = the finish
// shown as the design's headline colour.
const MAT_SCOPES = ["base", "wall", "tall"] as const;
function materialScopes(id: string): Record<string, any> {
  const m = designMaterial(id); if (!m) return {};
  if (m.materialId || m.colorCode) return { base: m, wall: m, tall: m };   // legacy flat = whole unit
  const out: Record<string, any> = {}; for (const s of MAT_SCOPES) if (m[s]) out[s] = m[s];
  return out;
}
function primaryMaterial(scopes: Record<string, any>): any { return scopes.base || scopes.wall || scopes.tall || null; }
// §2 per-cabinet material override — a cabinet's own finish (keyed section:runIdx:arrayIdx)
// wins over its scope finish. Stored as a `cabinets` map inside the design_materials blob.
const CK_RE = /^(base|wall):\d+:\d+$/;
function cabinetMaterials(id: string): Record<string, any> {
  const m = designMaterial(id); return (m && m.cabinets && typeof m.cabinets === "object") ? m.cabinets : {};
}
// Full material record (scopes + per-cabinet overrides) — what history snapshots / reverts restore.
function fullMaterial(id: string): any { const s: any = materialScopes(id); const cb = cabinetMaterials(id); if (Object.keys(cb).length) s.cabinets = cb; return s; }
function cabScope(c: any, section: string): string { return section === "wall" ? "wall" : (isTall(c.kind) ? "tall" : "base"); }
// Visible front area (mm²) of one cabinet — matches scopeFaceSqft's per-kind rules.
function cabFaceMm2(c: any, section: string): number {
  if (!c || c.kind === "filler" || c.kind === "sidepanel") return 0;
  if (section === "wall") return (c.w || 0) * (c.h || STD.wallHeight);
  if (isTall(c.kind)) return (c.w || 0) * (STD.wallStart + STD.wallHeight);
  return (c.w || 0) * (c.h || STD.baseHeight);
}
function matLabelOf(m: any): string { return m ? [m.brand, m.colorName].filter(Boolean).join(" ") + (m.code ? " (" + m.code + ")" : "") : ""; }
// Material chosen for a cabinet: its own override (if any), else the scope finish.
function cabMaterialFor(scopes: any, cabMats: any, ck: string, scope: string): any {
  return (cabMats && cabMats[ck]) || (scopes && (scopes[scope] || primaryMaterial(scopes))) || null;
}
function mm2ToSqft(mm2: number): number { return Math.round(mm2 / 92903 * 10) / 10; }
// Finish-material face lines (mm²) for costing/BOQ — scope aggregates (EXCLUDING overridden
// cabinets) + one grouped line per per-cabinet override material. With no overrides this is
// exactly the per-scope set (same faces) the quote/BOQ produced before. Consumers gate/format.
function materialFaceLines(layout: any, scopes: any, cabMats?: any): { scope: string; mat: any; faceMm2: number; override: boolean }[] {
  cabMats = cabMats || {};
  if (layout.furniture) { const m = scopes && (scopes.base || primaryMaterial(scopes)); return [{ scope: "base", mat: m || null, faceMm2: (layout.furniture.widthMM || 0) * (layout.furniture.heightMM || 0), override: false }]; }
  const scopeMm2: Record<string, number> = { base: 0, wall: 0, tall: 0 };
  const ovr = new Map<string, { mat: any; faceMm2: number }>();
  (layout.runs || []).forEach((run: any, ri: number) => {
    const tally = (arr: any[], section: string) => (arr || []).forEach((c, bi) => {
      const mm2 = cabFaceMm2(c, section); if (mm2 <= 0) return;
      const o = cabMats[section + ":" + ri + ":" + bi];
      if (o && o.code) { const k = "ovr:" + o.code; const e = ovr.get(k) || { mat: o, faceMm2: 0 }; e.faceMm2 += mm2; ovr.set(k, e); }
      else scopeMm2[cabScope(c, section)] += mm2;
    });
    tally(run.base, "base"); tally(run.wallCabs, "wall");
  });
  const out: { scope: string; mat: any; faceMm2: number; override: boolean }[] = [];
  for (const s of MAT_SCOPES) out.push({ scope: s, mat: scopes ? scopes[s] : null, faceMm2: scopeMm2[s], override: false });
  for (const e of ovr.values()) out.push({ scope: "custom", mat: e.mat, faceMm2: e.faceMm2, override: true });
  return out;
}
// Visible front/face area (sqft) per scope — basis for material costing (12.pdf).
function scopeFaceSqft(layout: any, scope: string): number {
  const u = layout.furniture; if (u) return scope === "base" ? Math.round((u.widthMM || 0) * (u.heightMM || 0) / 92903 * 10) / 10 : 0;   // furniture front = "base"
  let mm2 = 0;
  for (const run of (layout.runs || [])) {
    if (scope === "base") for (const c of (run.base || [])) { if (isTall(c.kind) || c.kind === "filler" || c.kind === "sidepanel") continue; mm2 += (c.w || 0) * (c.h || STD.baseHeight); }
    if (scope === "tall") for (const c of (run.base || [])) { if (!isTall(c.kind)) continue; mm2 += (c.w || 0) * (STD.wallStart + STD.wallHeight); }
    if (scope === "wall") for (const c of (run.wallCabs || [])) { if (c.kind === "filler" || c.kind === "sidepanel") continue; mm2 += (c.w || 0) * (c.h || STD.wallHeight); }
  }
  return Math.round(mm2 / 92903 * 10) / 10;   // 1 sqft = 92903 mm²
}
const SCOPE_LABEL: Record<string, string> = { base: "Base cabinets", wall: "Wall cabinets", tall: "Tall units" };
// ── Wardrobe → kitchen quote/BOQ adapter ─────────────────────────────────────
// A saved wardrobe (layout.wardrobe = {input, data, selIdx}) has runs:[] so the
// kitchen boq()/priceQuote() would report ₹0. These map the wardrobe's OWN costed
// BOQ into the shared quote shape so the gallery Estimate / quote CSV / quote PDF
// all show real, authoritative wardrobe numbers instead of an empty kitchen quote.
function wardrobeSelectedOption(layout: any): any { const w = (layout && layout.wardrobe) || {}; const opts = (w.data && w.data.options) || []; return opts[w.selIdx || 0] || opts[0] || null; }
function wardrobeBoqRows(layout: any): { item: string; qty: number; unit: string }[] {
  const sel = wardrobeSelectedOption(layout); if (!sel) return [];
  const rows: { item: string; qty: number; unit: string }[] = [];
  if (sel.boq && Array.isArray(sel.boq.lines)) for (const l of sel.boq.lines) rows.push({ item: l.item, qty: l.qty, unit: l.unit });
  else { const rp = sel.reports || {}; (rp.cut || []).forEach((cu: any) => rows.push({ item: cu.part + " (" + cu.size + ")", qty: cu.qty, unit: "no" })); (rp.hardware || []).forEach((h: any) => rows.push({ item: h.item, qty: h.qty, unit: "no" })); }
  return rows;
}
function wardrobeQuoteFromLayout(layout: any) {
  const sel = wardrobeSelectedOption(layout); if (!sel || !sel.boq) return null;
  const b = sel.boq;
  const lines = (b.lines || []).map((l: any) => ({ item: l.item, qty: l.qty, unit: l.unit, rate: l.rate, amount: l.amount }));
  if (!lines.length) return null;
  const subtotal = b.subtotal || lines.reduce((s: number, l: any) => s + l.amount, 0);
  const margin = b.labour || 0;   // the wardrobe engine's 22% labour uplift stands in for the quote "margin"
  const marginPct = subtotal ? Math.round(margin / subtotal * 1000) / 10 : 0;
  const taxable = b.taxable || (subtotal + margin);
  const gst = b.gst || 0;
  const gstPct = taxable ? Math.round(gst / taxable * 1000) / 10 : 0;
  const total = b.grandTotal || (taxable + gst);
  return { lines, subtotal, marginPct, margin, taxable, gstPct, gst, total, currency: "INR", wardrobe: true };
}
function priceQuote(layout: any, rates: Record<string, number>, scopes?: Record<string, any>, cabMats?: any) {
  if (layout && layout.wardrobe) { const wq = wardrobeQuoteFromLayout(layout); if (wq) return wq; }
  const r = { ...DEFAULT_RATES, ...(rates || {}) };
  const lines = boq(layout).map((row) => {
    const key = rateKeyFor(row.item);
    const rate = key === "_free" ? 0 : Math.round((r[key] ?? 0) * 100) / 100;
    const amount = Math.round(row.qty * rate);
    return { item: row.item, qty: row.qty, unit: row.unit, rate, amount };
  });
  // §8/§13 + §2: finish material as costed lines — per scope (overridden cabinets excluded)
  // plus a grouped line per per-cabinet override, each face area × rate + 15% factory wastage.
  if (scopes) for (const fl of materialFaceLines(layout, scopes, cabMats)) {
    const mat = fl.mat; if (!mat || !(Number(mat.customerRate) > 0)) continue;
    const face = mm2ToSqft(fl.faceMm2); if (face <= 0) continue;
    const qty = Math.round(face * 1.15 * 10) / 10, rate = Math.round(Number(mat.customerRate) * 100) / 100;
    const scopeLbl = fl.override ? "Custom · per-cabinet" : (SCOPE_LABEL[fl.scope] || fl.scope);
    const label = "Finish [" + scopeLbl + "] — " + matLabelOf(mat) + " · +15% wastage";
    lines.push({ item: label, qty, unit: mat.unit || "sqft", rate, amount: Math.round(qty * rate) });
  }
  const subtotal = lines.reduce((s, l) => s + l.amount, 0);
  const marginPct = r.margin_pct ?? 0, gstPct = r.gst_pct ?? 0;
  const margin = Math.round(subtotal * marginPct / 100);
  const taxable = subtotal + margin;
  const gst = Math.round(taxable * gstPct / 100);
  const total = taxable + gst;
  return { lines, subtotal, marginPct, margin, taxable, gstPct, gst, total, currency: "INR" };
}
function quoteRates(id: string): Record<string, number> {
  const row = sqlite.prepare(`SELECT rates FROM rate_cards WHERE design_id=?`).get(id) as any;
  return row ? { ...DEFAULT_RATES, ...JSON.parse(row.rates) } : { ...DEFAULT_RATES };
}
// Per-design client / "Bill To" details (customer + project), flowed into quote CSV/PDF + proposal.
sqlite.exec(`CREATE TABLE IF NOT EXISTS design_clients (
  design_id TEXT PRIMARY KEY, client TEXT NOT NULL, updated_at INTEGER NOT NULL);`);
const CLIENT_FIELDS = ["name", "phone", "email", "site", "ref", "notes"];
function quoteClient(id: string): Record<string, string> {
  const row = sqlite.prepare(`SELECT client FROM design_clients WHERE design_id=?`).get(id) as any;
  return row ? JSON.parse(row.client) : {};
}
function hasClient(cl: any): boolean { return !!(cl && (cl.name || cl.phone || cl.email || cl.site || cl.ref)); }
function quoteCsv(q: ReturnType<typeof priceQuote>, client?: any): string {
  const out: string[] = [];
  const cl = client || {};
  // Neutralise spreadsheet formula-injection: a value beginning =,+,-,@,tab,CR gets a leading apostrophe.
  const csvSafe = (v: any) => { const s = String(v == null ? "" : v); return (/^[=+\-@\t\r]/.test(s) ? "'" + s : s).replace(/"/g, '""'); };
  if (hasClient(cl)) {
    const f = (label: string, v: string) => out.push(`${label},"${csvSafe(v)}"`);
    if (cl.name) f("Bill To", cl.name);
    if (cl.phone) f("Phone", cl.phone);
    if (cl.email) f("Email", cl.email);
    if (cl.site) f("Site", cl.site);
    if (cl.ref) f("Quote Ref", cl.ref);
    out.push("");
  }
  out.push("S.No,Item,Qty,Unit,Rate (INR),Amount (INR)");
  q.lines.forEach((l, i) => out.push(`${i + 1},"${csvSafe(l.item)}",${l.qty},${l.unit},${l.rate},${l.amount}`));
  out.push(`,,,,Subtotal,${q.subtotal}`);
  out.push(`,,,,Margin (${q.marginPct}%),${q.margin}`);
  out.push(`,,,,Taxable,${q.taxable}`);
  out.push(`,,,,GST (${q.gstPct}%),${q.gst}`);
  out.push(`,,,,Total,${q.total}`);
  return out.join("\n");
}
app.get("/api/rate-card/default", (c) => c.json({ data: DEFAULT_RATES }));
app.get("/api/designs/:id/rate-card", (c) => {
  const d = loadDesign(c.req.param("id")); if (!d) return c.json({ error: "Design not found" }, 404);
  return c.json({ data: quoteRates(c.req.param("id")) });
});
app.put("/api/designs/:id/rate-card", async (c) => {
  const id = c.req.param("id"); const d = loadDesign(id); if (!d) return c.json({ error: "Design not found" }, 404);
  const b = await c.req.json().catch(() => ({} as any));
  const merged: Record<string, number> = { ...quoteRates(id) };
  for (const k of Object.keys(DEFAULT_RATES)) if (b[k] != null && isFinite(Number(b[k]))) merged[k] = Math.max(0, Number(b[k]));
  sqlite.prepare(`INSERT INTO rate_cards(design_id,rates,updated_at) VALUES(?,?,?)
    ON CONFLICT(design_id) DO UPDATE SET rates=excluded.rates, updated_at=excluded.updated_at`).run(id, JSON.stringify(merged), Date.now());
  auditEdit(id, d.row.designType, "adjustment", "rate-card updated");
  const quote = priceQuote(d.layout, merged, materialScopes(id), cabinetMaterials(id));
  broadcast(id, "quote", { total: quote.total });
  return c.json({ data: { ok: true, rates: merged, quote } });
});
app.get("/api/designs/:id/quote", (c) => {
  const id = c.req.param("id"); const d = loadDesign(id); if (!d) return c.json({ error: "Design not found" }, 404);
  return c.json({ data: priceQuote(d.layout, quoteRates(id), materialScopes(id), cabinetMaterials(id)) });
});
app.get("/api/designs/:id/quote.csv", (c) => {
  const id = c.req.param("id"); const d = loadDesign(id); if (!d) return c.json({ error: "Design not found" }, 404);
  const fname = `${d.row.designType.replace(/[^\w-]/g, "_")}-${d.row.id.slice(0, 8)}-quote.csv`;
  c.header("Content-Type", "text/csv");
  c.header("Content-Disposition", `attachment; filename="${fname}"`);
  return c.body(quoteCsv(priceQuote(d.layout, quoteRates(id), materialScopes(id), cabinetMaterials(id)), quoteClient(id)));
});
// Per-design selected material (Material Management Module). Whitelisted catalog fields.
app.get("/api/designs/:id/material", (c) => { const d = loadDesign(c.req.param("id")); if (!d) return c.json({ error: "Design not found" }, 404); return c.json({ data: designMaterial(c.req.param("id")) }); });
// §2: list per-cabinet overrides, each resolved to its cabinet's label (for the "Painted cabinets" panel).
app.get("/api/designs/:id/cabinet-materials", (c) => {
  const id = c.req.param("id"); const d = loadDesign(id); if (!d) return c.json({ error: "Design not found" }, 404);
  const cb = cabinetMaterials(id), out: any[] = [];
  const labelFor = (ck: string) => {
    const [section, ri, bi] = ck.split(":"); const run = (d.layout.runs || [])[+ri]; if (!run) return ck;
    const cc = (section === "wall" ? (run.wallCabs || []) : (run.base || []))[+bi];
    return cc ? ((cc.label || cc.kind) + (run.name ? " · " + run.name : "")) : ck;
  };
  for (const ck of Object.keys(cb)) { const m = cb[ck] || {}; out.push({ ck, label: labelFor(ck), brand: m.brand, colorName: m.colorName, code: m.code, colorCode: m.colorCode, finishType: m.finishType }); }
  return c.json({ data: out });
});
app.put("/api/designs/:id/material", async (c) => {
  const id = c.req.param("id"); const d = loadDesign(id); if (!d) return c.json({ error: "Design not found" }, 404);
  const b = await c.req.json().catch(() => ({} as any));
  const allow = ["materialId", "code", "category", "brand", "collection", "colorName", "colorCode", "finishType", "sheen", "dealerRate", "customerRate", "unit"];
  const m: any = {}; for (const k of allow) if (b[k] != null) m[k] = typeof b[k] === "number" ? b[k] : String(b[k]).slice(0, 80);
  if (m.colorCode && !/^#[0-9a-fA-F]{6}$/.test(m.colorCode)) delete m.colorCode;
  // §4 Apply-To: scope = all | base | wall | tall (default all → whole unit).
  // §2 per-cabinet: scope = cabinet (+ cabinetKey) sets/clears one cabinet's own finish.
  const scope = ["all", "base", "wall", "tall", "cabinet"].includes(b.scope) ? b.scope : "all";
  const cur: any = materialScopes(id);
  const existingCab = cabinetMaterials(id);
  if (Object.keys(existingCab).length) cur.cabinets = { ...existingCab };   // preserve per-cabinet overrides across any material write
  let tag = "[" + scope + "]";
  if (scope === "cabinet") {
    if (b.clearAll) { delete cur.cabinets; tag = "cleared all cabinet overrides"; }   // §2: wipe every per-cabinet override
    else {
      const ck = String(b.cabinetKey || "");
      if (!CK_RE.test(ck)) return c.json({ error: "invalid cabinetKey" }, 400);
      cur.cabinets = cur.cabinets || {};
      if (b.clear) { delete cur.cabinets[ck]; if (!Object.keys(cur.cabinets).length) delete cur.cabinets; tag = "cleared cabinet " + ck; }
      else { cur.cabinets[ck] = m; tag = "cabinet " + ck; }
    }
  } else if (scope === "all") { cur.base = m; cur.wall = m; cur.tall = m; }
  else { cur[scope] = m; }
  sqlite.prepare(`INSERT INTO design_materials(design_id,material,updated_at) VALUES(?,?,?)
    ON CONFLICT(design_id) DO UPDATE SET material=excluded.material, updated_at=excluded.updated_at`).run(id, JSON.stringify(cur), Date.now());
  auditEdit(id, d.row.designType, "adjustment", "material " + tag + ": " + [m.brand, m.colorName, m.code].filter(Boolean).join(" "));
  pushMaterialHistory(id, "Material " + tag + ": " + [m.brand, m.colorName, m.code].filter(Boolean).join(" "));
  broadcast(id, "material", { code: m.code || "", scope, ck: scope === "cabinet" ? b.cabinetKey : undefined });
  return c.json({ data: { ok: true, scope, scopes: cur } });
});

// ── §12 Theme creator — reusable bundles of per-scope material assignments. ──
sqlite.exec(`CREATE TABLE IF NOT EXISTS themes (id TEXT PRIMARY KEY, name TEXT NOT NULL, theme TEXT NOT NULL, created_at INTEGER NOT NULL);`);
function matByCode(code: string): any { return catalogAll().find((m) => m.code === code) || null; }
const BUILTIN_THEMES = [
  { id: "builtin-modern-luxury", name: "Modern Luxury", base: "N-04", wall: "N-15", tall: "N-04" },
  { id: "builtin-warm-earth", name: "Warm Earth", base: "E-01", wall: "E-15", tall: "E-01" },
  { id: "builtin-classic-white", name: "Classic White", base: "ACR-FW", wall: "ACR-FW", tall: "ACR-FW" },
  { id: "builtin-bold-accent", name: "Bold Accent", base: "R-06", wall: "N-16", tall: "N-16" },
  { id: "builtin-forest-calm", name: "Forest Calm", base: "G-05", wall: "N-15", tall: "G-05" },
].map((t) => ({ id: t.id, name: t.name, builtin: true, scopes: { base: matByCode(t.base), wall: matByCode(t.wall), tall: matByCode(t.tall) } }));
function listThemes(): any[] {
  const saved = (sqlite.prepare(`SELECT id,name,theme,created_at FROM themes ORDER BY created_at DESC`).all() as any[]).map((r) => ({ id: r.id, name: r.name, builtin: false, ...JSON.parse(r.theme) }));
  return [...BUILTIN_THEMES, ...saved];
}
app.get("/api/themes", (c) => c.json({ data: listThemes() }));
app.post("/api/themes", async (c) => {
  const b = await c.req.json().catch(() => ({} as any));
  const name = (String(b.name || "").trim().slice(0, 60)) || "Theme";
  let scopes: any = {};
  if (b.designId) { const d = loadDesign(b.designId); if (d) scopes = materialScopes(b.designId); }
  if (b.scopes && typeof b.scopes === "object") scopes = b.scopes;
  if (!primaryMaterial(scopes)) return c.json({ error: "No material assigned to save as a theme" }, 400);
  const id = randomUUID();
  sqlite.prepare(`INSERT INTO themes(id,name,theme,created_at) VALUES(?,?,?,?)`).run(id, name, JSON.stringify({ scopes }), Date.now());
  return c.json({ data: { id, name, scopes } });
});
app.delete("/api/themes/:id", (c) => { const id = c.req.param("id"); if (id.startsWith("builtin-")) return c.json({ error: "cannot delete a built-in theme" }, 400); sqlite.prepare(`DELETE FROM themes WHERE id=?`).run(id); return c.json({ data: { ok: true } }); });
app.post("/api/designs/:id/apply-theme", async (c) => {
  const id = c.req.param("id"); const d = loadDesign(id); if (!d) return c.json({ error: "Design not found" }, 404);
  const b = await c.req.json().catch(() => ({} as any));
  const theme = listThemes().find((t) => t.id === b.themeId); if (!theme) return c.json({ error: "Theme not found" }, 404);
  const sc = theme.scopes || {};
  const blob: any = { base: sc.base, wall: sc.wall, tall: sc.tall };
  const existCab = cabinetMaterials(id); if (Object.keys(existCab).length) blob.cabinets = existCab;   // §2: keep per-cabinet overrides when a whole-unit theme is applied
  sqlite.prepare(`INSERT INTO design_materials(design_id,material,updated_at) VALUES(?,?,?)
    ON CONFLICT(design_id) DO UPDATE SET material=excluded.material, updated_at=excluded.updated_at`).run(id, JSON.stringify(blob), Date.now());
  auditEdit(id, d.row.designType, "adjustment", "theme applied: " + theme.name);
  pushMaterialHistory(id, "Theme: " + theme.name);
  broadcast(id, "material", { theme: theme.name });
  const quote = priceQuote(d.layout, quoteRates(id), materialScopes(id), cabinetMaterials(id));
  return c.json({ data: { ok: true, theme: theme.name, primary: primaryMaterial(sc), total: quote.total } });
});

// ── §11 Material history (memento) — snapshot on every material change; revert. ──
sqlite.exec(`CREATE TABLE IF NOT EXISTS material_history (id TEXT PRIMARY KEY, design_id TEXT NOT NULL, snapshot TEXT NOT NULL, label TEXT NOT NULL, created_at INTEGER NOT NULL);`);
function pushMaterialHistory(id: string, label: string) {
  try {
    sqlite.prepare(`INSERT INTO material_history(id,design_id,snapshot,label,created_at) VALUES(?,?,?,?,?)`).run(randomUUID(), id, JSON.stringify(fullMaterial(id)), String(label).slice(0, 80), Date.now());
    const old = (sqlite.prepare(`SELECT id FROM material_history WHERE design_id=? ORDER BY created_at DESC LIMIT -1 OFFSET 50`).all(id) as any[]).map((r) => r.id);   // keep last 50
    if (old.length) { const del = sqlite.prepare(`DELETE FROM material_history WHERE id=?`); for (const x of old) del.run(x); }
  } catch { /* history is best-effort */ }
}
function materialHistory(id: string): any[] {
  return (sqlite.prepare(`SELECT id,snapshot,label,created_at FROM material_history WHERE design_id=? ORDER BY created_at DESC LIMIT 60`).all(id) as any[]).map((r) => { const p = primaryMaterial(JSON.parse(r.snapshot)); return { id: r.id, label: r.label, at: r.created_at, color: p ? p.colorCode : null, summary: p ? (p.brand + " " + p.colorName) : "—" }; });
}
app.get("/api/designs/:id/material-history", (c) => { const d = loadDesign(c.req.param("id")); if (!d) return c.json({ error: "Design not found" }, 404); return c.json({ data: materialHistory(c.req.param("id")) }); });
app.post("/api/designs/:id/material-revert", async (c) => {
  const id = c.req.param("id"); const d = loadDesign(id); if (!d) return c.json({ error: "Design not found" }, 404);
  const b = await c.req.json().catch(() => ({} as any));
  const row = sqlite.prepare(`SELECT snapshot,label FROM material_history WHERE id=? AND design_id=?`).get(b.historyId, id) as any;
  if (!row) return c.json({ error: "History entry not found" }, 404);
  sqlite.prepare(`INSERT INTO design_materials(design_id,material,updated_at) VALUES(?,?,?)
    ON CONFLICT(design_id) DO UPDATE SET material=excluded.material, updated_at=excluded.updated_at`).run(id, row.snapshot, Date.now());
  pushMaterialHistory(id, "Reverted → " + row.label);
  broadcast(id, "material", { revert: true });
  const quote = priceQuote(d.layout, quoteRates(id), materialScopes(id), cabinetMaterials(id));
  return c.json({ data: { ok: true, total: quote.total } });
});
// Client / "Bill To" details — persisted per design, addressed onto the quote + proposal.
app.get("/api/designs/:id/client", (c) => {
  const d = loadDesign(c.req.param("id")); if (!d) return c.json({ error: "Design not found" }, 404);
  return c.json({ data: quoteClient(c.req.param("id")) });
});
app.put("/api/designs/:id/client", async (c) => {
  const id = c.req.param("id"); const d = loadDesign(id); if (!d) return c.json({ error: "Design not found" }, 404);
  const b = await c.req.json().catch(() => ({} as any));
  const merged: Record<string, string> = { ...quoteClient(id) };
  for (const k of CLIENT_FIELDS) if (typeof b[k] === "string") merged[k] = b[k].slice(0, 200);
  sqlite.prepare(`INSERT INTO design_clients(design_id,client,updated_at) VALUES(?,?,?)
    ON CONFLICT(design_id) DO UPDATE SET client=excluded.client, updated_at=excluded.updated_at`).run(id, JSON.stringify(merged), Date.now());
  auditEdit(id, d.row.designType, "adjustment", `client details updated${merged.name ? " — " + merged.name : ""}`);
  broadcast(id, "client", { client: merged });
  return c.json({ data: { ok: true, client: merged } });
});

